const OPP_FIRST_STATS = new Set(["goals_against", "shot_against"]);
// Stats that after shot location go to the context details picker
const NEEDS_CONTEXT = new Set(["goal", "goals_against", "shot", "shot_against"]);

// Game periods — the slider positions
const PERIODS       = ["1Q","2Q","3Q","4Q","OT","SO","OVER"];
const PERIOD_LABELS = { "1Q":"1st Q","2Q":"2nd Q","3Q":"3rd Q","4Q":"4th Q","OT":"OT","SO":"Shoot Out","OVER":"OVER" };

const TEAM_COLORS = ["#ef4444","#3b82f6","#22c55e","#f59e0b","#8b5cf6","#06b6d4","#f97316","#ec4899"];
const uid = () => Math.random().toString(36).slice(2, 9);

// ─── Helpers ──────────────────────────────────────────────────────────────────
function playerStats(events, playerId) {
  const s = {};
  events.filter(e => e.playerId === playerId).forEach(e => { s[e.stat] = (s[e.stat] || 0) + 1; });
  return s;
}

function teamGameStats(events, teamId, players) {
  const teamPlayerIds = new Set(players.filter(p => p.teamId === teamId).map(p => p.id));
  const s = {};
  events.filter(e => teamPlayerIds.has(e.playerId)).forEach(e => { s[e.stat] = (s[e.stat] || 0) + 1; });
  return s;
}

