  @keyframes assistPulse {
    0%   { transform: scale(1);    box-shadow: 0 0 0 0 rgba(59,130,246,0.7),  0 0 0 0 rgba(59,130,246,0.4); border-color: var(--border); background: var(--surface); }
    15%  { transform: scale(1.08); box-shadow: 0 0 0 6px rgba(59,130,246,0.5), 0 0 0 12px rgba(59,130,246,0.15); border-color: #3b82f6; background: rgba(59,130,246,0.12); }
    30%  { transform: scale(1);    box-shadow: 0 0 0 0 rgba(59,130,246,0.2),  0 0 0 0 rgba(59,130,246,0); border-color: #3b82f6; background: rgba(59,130,246,0.08); }
    50%  { transform: scale(1.05); box-shadow: 0 0 0 5px rgba(59,130,246,0.4), 0 0 0 10px rgba(59,130,246,0.1); border-color: #3b82f6; background: rgba(59,130,246,0.12); }
    65%  { transform: scale(1);    box-shadow: 0 0 0 0 rgba(59,130,246,0.1),  0 0 0 0 rgba(59,130,246,0); border-color: #3b82f6; background: rgba(59,130,246,0.06); }
    80%  { transform: scale(1.03); box-shadow: 0 0 0 3px rgba(59,130,246,0.25); border-color: #3b82f6; background: rgba(59,130,246,0.08); }
    100% { transform: scale(1);    box-shadow: 0 0 0 0 rgba(59,130,246,0); border-color: #3b82f6; background: rgba(59,130,246,0.06); }
  }
  @keyframes assistIconSpin {
    0%   { transform: scale(1)    rotate(0deg); }
    20%  { transform: scale(1.4)  rotate(-20deg); }
    40%  { transform: scale(1.2)  rotate(15deg); }
    60%  { transform: scale(1.35) rotate(-10deg); }
    80%  { transform: scale(1.15) rotate(5deg); }
    100% { transform: scale(1)    rotate(0deg); }
  }
  @keyframes assistShimmer {
    0%, 100% { background: rgba(59,130,246,0.06); box-shadow: 0 0 8px rgba(59,130,246,0.15); }
    50%       { background: rgba(59,130,246,0.14); box-shadow: 0 0 18px rgba(59,130,246,0.35); }
  }
