  .live-badge { display: inline-flex; align-items: center; gap: 4px; font-size: 10px; font-weight: 700; letter-spacing: 1px; color: #fff; background: rgba(239,68,68,0.75); border-radius: 20px; padding: 2px 8px; margin-left: 8px; }
  .live-dot { width: 5px; height: 5px; border-radius: 50%; background: #fff; animation: pulse 1.5s infinite; }
  @keyframes pulse { 0%,100% { opacity: 1; } 50% { opacity: 0.4; } }

  /* ── Undo row ── */
  .undo-row { display: flex; align-items: center; gap: 10px; padding: 10px 16px; background: var(--surface); border: 1px solid var(--border); border-radius: 10px; }
  .undo-label { flex: 1; font-size: 12px; color: var(--muted); }
  .undo-event { font-weight: 700; color: var(--text); }

  /* ── Empty ── */
  .empty { text-align: center; padding: 48px 24px; color: var(--muted); }
  .empty-icon { font-size: 40px; margin-bottom: 12px; }
  .empty-title { font-size: 16px; font-weight: 700; color: var(--text); margin-bottom: 6px; }
  .empty-sub { font-size: 13px; line-height: 1.6; color: var(--muted); }

  /* ── Misc ── */
  .divider { height: 1px; background: var(--border); margin: 12px 0; }
  .chip { display: inline-flex; align-items: center; gap: 4px; padding: 3px 10px; border-radius: 20px; font-size: 11px; font-weight: 700; }
  .chip-goalie { background: var(--gold-dim); color: #5a3e00; }
  .chip-field { background: var(--surface2); color: var(--muted); }
  input[type=number]::-webkit-inner-spin-button { -webkit-appearance: none; }
`;

// ─── Toast ────────────────────────────────────────────────────────────────────
function useToast() {
  const [toasts, setToasts] = useState([]);
  const push = useCallback((msg, icon = "✅") => {
    const id = uid();
    setToasts(t => [...t, { id, msg, icon }]);
    setTimeout(() => setToasts(t => t.filter(x => x.id !== id)), 2200);
  }, []);
  return { toasts, push };
}

// ═══════════════════════════════════════════════════════════════════════════════
// STAT HELPERS — centralise goal/shot detection so 5M goals are never missed
// ═══════════════════════════════════════════════════════════════════════════════
const isGoalFor     = e => e.stat === "goal" || e.stat === "penalty_5m_goal_for";
const isShotFor     = e => e.stat === "goal" || e.stat === "shot" || e.stat === "penalty_5m_goal_for" || e.stat === "penalty_5m_miss_for" || e.stat === "penalty_5m_block";
const isGoalAgainst = e => e.stat === "goals_against" || e.stat === "penalty_5m_goal_against";

// ═══════════════════════════════════════════════════════════════════════════════
// ROOT
// ═══════════════════════════════════════════════════════════════════════════════
function App() {
  const [db, setDb] = useState(() => load() || EMPTY);
  const [screen, setScreen] = useState("track");
  const [goHomeSignal, setGoHomeSignal] = useState(0);
  const [branding, setBranding] = useState({ club_name: "WAVE", primary_color: "#003087", secondary_color: "#FFC72C", has_ai: false });
  const { toasts, push } = useToast();

  useEffect(() => { save(db); }, [db]);

  // Fetch branding settings from server and apply CSS variables
  useEffect(() => {
    fetch(SERVER_URL + "?action=get_settings&_=" + Date.now())
      .then(r => r.json())
      .then(j => {
        if (j.ok && j.settings) {
          setBranding(j.settings);
          const root = document.documentElement;
          if (j.settings.primary_color)   { root.style.setProperty("--navy",       j.settings.primary_color); root.style.setProperty("--accent", j.settings.primary_color); }
          if (j.settings.secondary_color) { root.style.setProperty("--gold",        j.settings.secondary_color); }
        }
      })
      .catch(() => {});
  }, []);

  const update = useCallback((fn) => setDb(prev => { const next = { ...prev }; fn(next); return next; }), []);

  const activeGame = db.games.find(g => g.id === db.activeGameId) || null;
  const clubName = branding.club_name || "WAVE";
  const hasAi    = !!branding.has_ai;

  function handleHomeNav() {
    // If we're on another screen, just switch back — never clear an active game
    if (screen !== "track") {
      setScreen("track");
      return;
    }
    // Already on track screen: if there's an active game in progress, stay in it
    // (do nothing — game is already showing)
    // Only send the "go to game list" signal if there's no active game
    if (!db.activeGameId) {
      setGoHomeSignal(s => s + 1);
    }
  }

  return (
    <>
      <style>{CSS}</style>
      <div className="app">
        {/* Toast layer */}
        <div className="toast-wrap">
          {toasts.map(t => (
            <div key={t.id} className="toast">{t.icon} {t.msg}</div>
          ))}
        </div>

        {/* Screen */}
        <div className="screen">
          {screen === "track" && <TrackScreen db={db} update={update} push={push} activeGame={activeGame} goHomeSignal={goHomeSignal} clubName={clubName} />}
          {screen === "setup" && <SetupScreen db={db} update={update} push={push} clubName={clubName} />}
          {screen === "ask"   && <AskScreen clubName={clubName} />}
        </div>

        {/* Active game resume banner — shown when user navigates away mid-game */}
        {activeGame && screen !== "track" && (
          <div onClick={() => setScreen("track")} style={{
            background: "linear-gradient(90deg, #16a34a, #15803d)",
            color: "#fff", padding: "10px 16px",
            display: "flex", alignItems: "center", justifyContent: "space-between",
            cursor: "pointer", flexShrink: 0, gap: 10,
          }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8, fontSize: 13, fontWeight: 700 }}>
              <span style={{ fontSize: 16 }}>🏊</span>
              Game in progress — tap to return
            </div>
            <div style={{ fontSize: 20, fontWeight: 900, fontFamily: "var(--font-display)", letterSpacing: 1 }}>
              {activeGame.homeScore ?? 0} – {activeGame.awayScore ?? 0}
            </div>
          </div>
        )}

        {/* Nav */}
        <nav className="nav">
          <button className={"nav-btn" + (screen === "track" ? " active" : "")} onClick={handleHomeNav}>
            <span className="nav-icon">🏠</span>
            Home
          </button>
          {hasAi && (
            <button className={"nav-btn" + (screen === "ask" ? " active" : "")} onClick={() => setScreen("ask")}>
              <span className="nav-icon">🤖</span>
              Ask SkipShot
            </button>
          )}
        </nav>
      </div>
    </>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// ASK SKIPSHOT  — natural language stats queries via Gemini
// ═══════════════════════════════════════════════════════════════════════════════
function AskScreen({ clubName }) {
  const [question, setQuestion]   = useState("");
  const [answer,   setAnswer]     = useState(null);
  const [table,    setTable]      = useState(null);
  const [loading,  setLoading]    = useState(false);
  const [error,    setError]      = useState(null);
  const [meta,     setMeta]       = useState(null);
  const [listening, setListening] = useState(false);
  const recognitionRef = useRef(null);

  const SUGGESTED = [
    "Who are the top 10 shooters?",
    "Who had the most assists?",
    "What was our man-up conversion rate?",
    "Which goalie had the best save percentage?",
    "Who drew the most kickouts?",
    "How many steals did we have this season?",
    "What was our record this season?",
    "Who was our top scorer overall?",
  ];

  async function handleAsk(q) {
    const text = (q || question).trim();
    if (!text) return;
    setLoading(true); setAnswer(null); setTable(null); setError(null); setMeta(null);
    const t0 = Date.now();
    try {
      const r = await fetch(SERVER_URL + "?_=" + Date.now(), {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action: "ask_data_public", question: text }),
      });
      const j = await r.json();
      const elapsed = ((Date.now() - t0) / 1000).toFixed(1);
      if (j.ok) {
        setAnswer(j.answer);
        setTable(j.table || null);
        setMeta(`Gemini 2.5 Flash · ${elapsed}s · ${j.games_used ?? "?"} game${(j.games_used ?? 0) !== 1 ? "s" : ""} analysed`);
      } else {
        setError(j.error || "Something went wrong");
      }
    } catch (e) {
      setError("Network error — please try again");
    }
    setLoading(false);
  }

  // Speech recognition
  const SR = typeof window !== "undefined" && (window.SpeechRecognition || window.webkitSpeechRecognition);
  const canSpeak = !!SR && ("ontouchstart" in window);

  function toggleSpeech() {
    if (listening) { recognitionRef.current?.stop(); return; }
    const rec = new SR();
    rec.lang = "en-CA"; rec.interimResults = true; rec.maxAlternatives = 1;
    recognitionRef.current = rec;
    rec.onstart  = () => setListening(true);
    rec.onresult = (e) => setQuestion(Array.from(e.results).map(r => r[0].transcript).join(""));
    rec.onend    = () => setListening(false);
    rec.onerror  = (e) => { setListening(false); if (e.error !== "aborted") setError("Mic error: " + e.error); };
    rec.start();
  }

  return (
    <div style={{ display: "flex", flexDirection: "column", height: "100%", background: "var(--bg)" }}>

      {/* Header */}
      <div style={{ background: "var(--navy)", padding: "20px 16px 16px", borderBottom: "3px solid var(--gold)", flexShrink: 0 }}>
        <div style={{ fontFamily: "var(--font-display)", fontSize: 28, color: "#fff", letterSpacing: 1 }}>🤖 Ask SkipShot</div>
        <div style={{ fontSize: 12, color: "rgba(255,255,255,0.6)", marginTop: 3 }}>{clubName} · All approved games · Powered by Gemini</div>
      </div>

      {/* Scrollable content */}
      <div style={{ flex: 1, overflowY: "auto", padding: "16px 16px 100px" }}>

        {/* Input area */}
        <div style={{ background: "var(--surface)", borderRadius: 14, border: "1px solid var(--border)", padding: "14px 14px 12px", marginBottom: 16 }}>
          <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: ".8px", textTransform: "uppercase", color: "var(--muted)", marginBottom: 8 }}>Your Question</div>
          <textarea
            value={question}
            onChange={e => setQuestion(e.target.value)}
            placeholder="e.g. Who had the most assists this season?"
            rows={2}
            style={{ width: "100%", border: "1.5px solid var(--border)", borderRadius: 10, padding: "10px 12px", fontSize: 14, fontFamily: "var(--font-body)", resize: "none", background: "var(--bg)", color: "var(--text)", outline: "none", boxSizing: "border-box", ...(listening ? { borderColor: "#ef4444", outline: "2px solid rgba(239,68,68,.3)" } : {}) }}
            onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); handleAsk(); } }}
          />
          <div style={{ display: "flex", gap: 8, marginTop: 10 }}>
            {canSpeak && (
              <button onClick={toggleSpeech} style={{ padding: "10px 14px", borderRadius: 10, border: "1.5px solid var(--border)", background: listening ? "rgba(239,68,68,.1)" : "var(--bg)", fontSize: 18, cursor: "pointer", flexShrink: 0 }} title={listening ? "Stop" : "Ask by voice"}>
                {listening ? "🔴" : "🎤"}
              </button>
            )}
            <button onClick={() => handleAsk()} disabled={loading || !question.trim()} style={{ flex: 1, padding: "11px 16px", borderRadius: 10, border: "none", background: question.trim() && !loading ? "var(--navy)" : "var(--border)", color: question.trim() && !loading ? "#fff" : "var(--muted)", fontSize: 14, fontWeight: 700, cursor: question.trim() && !loading ? "pointer" : "default", transition: "background .15s" }}>
              {loading ? "⏳ Thinking…" : "✨ Ask SkipShot"}
            </button>
          </div>
        </div>

        {/* Suggested questions */}
        {!answer && !loading && (
          <div style={{ marginBottom: 16 }}>
            <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: ".8px", textTransform: "uppercase", color: "var(--muted)", marginBottom: 8 }}>Try asking…</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
              {SUGGESTED.map(s => (
                <button key={s} onClick={() => { setQuestion(s); handleAsk(s); }}
                  style={{ textAlign: "left", padding: "11px 14px", borderRadius: 10, border: "1px solid var(--border)", background: "var(--surface)", fontSize: 13, color: "var(--navy)", fontWeight: 600, cursor: "pointer" }}>
                  {s}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Loading pulse */}
        {loading && (
          <div style={{ background: "var(--surface)", borderRadius: 14, border: "1px solid var(--border)", padding: "20px 16px", textAlign: "center" }}>
            <div style={{ fontSize: 28, marginBottom: 8 }}>🤖</div>
            <div style={{ fontSize: 13, color: "var(--muted)" }}>SkipShot is analysing {clubName} stats…</div>
          </div>
        )}

        {/* Answer */}
        {answer && !loading && (
          <div style={{ borderRadius: 14, overflow: "hidden", border: "1.5px solid var(--navy)" }}>

            {/* Text answer */}
            <div style={{ background: "var(--surface)", padding: "16px 16px 14px" }}>
              <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: ".8px", textTransform: "uppercase", color: "var(--navy)", marginBottom: 10 }}>SkipShot says…</div>
              <div style={{ fontSize: 15, lineHeight: 1.75, color: "var(--text)" }}>{answer}</div>
            </div>

            {/* Table */}
            {table && table.headers && table.rows && (
              <div style={{ overflowX: "auto", borderTop: "1.5px solid var(--navy)" }}>
                <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 13 }}>
                  <thead>
                    <tr>
                      {table.headers.map((h, i) => (
                        <th key={i} style={{ background: "var(--navy)", color: "#fff", padding: "8px 10px", fontWeight: 700, fontSize: 11, letterSpacing: ".6px", textTransform: "uppercase", textAlign: i === 0 || i === 1 ? "left" : "center", whiteSpace: "nowrap" }}>
                          {h}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {table.rows.map((row, ri) => (
                      <tr key={ri} style={{ background: ri % 2 === 0 ? "var(--surface)" : "var(--bg)" }}>
                        {row.map((cell, ci) => (
                          <td key={ci} style={{ padding: "9px 10px", borderBottom: "1px solid var(--border)", textAlign: ci === 0 || ci === 1 ? "left" : "center", fontFamily: ci > 1 ? "var(--font-mono, monospace)" : "inherit", fontWeight: ci === 1 ? 600 : 400, color: ri === 0 && ci > 1 ? "var(--navy)" : "var(--text)" }}>
                            {cell}
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}

            {/* Meta + reset */}
            <div style={{ background: "var(--surface)", padding: "10px 16px 14px", borderTop: "1px solid var(--border)" }}>
              {meta && <div style={{ fontSize: 11, color: "var(--muted)", marginBottom: 10, textAlign: "right" }}>{meta}</div>}
              <button onClick={() => { setAnswer(null); setTable(null); setMeta(null); setQuestion(""); }} style={{ width: "100%", padding: "10px", borderRadius: 10, border: "1.5px solid var(--border)", background: "var(--bg)", fontSize: 13, color: "var(--muted)", cursor: "pointer", fontWeight: 600 }}>
                Ask SkipShot another question
              </button>
            </div>
          </div>
        )}

        {/* Error */}
        {error && (
          <div style={{ background: "rgba(239,68,68,.07)", border: "1px solid rgba(239,68,68,.25)", borderRadius: 12, padding: "14px 16px", fontSize: 13, color: "#b91c1c" }}>
            ⚠️ {error}
          </div>
        )}
      </div>
    </div>
  );
}

