// ─── New Game Modal ───────────────────────────────────────────────────────────
// Two modes: "new" (create) and "join" (attach to admin-created game)
function NewGameModal({ db, onStart, onClose }) {
  const unsubmitted = db.games.filter(g => !g.serverKey && g.events && g.events.length > 0);
  return (
    <div className="player-picker" onClick={onClose}>
      <div className="picker-sheet" onClick={e => e.stopPropagation()} style={{ maxHeight: "92vh" }}>
        <div className="picker-header">
          <div style={{ fontSize: 26 }}>🤽</div>
          <div className="picker-title">
            <div className="picker-stat-name">New Game</div>
            <div className="picker-sub">Set up a game to track</div>
          </div>
          <button className="btn btn-icon" onClick={onClose}>✕</button>
        </div>
        {unsubmitted.length > 0 && (
          <div style={{
            margin: "0 16px 4px", padding: "10px 14px", borderRadius: 10,
            background: "rgba(245,158,11,0.1)", border: "1.5px solid rgba(245,158,11,0.4)",
            display: "flex", alignItems: "flex-start", gap: 10,
          }}>
            <span style={{ fontSize: 18, flexShrink: 0 }}>⚠️</span>
            <div style={{ fontSize: 12, color: "#92400e", lineHeight: 1.5 }}>
              <strong>You have {unsubmitted.length} unsubmitted game{unsubmitted.length > 1 ? "s" : ""}.</strong>
              {" "}Consider submitting {unsubmitted.length > 1 ? "them" : "it"} from My Games before starting a new one, so your stats aren't lost.
            </div>
          </div>
        )}
        <NewGamePanel db={db} onStart={onStart} onClose={onClose} />
      </div>
    </div>
  );
}

// ─── Join Existing Game Panel ─────────────────────────────────────────────────
// Fetches active server games and lets user pick one to track
function JoinGamePanel({ db, onStart, onClose }) {
  const [games,   setGames]   = useState(null);
  const [loading, setLoading] = useState(false);
  const [error,   setError]   = useState("");
  const [picked,  setPicked]  = useState(null);

  // Load roster key for the picked game
  const [rosterKey, setRosterKey] = useState("");
  const [rosters,   setRosters]   = useState(null);

  useEffect(() => {
    load();
  }, []);

  async function load() {
    setLoading(true); setError("");
    try {
      const [gRes, rRes] = await Promise.all([
        fetch(SERVER_URL + "?action=get_games&_=" + Date.now()),
        fetch(SERVER_URL + "?action=get_rosters&_=" + Date.now()),
      ]);
      const [gJson, rJson] = await Promise.all([gRes.json(), rRes.json()]);
      if (gJson.ok) setGames(gJson.games || []);
      else setError(gJson.error || "Could not load games");
      if (rJson.ok) setRosters(rJson.rosters || []);
    } catch { setError("Could not reach server"); }
    setLoading(false);
  }

  async function joinGame() {
    if (!picked) return;
    // If a WAVE roster was selected, load its players
    let rosterPlayers = [];
    if (rosterKey) {
      try {
        const res  = await fetch(SERVER_URL + "?action=get_roster_players&roster_key=" + encodeURIComponent(rosterKey) + "&_=" + Date.now());
        const json = await res.json();
        if (json.ok) rosterPlayers = json.roster.players || [];
      } catch {}
    }
    // Use server players if roster not picked but game has them
    const serverPlayers = picked.players || [];
    const players = rosterPlayers.length ? rosterPlayers : serverPlayers;

    onStart({
      waveTeamId:        null,
      waveTeamName:      picked.wave_team,
      waveRosterPlayers: players,
      opponentName:      picked.opponent,
      ageGroup:          picked.age_group || "",
      tournament:        picked.tournament || "",
      gameDate:          picked.game_date,
      _serverKey:        picked.game_key, // force this game_key
    });
  }

  // Rosters filtered to picked game's age group
  const waveRosters = rosters
    ? rosters.filter(r => !picked || !picked.age_group || !r.age_group || r.age_group === picked.age_group)
    : [];

  return (
    <>
      <div className="picker-list" style={{ padding: "12px 16px 0", overflowY: "auto" }}>
        {loading && <div style={{ textAlign: "center", padding: "30px 0", color: "var(--muted)" }}>⏳ Loading games…</div>}
        {error   && <div style={{ textAlign: "center", padding: "20px", color: "#ef4444", fontSize: 13 }}>{error} <button onClick={load} style={{ marginLeft: 8, padding: "4px 10px", borderRadius: 8, border: "1px solid var(--border)", background: "var(--surface)", cursor: "pointer", fontSize: 12 }}>Retry</button></div>}

        {games && games.length === 0 && (
          <div style={{ textAlign: "center", padding: "30px 0", color: "var(--muted)", fontSize: 13 }}>
            No active games on the server.<br/>Ask your admin to create a game, or use ➕ New Game.
          </div>
        )}

        {games && games.map(g => {
          const isSel = picked?.game_key === g.game_key;
          return (
            <div key={g.game_key}
              onClick={() => { setPicked(isSel ? null : g); setRosterKey(""); }}
              style={{
                padding: "12px 14px", borderRadius: 12, marginBottom: 8, cursor: "pointer",
                border: `2px solid ${isSel ? "var(--navy)" : "var(--border)"}`,
                background: isSel ? "var(--accent-dim)" : "var(--surface2)",
                transition: "all .15s",
              }}>
              <div style={{ fontWeight: 700, fontSize: 14, color: isSel ? "var(--navy)" : "var(--text)" }}>
                {g.wave_team} <span style={{ opacity: 0.5 }}>vs</span> {g.opponent}
              </div>
              <div style={{ fontSize: 11, color: "var(--muted)", marginTop: 3 }}>
                {new Date(g.game_date + "T12:00:00").toLocaleDateString("en-CA", { weekday: "short", month: "short", day: "numeric" })}
                {g.tournament ? ` · ${g.tournament}` : ""}
                {g.age_group  ? ` · ${g.age_group}` : ""}
                {g.status === "active" ? " · 🟢 Open" : ""}
              </div>
            </div>
          );
        })}

        {/* Roster picker for the selected game */}
        {picked && waveRosters.length > 0 && (
          <div style={{ marginTop: 8, paddingTop: 12, borderTop: "1px solid var(--border)" }}>
            <div className="form-label" style={{ marginBottom: 6 }}>Your Roster <span style={{ fontWeight: 400, opacity: 0.6 }}>(optional — picks up player names)</span></div>
            <select className="form-input form-select" value={rosterKey} onChange={e => setRosterKey(e.target.value)}>
              <option value="">— Use game's player list —</option>
              {waveRosters.map(r => (
                <option key={r.roster_key} value={r.roster_key}>
                  {r.name}{r.age_group ? ` · ${r.age_group}` : ""} ({r.player_count} players)
                </option>
              ))}
            </select>
          </div>
        )}
      </div>

      <div className="picker-cancel" style={{ display: "flex", gap: 10 }}>
        <button className="btn btn-secondary" style={{ flex: 1 }} onClick={onClose}>Cancel</button>
        <button className="btn btn-primary" style={{ flex: 1, background: "#16a34a", borderColor: "#16a34a" }}
          onClick={joinGame} disabled={!picked}>
          🤽 Track This Game
        </button>
      </div>
    </>
  );
}

// ─── New Game Panel ───────────────────────────────────────────────────────────
// Original multi-step create flow
function NewGamePanel({ db, onStart, onClose }) {
  const [step, setStep] = useState(1);

  // Step 1: WAVE team
  const [waveTeamName,    setWaveTeamName]     = useState("");
  const [importedRoster,  setImportedRoster]   = useState(null); // { name, age_group, tournament, players[] }
  const [importingRoster, setImportingRoster]  = useState(null);

  // Step 2: Opponent
  const [opponentName, setOpponentName] = useState("");
  const [oppCustom,    setOppCustom]    = useState(false); // typing manually

  // Step 3: Details
  const [ageGroup,    setAgeGroup]    = useState(db.ageGroup || "");
  const [tournament,  setTournament]  = useState(db.tournament || "");
  const [gameDate,    setGameDate]    = useState(new Date().toISOString().slice(0, 10));

  // Server rosters, team names, tournament names
  const [rosters,        setRosters]        = useState(null);
  const [teamNameList,   setTeamNameList]   = useState([]);
  const [tourNameList,   setTourNameList]   = useState([]);
  const [rostersLoading, setRostersLoading] = useState(false);
  const [rostersErr,     setRostersErr]     = useState("");

  useEffect(() => { fetchAll(); }, []);

  async function fetchAll() {
    setRostersLoading(true); setRostersErr("");
    try {
      const [rRes, tRes, tourRes] = await Promise.all([
        fetch(SERVER_URL + "?action=get_rosters&_=" + Date.now()),
        fetch(SERVER_URL + "?action=get_team_names&_=" + Date.now()),
        fetch(SERVER_URL + "?action=get_tournament_names&_=" + Date.now()),
      ]);
      const [rJson, tJson, tourJson] = await Promise.all([rRes.json(), tRes.json(), tourRes.json()]);
      if (rJson.ok)    setRosters(rJson.rosters || []);
      if (tJson.ok)    setTeamNameList(tJson.teams || []);
      if (tourJson.ok) setTourNameList(tourJson.tournaments || []);
      if (!rJson.ok)   setRostersErr(rJson.error || "Could not load rosters");
    } catch { setRostersErr("Could not reach server"); }
    setRostersLoading(false);
  }

  async function fetchAndImportRoster(rosterKey) {
    setImportingRoster(rosterKey);
    try {
      const res  = await fetch(SERVER_URL + "?action=get_roster_players&roster_key=" + encodeURIComponent(rosterKey) + "&_=" + Date.now());
      const json = await res.json();
      if (!json.ok) throw new Error(json.error);
      const roster = { ...json.roster, roster_key: rosterKey };
      setImportedRoster(roster);
      setWaveTeamName("");
      // Prefill tournament if roster has one and tournament field is empty
      if (roster.tournament) setTournament(roster.tournament);
      // Prefill age group if roster has one
      if (roster.age_group) setAgeGroup(roster.age_group);
    } catch (e) {
      alert("Could not load roster: " + e.message);
    }
    setImportingRoster(null);
  }

  // Distinct opponent names: server team_names list + roster names, deduped
  const oppChoices = [
    ...teamNameList.map(t => t.name),
    ...(rosters ? rosters.map(r => r.name) : []),
  ].filter((n, i, arr) => arr.indexOf(n) === i).sort();

  // Age groups filtered roster list for WAVE team picker
  const filteredRosters = rosters
    ? (ageGroup ? rosters.filter(r => r.age_group === ageGroup || !r.age_group) : rosters)
    : [];

  const ageGroups = ["10U","12U","14U","16U","18U","Other"];

  const canProceed1 = !!importedRoster || waveTeamName.trim().length > 0;
  const canProceed2 = opponentName.trim();
  const canCreate   = canProceed2 && gameDate;

  async function handleCreate() {
    if (!canCreate) return;
    const resolvedName = importedRoster
      ? importedRoster.name
      : waveTeamName.trim() || "WAVE";
    const resolvedAgeGroup = ageGroup || importedRoster?.age_group || "";
    onStart({
      waveTeamId:       null,
      waveTeamName:     resolvedName,
      waveRosterPlayers: importedRoster?.players || [],
      opponentName:     opponentName.trim(),
      ageGroup:         resolvedAgeGroup,
      tournament:       tournament.trim(),
      gameDate,
    });
  }

  const stepTitles = ["Select a Roster", "Opponent", "Details"];

  return (
    <>
        <div style={{ fontSize: 12, color: "var(--muted)", textAlign: "center", padding: "6px 0 2px", fontWeight: 600 }}>
          Step {step} of 3 — {stepTitles[step - 1]}
        </div>
        {/* Step dots */}
        <div style={{ display: "flex", justifyContent: "center", gap: 8, padding: "6px 0 4px" }}>
          {[1,2,3].map(s => (
            <div key={s} style={{ width: s === step ? 22 : 8, height: 8, borderRadius: 4, transition: "all 0.2s",
              background: s < step ? "var(--navy)" : s === step ? "var(--gold)" : "var(--border)" }} />
          ))}
        </div>

        <div className="picker-list" style={{ padding: "16px 20px 0" }}>

          {/* ── Step 1: Select a Roster ── */}
          {step === 1 && (
            <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>

              {/* Age group */}
              <div>
                <div className="form-label" style={{ marginBottom: 8 }}>Age Group / Division</div>
                <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 7 }}>
                  {ageGroups.map(ag => (
                    <button key={ag} onClick={() => setAgeGroup(ag === ageGroup ? "" : ag)} style={{
                      padding: "9px 4px", borderRadius: 10, cursor: "pointer",
                      fontFamily: "var(--font-body)", fontWeight: 700, fontSize: 13,
                      border: `2px solid ${ageGroup === ag ? "var(--navy)" : "var(--border)"}`,
                      background: ageGroup === ag ? "var(--accent-dim)" : "var(--surface)",
                      color: ageGroup === ag ? "var(--navy)" : "var(--muted)", transition: "all 0.15s",
                    }}>{ag}</button>
                  ))}
                </div>
              </div>

              {/* ── Roster picker ── */}
              {rostersLoading && (
                <div style={{ textAlign: "center", padding: "20px 0", color: "var(--muted)", fontSize: 13 }}>⏳ Loading rosters…</div>
              )}
              {rostersErr && (
                <div style={{ color: "#ef4444", fontSize: 13 }}>
                  ⚠️ {rostersErr}
                  <button onClick={fetchAll} style={{ marginLeft: 8, padding: "3px 8px", borderRadius: 7, border: "1px solid var(--border)", background: "var(--surface)", cursor: "pointer", fontSize: 12 }}>Retry</button>
                </div>
              )}
              {!rostersLoading && rosters && rosters.length > 0 && (
                <div style={{ display: "flex", flexDirection: "column", gap: 6, maxHeight: 260, overflowY: "auto" }}>
                  {filteredRosters.length === 0 && (
                    <div style={{ textAlign: "center", padding: "12px 0", color: "var(--muted)", fontSize: 13 }}>No rosters for this age group — try another or enter a name below.</div>
                  )}
                  {filteredRosters.map(r => {
                    const isSel = importedRoster?.roster_key === r.roster_key;
                    return (
                      <div key={r.roster_key} onClick={() => { if (!importingRoster) fetchAndImportRoster(r.roster_key); }}
                        style={{ display: "flex", alignItems: "center", gap: 10, padding: "11px 13px", borderRadius: 10, cursor: "pointer",
                          border: `2px solid ${isSel ? "var(--navy)" : "var(--border)"}`,
                          background: isSel ? "var(--accent-dim)" : "var(--surface)", transition: "all 0.15s" }}>
                        <div style={{ flex: 1 }}>
                          <div style={{ fontWeight: 700, fontSize: 14, color: isSel ? "var(--navy)" : "var(--text)" }}>{r.name}</div>
                          <div style={{ fontSize: 11, color: "var(--muted)", marginTop: 2 }}>
                            {r.player_count} players{r.age_group ? ` · ${r.age_group}` : ""}{r.tournament ? ` · ${r.tournament}` : ""}
                          </div>
                        </div>
                        {importingRoster === r.roster_key
                          ? <span style={{ fontSize: 12, color: "var(--muted)" }}>Loading…</span>
                          : isSel ? <span style={{ color: "var(--navy)", fontWeight: 700, fontSize: 16 }}>✓</span> : null}
                      </div>
                    );
                  })}
                </div>
              )}

              {/* Manual name fallback */}
              {!rostersLoading && (
                <div>
                  <div className="form-label" style={{ marginBottom: 6 }}>
                    {rosters && rosters.length > 0 ? "Or enter a team name manually" : "Enter your team name"}
                  </div>
                  <input className="form-input" placeholder="e.g. WAVE Piranhas"
                    value={importedRoster ? "" : waveTeamName}
                    onChange={e => { setWaveTeamName(e.target.value); setImportedRoster(null); }}
                    style={{ marginBottom: 0 }} />
                </div>
              )}
            </div>
          )}

          {/* ── Step 2: Opponent ── */}
          {step === 2 && (
            <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
              {oppChoices.length > 0 && !oppCustom && (
                <div>
                  <div className="form-label" style={{ marginBottom: 8 }}>Select Opponent</div>
                  <div style={{ display: "flex", flexDirection: "column", gap: 6, maxHeight: 280, overflowY: "auto" }}>
                    {oppChoices.map(name => (
                      <div key={name} onClick={() => setOpponentName(name)} style={{
                        display: "flex", alignItems: "center", gap: 10, padding: "12px 14px",
                        borderRadius: 10, cursor: "pointer",
                        border: `2px solid ${opponentName === name ? "var(--navy)" : "var(--border)"}`,
                        background: opponentName === name ? "var(--accent-dim)" : "var(--surface)",
                        transition: "all 0.15s",
                      }}>
                        <span style={{ fontSize: 15 }}>🤽</span>
                        <span style={{ flex: 1, fontWeight: 700, fontSize: 14, color: opponentName === name ? "var(--navy)" : "var(--text)" }}>{name}</span>
                        {opponentName === name && <span style={{ fontSize: 13 }}>✓</span>}
                      </div>
                    ))}
                  </div>
                  <button onClick={() => { setOppCustom(true); setOpponentName(""); }}
                    style={{ marginTop: 10, width: "100%", padding: "10px", borderRadius: 10, border: "1.5px dashed var(--border)", background: "none", cursor: "pointer", fontSize: 13, color: "var(--muted)", fontWeight: 600 }}>
                    ✏️ Not listed — enter name manually
                  </button>
                </div>
              )}
              {(oppCustom || oppChoices.length === 0) && (
                <div>
                  <div className="form-label" style={{ marginBottom: 6 }}>Opponent Name</div>
                  <input className="form-input" placeholder="e.g. Gatineau Olympiques" autoFocus
                    value={opponentName} onChange={e => setOpponentName(e.target.value)} />
                  {oppChoices.length > 0 && (
                    <button onClick={() => { setOppCustom(false); setOpponentName(""); }}
                      style={{ marginTop: 8, fontSize: 12, color: "var(--navy)", background: "none", border: "none", cursor: "pointer", textDecoration: "underline" }}>
                      ← Back to list
                    </button>
                  )}
                </div>
              )}
            </div>
          )}

          {/* ── Step 3: Details ── */}
          {step === 3 && (
            <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>

              {/* Summary */}
              <div style={{ background: "rgba(0,48,135,0.05)", border: "1px solid var(--border)", borderRadius: 10, padding: "12px 14px" }}>
                <div style={{ fontSize: 13, fontWeight: 700, color: "var(--navy)", marginBottom: 4 }}>
                  {importedRoster?.name || waveTeamName || "Your team"}
                  <span style={{ color: "var(--muted)", fontWeight: 400, margin: "0 6px" }}>vs</span>
                  {opponentName}
                </div>
                {(ageGroup || importedRoster?.age_group) && <div style={{ fontSize: 11, color: "var(--muted)" }}>{ageGroup || importedRoster?.age_group}</div>}
                {importedRoster && <div style={{ fontSize: 11, color: "#16a34a", marginTop: 2 }}>✓ {importedRoster.players?.length || 0} players imported</div>}
              </div>

              <div>
                <div className="form-label" style={{ marginBottom: 6 }}>Date</div>
                <input className="form-input" type="date" value={gameDate}
                  onChange={e => setGameDate(e.target.value)} />
              </div>

              <div>
                <div className="form-label" style={{ marginBottom: 6 }}>Tournament <span style={{ fontWeight: 400, color: "var(--muted)" }}>(optional)</span></div>
                {tourNameList.length > 0 ? (
                  <select className="form-input form-select" value={tournament} onChange={e => setTournament(e.target.value)}>
                    <option value="">— none —</option>
                    {tourNameList.map(t => <option key={t.name} value={t.name}>{t.name}</option>)}
                    <option value="__custom__">Other (type below)</option>
                  </select>
                ) : null}
                {(tourNameList.length === 0 || tournament === "__custom__") && (
                  <input className="form-input" placeholder="e.g. Ottawa Spring Open"
                    value={tournament === "__custom__" ? "" : tournament}
                    onChange={e => setTournament(e.target.value)}
                    style={{ marginTop: tourNameList.length > 0 ? 8 : 0 }} />
                )}
              </div>

              {!ageGroup && (
                <div>
                  <div className="form-label" style={{ marginBottom: 8 }}>Age Group <span style={{ fontWeight: 400, color: "var(--muted)" }}>(optional)</span></div>
                  <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 7 }}>
                    {ageGroups.map(ag => (
                      <button key={ag} onClick={() => setAgeGroup(ag === ageGroup ? "" : ag)} style={{
                        padding: "9px 4px", borderRadius: 10, cursor: "pointer",
                        fontFamily: "var(--font-body)", fontWeight: 700, fontSize: 13,
                        border: `2px solid ${ageGroup === ag ? "var(--navy)" : "var(--border)"}`,
                        background: ageGroup === ag ? "var(--accent-dim)" : "var(--surface)",
                        color: ageGroup === ag ? "var(--navy)" : "var(--muted)", transition: "all 0.15s",
                      }}>{ag}</button>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}

        </div>

        <div className="picker-cancel" style={{ display: "flex", gap: 10 }}>
          {step > 1
            ? <button className="btn btn-secondary" style={{ flex: 1 }} onClick={() => setStep(s => s - 1)}>← Back</button>
            : <button className="btn btn-secondary" style={{ flex: 1 }} onClick={onClose}>Cancel</button>
          }
          {step < 3
            ? <button className="btn btn-primary" style={{ flex: 1 }}
                onClick={() => setStep(s => s + 1)}
                disabled={step === 1 ? !canProceed1 : !canProceed2}>
                Next →
              </button>
            : <button className="btn btn-primary" style={{ flex: 1, background: "#16a34a", borderColor: "#16a34a" }}
                onClick={handleCreate}
                disabled={!canCreate}>
                🤽 Start Game
              </button>
          }
        </div>
      </>
    );
}

// ─── Track Screen ─────────────────────────────────────────────────────────────
// ─── Game List Screen ──────────────────────────────────────────────────────────
// Shown when no active game is loaded. Displays all local games with server
// status (Submitted / Accepted), a Clear List option, and New Game CTA.
function GameListScreen({ db, update, creating, showNewGame, setShowNewGame, handleCreateGame, setViewGameId, push, clubName }) {
  const archivedIds  = new Set(db.archivedGameIds || []);
  const myGames      = db.games
    .filter(g => !archivedIds.has(g.id))
    .slice().sort((a, b) => new Date(b.date) - new Date(a.date));

  const [showConfirmClear, setShowConfirmClear] = useState(false);
  const [confirmArchive,   setConfirmArchive]   = useState(null); // game object to archive
  const [community,        setCommunity]        = useState(null);
  const [commLoading,      setCommLoading]      = useState(false);
  const [commError,        setCommError]        = useState("");
  const [pubReports,       setPubReports]       = useState(null);
  const [pubLoading,       setPubLoading]       = useState(false);
  const [viewReport,       setViewReport]       = useState(null);
  const [submitGame,       setSubmitGame]       = useState(null);
  const [reportGame,       setReportGame]       = useState(null);
  const [officialKey,      setOfficialKey]      = useState(null);
  const [officialStatus,   setOfficialStatus]   = useState({}); // serverKey → "official" | "pending"

  useEffect(() => {
    // Fetch official status for all submitted games
    const submittedKeys = myGames.filter(g => g.serverKey).map(g => g.serverKey);
    submittedKeys.forEach(key => {
      fetch(`${SERVER_URL}?action=get_official_game&game_key=${encodeURIComponent(key)}&_=${Date.now()}`)
        .then(r => r.json())
        .then(j => {
          setOfficialStatus(prev => ({ ...prev, [key]: j.ok ? "official" : "pending" }));
        })
        .catch(() => {});
    });

    setCommLoading(true);
    fetch(`${SERVER_URL}?action=get_community_games&_=${Date.now()}`)
      .then(r => r.json())
      .then(j => { setCommunity(j.ok ? j.games : []); setCommError(j.ok ? "" : (j.error || "Could not load")); })
      .catch(() => { setCommunity([]); setCommError("Could not reach server"); })
      .finally(() => setCommLoading(false));

    setPubLoading(true);
    fetch(`${SERVER_URL}?action=get_published_reports&_=${Date.now()}`)
      .then(r => r.json())
      .then(j => setPubReports(j.ok ? j.reports : []))
      .catch(() => setPubReports([]))
      .finally(() => setPubLoading(false));
  }, []);

  function archiveGame(gameId, e) {
    e.stopPropagation();
    update(d => {
      if (!d.archivedGameIds) d.archivedGameIds = [];
      if (!d.archivedGameIds.includes(gameId)) d.archivedGameIds.push(gameId);
      if (d.activeGameId === gameId) d.activeGameId = null;
    });
    const g = db.games.find(x => x.id === gameId);
    if (g && g.serverKey && localStorage.getItem("wp_active_server_key") === g.serverKey)
      localStorage.removeItem("wp_active_server_key");
  }

  function clearList() {
    update(d => {
      if (!d.archivedGameIds) d.archivedGameIds = [];
      d.games.forEach(g => { if (!d.archivedGameIds.includes(g.id)) d.archivedGameIds.push(g.id); });
      d.activeGameId = null;
    });
    localStorage.removeItem("wp_active_server_key");
    setShowConfirmClear(false);
    push("Game list cleared", "🗑️");
  }

  const fmtDate = iso => new Date(iso).toLocaleDateString("en-CA", { month: "short", day: "numeric", year: "numeric" });

  return (
    <div>
      <div className="page-header">
        <div className="page-title">{clubName} STATS TRACKER</div>
        <div className="page-sub">{db.season || (clubName + " Stats Tracker")}</div>
      </div>

      <div style={{ padding: "0 16px 100px" }}>

        {/* New Game */}
        <button className="btn btn-primary"
          style={{ width: "100%", marginBottom: 24, padding: "16px", fontSize: 16 }}
          onClick={() => setShowNewGame(true)} disabled={creating}>
          {creating ? "⏳ Creating game…" : "🤽 + New Game"}
        </button>

        {/* ── My Games ── */}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
          <div className="section-label" style={{ padding: 0 }}>My Games</div>
          {myGames.length > 0 && (
            <button type="button" onClick={() => setShowConfirmClear(true)}
              style={{ fontSize: 12, fontWeight: 700, color: "var(--danger)", background: "none", border: "none", cursor: "pointer" }}>
              Clear
            </button>
          )}
        </div>

        {myGames.length === 0 && (
          <div style={{ textAlign: "center", padding: "16px 0 28px", color: "var(--muted)", fontSize: 13 }}>
            No games yet — tap New Game to get started.
          </div>
        )}

        {myGames.map(g => {
          const ht = db.teams.find(t => t.id === g.homeTeamId);
          const at = db.teams.find(t => t.id === g.awayTeamId);
          return (
            <div key={g.id} style={{ background: "var(--surface)", borderRadius: 14, border: `1px solid ${g.abandoned ? "rgba(239,68,68,.25)" : "var(--border)"}`, marginBottom: 10, overflow: "hidden", opacity: g.abandoned ? 0.8 : 1 }}>
              {/* Card header — tap to resume tracking */}
              <div onClick={() => { if (g.serverKey) localStorage.setItem("wp_active_server_key", g.serverKey); update(d => { const gx = d.games.find(x => x.id === g.id); if (gx) { gx.abandoned = false; d.activeGameId = gx.id; } }); setViewGameId(g.id); }}
                style={{ display: "flex", alignItems: "center", padding: "12px 14px", cursor: "pointer", gap: 10 }}>
                <div style={{ flex: 1 }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 8, fontWeight: 700, fontSize: 14, flexWrap: "wrap" }}>
                    <span style={{ color: ht?.color || "var(--navy)" }}>{ht?.name || "Home"}</span>
                    <span style={{ fontFamily: "var(--font-mono)", color: "var(--navy)", fontWeight: 900 }}>{g.homeScore}–{g.awayScore}</span>
                    <span style={{ color: at?.color || "var(--muted)" }}>{at?.name || "Away"}</span>
                  </div>
                  <div style={{ fontSize: 11, color: "var(--muted)", marginTop: 3 }}>
                    {g.ageGroup ? `${g.ageGroup} · ` : ""}
                    {g.tournament ? `${g.tournament} · ` : ""}
                    {fmtDate(g.date)}
                  </div>
                </div>
                <span style={{ fontSize: 11, color: "var(--muted)" }}>▶</span>
              </div>

              {/* Action bar */}
              {(() => {
                const isAbandoned = !!g.abandoned;

                // Abandoned state — only Resume and Delete
                if (isAbandoned) {
                  return (
                    <div style={{ borderTop: "1px solid var(--border)" }}>
                      <div style={{ padding: "5px 14px 6px", display: "flex", alignItems: "center", gap: 6, borderBottom: "1px solid var(--border)", background: "rgba(239,68,68,.04)" }}>
                        <span style={{ fontSize: 11 }}>⚠️</span>
                        <span style={{ fontSize: 11, fontWeight: 700, color: "#b91c1c", letterSpacing: 0.3 }}>Game abandoned — stats not submitted</span>
                      </div>
                      <div style={{ display: "flex" }}>
                        <button
                          onClick={() => { if (g.serverKey) localStorage.setItem("wp_active_server_key", g.serverKey); update(d => { const gx = d.games.find(x => x.id === g.id); if (gx) { gx.abandoned = false; d.activeGameId = gx.id; } }); setViewGameId(g.id); }}
                          style={{ flex: 1, padding: "9px 0", background: "none", border: "none", borderRight: "1px solid var(--border)", cursor: "pointer", fontSize: 12, fontWeight: 700, color: "var(--navy)" }}>
                          ▶ Resume
                        </button>
                        <button
                          onClick={e => { e.stopPropagation(); setConfirmArchive(g); }}
                          style={{ flex: 1, padding: "9px 0", background: "none", border: "none", cursor: "pointer", fontSize: 12, fontWeight: 700, color: "#ef4444" }}>
                          🗑 Delete
                        </button>
                      </div>
                    </div>
                  );
                }

                // Normal state
                const isSubmitted = !!g.serverKey;
                const statusLoading = isSubmitted && !(g.serverKey in officialStatus);
                const status      = isSubmitted ? (officialStatus[g.serverKey] || "pending") : null;
                const isOfficial  = status === "official";
                const isPending   = status === "pending";
                const submitDisabled = isSubmitted;

                const officialIcon  = isOfficial  ? "✅" : isPending ? "🔍" : "⏳";
                const officialLabel = isOfficial  ? "Official" : isPending ? "Under Review" : "Checking…";
                const officialColor = isOfficial  ? "#166534" : isPending ? "#1d4ed8" : "var(--muted)";

                return (
                  <div style={{ display: "flex", borderTop: "1px solid var(--border)" }}>
                    <button
                      onClick={() => !submitDisabled && setSubmitGame(g)}
                      disabled={submitDisabled}
                      style={{ flex: 1, padding: "9px 0", background: "none", border: "none", borderRight: "1px solid var(--border)", cursor: submitDisabled ? "default" : "pointer", fontSize: 12, fontWeight: 700, color: submitDisabled ? "var(--muted)" : "var(--navy)", opacity: submitDisabled ? 0.4 : 1 }}>
                      📤 Submit
                    </button>
                    <button onClick={() => setReportGame(g)} style={{ flex: 1, padding: "9px 0", background: "none", border: "none", borderRight: "1px solid var(--border)", cursor: "pointer", fontSize: 12, fontWeight: 700, color: "var(--navy)" }}>
                      📊 Report
                    </button>
                    {isSubmitted && (
                      <button
                        onClick={() => isOfficial ? setOfficialKey(g.serverKey) : null}
                        style={{ flex: 1, padding: "9px 0", background: "none", border: "none", borderRight: "1px solid var(--border)", cursor: isOfficial ? "pointer" : "default", fontSize: 12, fontWeight: 700, color: officialColor }}>
                        {officialIcon} {officialLabel}
                      </button>
                    )}
                    <button onClick={e => { e.stopPropagation(); setConfirmArchive(g); }} style={{ width: 44, padding: "9px 0", background: "none", border: "none", cursor: "pointer", fontSize: 15, color: "#ef4444" }}>
                      ✕
                    </button>
                  </div>
                );
              })()}
            </div>
          );
        })}

        {/* ── Community Games ── */}
        <div className="section-label" style={{ padding: "12px 0 10px" }}>Community Games</div>
        {commLoading && <div style={{ textAlign: "center", padding: "16px 0", color: "var(--muted)", fontSize: 13 }}>Loading…</div>}
        {!commLoading && commError && <div style={{ textAlign: "center", padding: "12px 0", color: "var(--muted)", fontSize: 12 }}>⚠️ {commError}</div>}
        {!commLoading && !commError && community && community.length === 0 && (
          <div style={{ textAlign: "center", padding: "16px 0 8px", color: "var(--muted)", fontSize: 13 }}>No community games yet.</div>
        )}
        {/* Faded WAVE logo — shown when community list is empty or loading */}
        {!commLoading && community && community.length === 0 && (
          <div style={{ textAlign: "center", padding: "8px 0 24px" }}>
            <img src={WAVE_LOGO} alt="WAVE Swim and Polo" style={{ width: 180, height: 180, objectFit: "contain", opacity: 0.08 }} />
          </div>
        )}
        {community && community.map(g => (
          <div key={g.game_key} style={{ background: "var(--surface)", borderRadius: 14, border: "1px solid var(--border)", marginBottom: 10, overflow: "hidden" }}>
            <div style={{ padding: "12px 14px" }}>
              <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 3 }}>
                {g.wave_team}
                <span style={{ fontFamily: "var(--font-mono)", color: "var(--navy)", fontWeight: 900, margin: "0 6px" }}>{g.wave_score}–{g.opp_score}</span>
                {g.opponent}
              </div>
              <div style={{ fontSize: 11, color: "var(--muted)" }}>
                {g.age_group ? `${g.age_group} · ` : ""}
                {g.tournament ? `${g.tournament} · ` : ""}
                {fmtDate(g.game_date)}
              </div>
            </div>
            <div style={{ borderTop: "1px solid var(--border)" }}>
              <button onClick={() => setOfficialKey(g.game_key)} style={{ width: "100%", padding: "9px 0", background: "none", border: "none", cursor: "pointer", fontSize: 12, fontWeight: 700, color: "#166534" }}>
                📖 Read Report
              </button>
            </div>
          </div>
        ))}

        {/* ── Published Reports ── */}
        {(pubLoading || (pubReports && pubReports.length > 0)) && (
          <>
            <div className="section-label" style={{ padding: "12px 0 10px" }}>Reports from Admin</div>
            {pubLoading && <div style={{ textAlign: "center", padding: "16px 0", color: "var(--muted)", fontSize: 13 }}>Loading…</div>}
            {pubReports && pubReports.map(r => {
              const typeIcon = { tournament: "🏆", season: "📅", player: "👤", custom: "📄" }[r.type] || "📄";
              return (
                <div key={r.report_key} style={{ background: "var(--surface)", borderRadius: 14, border: "1px solid var(--border)", marginBottom: 10, overflow: "hidden" }}>
                  <div style={{ padding: "12px 14px" }}>
                    <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 3 }}>{typeIcon} {r.title}</div>
                    <div style={{ fontSize: 11, color: "var(--muted)" }}>
                      {r.subtitle ? `${r.subtitle} · ` : ""}
                      {r.season ? `${r.season} · ` : ""}
                      {new Date(r.published_at).toLocaleDateString("en-CA", { month: "short", day: "numeric", year: "numeric" })}
                    </div>
                  </div>
                  <div style={{ borderTop: "1px solid var(--border)" }}>
                    <button onClick={() => {
                      // Fetch full report data then display
                      fetch(`${SERVER_URL}?action=get_published_report&report_key=${encodeURIComponent(r.report_key)}&_=${Date.now()}`)
                        .then(res => res.json())
                        .then(j => { if (j.ok) setViewReport(j.report); });
                    }} style={{ width: "100%", padding: "9px 0", background: "none", border: "none", cursor: "pointer", fontSize: 12, fontWeight: 700, color: "var(--navy)" }}>
                      📖 Read Report
                    </button>
                  </div>
                </div>
              );
            })}
          </>
        )}
      </div>

      {/* Report viewer sheet */}
      {viewReport && (
        <div className="player-picker" onClick={() => setViewReport(null)}>
          <div className="picker-sheet" onClick={e => e.stopPropagation()} style={{ maxHeight: "92vh" }}>
            <div className="picker-header">
              <div style={{ fontSize: 24 }}>📄</div>
              <div className="picker-title">
                <div className="picker-stat-name">{viewReport.title}</div>
                {viewReport.subtitle && <div className="picker-sub">{viewReport.subtitle}</div>}
              </div>
              <button className="btn btn-icon" onClick={() => setViewReport(null)}>✕</button>
            </div>
            <div style={{ overflowY: "auto", padding: "0 16px 24px" }}>
              {viewReport.season && (
                <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 12 }}>
                  <span style={{ fontSize: 11, fontWeight: 700, color: "var(--navy)", background: "var(--accent-dim)", padding: "2px 8px", borderRadius: 20 }}>{viewReport.season}</span>
                  <span style={{ fontSize: 11, color: "var(--muted)", background: "var(--surface2)", padding: "2px 8px", borderRadius: 20 }}>{viewReport.type}</span>
                  <span style={{ fontSize: 11, color: "var(--muted)", background: "var(--surface2)", padding: "2px 8px", borderRadius: 20 }}>
                    {new Date(viewReport.published_at).toLocaleDateString("en-CA", { month: "long", day: "numeric", year: "numeric" })}
                  </span>
                </div>
              )}
              <ReportViewer data={viewReport.data} />
            </div>
          </div>
        </div>
      )}
      {confirmArchive && (
        <div className="player-picker" onClick={() => setConfirmArchive(null)}>
          <div className="picker-sheet" onClick={e => e.stopPropagation()} style={{ maxHeight: "50vh" }}>
            <div className="picker-header">
              <div style={{ fontSize: 24 }}>🗑️</div>
              <div className="picker-title">
                <div className="picker-stat-name">Remove Game?</div>
                <div className="picker-sub">This cannot be undone</div>
              </div>
              <button className="btn btn-icon" onClick={() => setConfirmArchive(null)}>✕</button>
            </div>
            <div style={{ padding: "16px 20px" }}>
              {(() => {
                const ht = db.teams.find(t => t.id === confirmArchive.homeTeamId);
                const at = db.teams.find(t => t.id === confirmArchive.awayTeamId);
                return (
                  <div style={{ fontWeight: 700, fontSize: 15, color: "var(--text)", marginBottom: 12, textAlign: "center" }}>
                    {ht?.name || "Home"} {confirmArchive.homeScore}–{confirmArchive.awayScore} {at?.name || "Away"}
                  </div>
                );
              })()}
              <div style={{ background: "rgba(239,68,68,0.07)", border: "1.5px solid rgba(239,68,68,0.25)", borderRadius: 10, padding: "12px 14px", fontSize: 13, color: "#7f1d1d", lineHeight: 1.6 }}>
                ⚠️ <strong>This game will be permanently removed from your device.</strong>
                {" "}You will no longer be able to resume tracking, edit the roster, or submit stats to the server. This action cannot be undone.
              </div>
            </div>
            <div className="picker-cancel" style={{ display: "flex", gap: 10 }}>
              <button className="btn btn-secondary" style={{ flex: 1 }} onClick={() => setConfirmArchive(null)}>Cancel</button>
              <button className="btn btn-primary" style={{ flex: 1, background: "#dc2626", borderColor: "#dc2626" }}
                onClick={e => { archiveGame(confirmArchive.id, e); setConfirmArchive(null); push("Game removed", "🗑️"); }}>
                🗑️ Remove Game
              </button>
            </div>
          </div>
        </div>
      )}

      {showConfirmClear && (
        <div className="player-picker" onClick={() => setShowConfirmClear(false)}>
          <div className="picker-sheet" onClick={e => e.stopPropagation()} style={{ maxHeight: "50vh" }}>
            <div className="picker-header">
              <div style={{ fontSize: 24 }}>🗑️</div>
              <div className="picker-title">
                <div className="picker-stat-name">Clear My Games?</div>
                <div className="picker-sub">Hides {myGames.length} game{myGames.length !== 1 ? "s" : ""} from this list</div>
              </div>
              <button className="btn btn-icon" onClick={() => setShowConfirmClear(false)}>✕</button>
            </div>
            <div style={{ padding: "16px" }}>
              <div style={{ fontSize: 13, color: "var(--muted)", marginBottom: 16, lineHeight: 1.5 }}>
                Games are hidden from this list but your stats stay available. Nothing is deleted.
              </div>
              <div style={{ display: "flex", gap: 10 }}>
                <button className="btn btn-secondary" style={{ flex: 1 }} onClick={() => setShowConfirmClear(false)}>Cancel</button>
                <button className="btn btn-danger"    style={{ flex: 1 }} onClick={clearList}>Clear</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {submitGame  && <InlineSubmitSheet  game={submitGame}  db={db} push={push} onClose={() => setSubmitGame(null)} />}
      {reportGame  && <InlineReportSheet  game={reportGame}  db={db} onClose={() => setReportGame(null)} />}
      {officialKey && <InlineOfficialSheet serverKey={officialKey} db={db} onClose={() => setOfficialKey(null)} />}
      {showNewGame && <NewGameModal db={db} onStart={handleCreateGame} onClose={() => setShowNewGame(false)} />}
    </div>
  );
}

// ─── Inline Submit Sheet ───────────────────────────────────────────────────────
function InlineSubmitSheet({ game, db, push, onClose }) {
  const [initials, setInitials] = useState(() => localStorage.getItem("wp_initials") || "");
  const [isCoach,  setIsCoach]  = useState(() => localStorage.getItem("wp_is_coach") === "1");
  const [status,   setStatus]   = useState("idle");
  const [errMsg,   setErrMsg]   = useState("");

  const homeTeam = db.teams.find(t => t.id === game.homeTeamId);
  const awayTeam = db.teams.find(t => t.id === game.awayTeamId);

  function saveIdentity(init, coach) {
    setInitials(init); setIsCoach(coach);
    localStorage.setItem("wp_initials", init);
    localStorage.setItem("wp_is_coach", coach ? "1" : "0");
  }

  async function submit() {
    if (!initials.trim()) { push("Enter your initials first", "⚠️"); return; }
    if (!game.serverKey)  { push("This game has no server connection — stats saved locally only", "💾"); return; }
    setStatus("sending"); setErrMsg("");
    try {
      const res  = await fetch(SERVER_URL, {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action: "submit_stats", data: {
          game_key:     game.serverKey,
          tracker_name: initials.trim().toUpperCase(),
          is_coach:     isCoach ? 1 : 0,
          wave_score:   game.homeScore,
          opp_score:    game.awayScore,
          wave_team:    db.teams.find(t => t.id === game.homeTeamId)?.name || "WAVE",
          opponent:     db.teams.find(t => t.id === game.awayTeamId)?.name || "Opponent",
          game_date:    game.date || new Date().toISOString().slice(0,10),
          tournament:   game.tournament || "",
          age_group:    game.ageGroup || "",
          events:       game.events.map(e => ({
            id: e.id, stat: e.stat, playerId: e.playerId,
            ts: e.ts, period: e.period || null,
            shotLocation: e.shotLocation || null,
            situation: e.situation || null, playType: e.playType || null,
            oppNum: e.oppNum || null, shotExp: e.shotExp || null, wetDry: e.wetDry || null,
          })),
        }}),
      });
      const json = await res.json();
      if (!json.ok) throw new Error(json.error || "Server error");
      setStatus("done");
      push("Stats submitted!", "📤");
    } catch(err) { setStatus("error"); setErrMsg(err.message); }
  }

  return (
    <div className="player-picker" onClick={onClose}>
      <div className="picker-sheet" onClick={e => e.stopPropagation()} style={{ maxHeight: "88vh" }}>
        <div className="picker-header">
          <div style={{ fontSize: 24 }}>📤</div>
          <div className="picker-title">
            <div className="picker-stat-name">Submit Stats</div>
            <div className="picker-sub">{homeTeam?.name} {game.homeScore}–{game.awayScore} {awayTeam?.name}</div>
          </div>
          <button className="btn btn-icon" onClick={onClose}>✕</button>
        </div>
        <div style={{ padding: "16px", overflowY: "auto" }}>
          <label className="form-label" style={{ display: "block", marginBottom: 6 }}>Your Initials</label>
          <input className="form-input" maxLength={5} placeholder="e.g. SB"
            value={initials} onChange={e => saveIdentity(e.target.value.toUpperCase(), isCoach)}
            style={{ textTransform: "uppercase", letterSpacing: 2, fontWeight: 700, fontSize: 18, width: 110, marginBottom: 12 }} />

          <div onClick={() => saveIdentity(initials, !isCoach)} style={{
            display: "flex", alignItems: "center", gap: 10, cursor: "pointer", marginBottom: 16,
            padding: "10px 14px", borderRadius: 10,
            background: isCoach ? "rgba(255,199,44,0.15)" : "var(--bg)",
            border: `2px solid ${isCoach ? "var(--gold)" : "var(--border)"}`,
          }}>
            <div style={{ width: 22, height: 22, borderRadius: 6, flexShrink: 0, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 14,
              background: isCoach ? "var(--gold)" : "transparent", border: `2px solid ${isCoach ? "var(--gold)" : "var(--border)"}`, color: isCoach ? "#5a3e00" : "transparent" }}>
              {isCoach ? "✓" : ""}
            </div>
            <div>
              <div style={{ fontWeight: 700, fontSize: 14, color: isCoach ? "#92650a" : "var(--text)" }}>🏅 I'm a coach</div>
              <div style={{ fontSize: 11, color: "var(--muted)" }}>Coach submissions are highlighted for the admin</div>
            </div>
          </div>

          <div style={{ fontSize: 13, color: "var(--muted)", marginBottom: 14 }}>{game.events.length} events recorded</div>

          {errMsg && (
            <div style={{ padding: "10px 14px", background: "rgba(239,68,68,0.08)", border: "1px solid rgba(239,68,68,0.3)", borderRadius: 10, fontSize: 13, color: "var(--danger)", marginBottom: 12 }}>
              ⚠️ {errMsg}
            </div>
          )}

          {status === "done" ? (
            <div style={{ textAlign: "center", padding: "20px", background: "rgba(22,163,74,0.07)", border: "2px solid rgba(22,163,74,0.3)", borderRadius: 12 }}>
              <div style={{ fontSize: 36, marginBottom: 6 }}>📤</div>
              <div style={{ fontWeight: 700, color: "#166534", fontSize: 15 }}>Submitted!</div>
              <div style={{ fontSize: 12, color: "var(--muted)", marginTop: 4 }}>The coaching staff will review your stats.</div>
            </div>
          ) : (
            <button className="btn btn-primary" style={{ width: "100%" }}
              onClick={submit} disabled={status === "sending" || !initials.trim()}>
              {status === "sending" ? "⏳ Sending…" : `📤 Submit as ${initials.trim().toUpperCase() || "?"}${isCoach ? " 🏅" : ""}`}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

// ─── Inline Report Sheet ───────────────────────────────────────────────────────
function InlineReportSheet({ game, db, onClose }) {
  const homeTeam   = db.teams.find(t => t.id === game.homeTeamId);
  const awayTeam   = db.teams.find(t => t.id === game.awayTeamId);
  const reportData = buildTrackerReport([game], db,
    `${homeTeam?.name || "WAVE"} vs ${awayTeam?.name || "Opponent"}`,
    game.tournament ? `${game.tournament}${game.date ? " · " + new Date(game.date+"T12:00:00").toLocaleDateString("en-CA",{month:"short",day:"numeric",year:"numeric"}) : ""}` : "",
    "game");
  const [exporting, setExporting] = useState(false);

  async function handlePDF() {
    setExporting(true);
    try { await exportReportPDF(reportData, `${homeTeam?.name||"WAVE"}_vs_${awayTeam?.name||"Opp"}`); }
    catch(e) { alert("PDF error: " + e.message); }
    setExporting(false);
  }

  return (
    <div className="player-picker" onClick={onClose}>
      <div className="picker-sheet" onClick={e => e.stopPropagation()} style={{ maxHeight: "92vh" }}>
        <div className="picker-header">
          <div style={{ fontSize: 24 }}>📊</div>
          <div className="picker-title">
            <div className="picker-stat-name">Game Report</div>
            <div className="picker-sub">{homeTeam?.name} {game.homeScore}–{game.awayScore} {awayTeam?.name}</div>
          </div>
          <div style={{ display: "flex", gap: 6 }}>
            <button onClick={handlePDF} disabled={exporting} style={{ padding: "6px 12px", borderRadius: 8, border: "1.5px solid var(--border)", background: "var(--surface2)", fontSize: 12, fontWeight: 700, cursor: "pointer", color: "var(--navy)" }}>
              {exporting ? "⏳" : "📄 PDF"}
            </button>
            <button className="btn btn-icon" onClick={onClose}>✕</button>
          </div>
        </div>
        <div style={{ overflowY: "auto", paddingBottom: 24 }}>
          <GameReportCard
            reportData={reportData}
            badge={{ icon: "📊",
              title: `${homeTeam?.name||"WAVE"} ${game.homeScore}–${game.awayScore} ${awayTeam?.name||"Opponent"}`,
              sub: [game.tournament, game.date ? new Date(game.date+"T12:00:00").toLocaleDateString("en-CA",{month:"short",day:"numeric",year:"numeric"}) : "", `${game.events?.length||0} events`].filter(Boolean).join(" · "),
              bg: "linear-gradient(135deg,#1e3a6e,#003087)" }}
            exporting={exporting}
            onPDF={handlePDF}
          />
        </div>
      </div>
    </div>
  );
}

// ─── Inline Official Report Sheet ─────────────────────────────────────────────
function InlineOfficialSheet({ serverKey, db, onClose }) {
  const [loading,   setLoading]   = useState(true);
  const [data,      setData]      = useState(null);
  const [error,     setError]     = useState(null);
  const [exporting, setExporting] = useState(false);

  useEffect(() => {
    setLoading(true); setError(null); setData(null);
    fetch(`${SERVER_URL}?action=get_official_game&game_key=${encodeURIComponent(serverKey)}&_=${Date.now()}`)
      .then(r => r.json())
      .then(j => { setLoading(false); if (j.ok) setData(j); else setError(j.error || "No official record yet."); })
      .catch(() => { setLoading(false); setError("Could not reach server."); });
  }, [serverKey]);

  const reportData = data ? (() => {
    const { game: g, official } = data;
    const adminGame = {
      game_key: serverKey, game_date: g.game_date, opponent: g.opponent,
      tournament: g.tournament, wave_team: g.wave_team,
      wave_score: official.wave_score, opp_score: official.opp_score,
      players: g.players || [], official_events: official.events || [],
    };
    return crunchTrackerReport([adminGame],
      `${g.wave_team} vs ${g.opponent}`,
      [g.tournament, new Date(g.game_date+"T12:00:00").toLocaleDateString("en-CA",{month:"short",day:"numeric",year:"numeric"})].filter(Boolean).join(" · "),
      "game");
  })() : null;

  async function handlePDF() {
    if (!reportData || !data) return;
    setExporting(true);
    try { await exportReportPDF(reportData, `${data.game.wave_team}_vs_${data.game.opponent}`); }
    catch(e) { alert("PDF error: " + e.message); }
    setExporting(false);
  }

  return (
    <div className="player-picker" onClick={onClose}>
      <div className="picker-sheet" onClick={e => e.stopPropagation()} style={{ maxHeight: "92vh" }}>
        <div className="picker-header">
          <div style={{ fontSize: 24 }}>✅</div>
          <div className="picker-title">
            <div className="picker-stat-name">Official Report</div>
            <div className="picker-sub">{data ? `${data.game.wave_team} vs ${data.game.opponent}` : "Loading…"}</div>
          </div>
          <div style={{ display: "flex", gap: 6 }}>
            {data && <button onClick={handlePDF} disabled={exporting} style={{ padding: "6px 12px", borderRadius: 8, border: "1.5px solid var(--border)", background: "var(--surface2)", fontSize: 12, fontWeight: 700, cursor: "pointer", color: "var(--navy)" }}>{exporting ? "⏳" : "📄 PDF"}</button>}
            <button className="btn btn-icon" onClick={onClose}>✕</button>
          </div>
        </div>
        <div style={{ overflowY: "auto", paddingBottom: 24 }}>
          {loading && <div style={{ textAlign: "center", padding: "40px 16px", color: "var(--muted)" }}>⏳ Loading…</div>}
          {error && !loading && (
            <div style={{ margin: "16px", padding: "20px", background: "rgba(245,158,11,0.08)", border: "1px solid rgba(245,158,11,0.3)", borderRadius: 12, textAlign: "center" }}>
              <div style={{ fontSize: 28, marginBottom: 8 }}>⏳</div>
              <div style={{ fontWeight: 700, fontSize: 15, marginBottom: 4 }}>Not approved yet</div>
              <div style={{ fontSize: 13, color: "var(--muted)" }}>{error}</div>
            </div>
          )}
          {data && reportData && (
            <GameReportCard
              reportData={reportData}
              badge={{ icon: "✅",
                title: `${data.game.wave_team} ${data.official.wave_score}–${data.official.opp_score} ${data.game.opponent}`,
                sub: `✅ Official · Approved ${new Date(data.official.finalized_at).toLocaleDateString("en-CA",{month:"short",day:"numeric",year:"numeric"})}`,
                bg: "linear-gradient(135deg,#166534,#15803d)" }}
              exporting={exporting}
              onPDF={handlePDF}
            />
          )}
        </div>
      </div>
    </div>
  );
}

function TrackScreen({ db, update, push, activeGame, goHomeSignal, clubName }) {
  const [pickerStat,  setPickerStat]  = useState(null);
  const [shotPicker,  setShotPicker]  = useState(null);
  const [goalContext, setGoalContext] = useState(null);
  const [assistPulse, setAssistPulse] = useState(false);
  const assistPulseTimer = useRef(null);
  const assistPulseStart = useRef(0);
  const [activeKickout, setActiveKickout] = useState(null); // "wave" = WAVE player KO'd (man down), "opp" = opp KO'd (man up)
  const [penaltyShot, setPenaltyShot] = useState(null);
  const [showAbandonConfirm, setShowAbandonConfirm] = useState(false); // { step: "direction"|"player"|"outcome", direction: "for"|"against", playerId, oppNum }
  const [viewGameId,  setViewGameId]  = useState(activeGame?.id || null);
  const [showNewGame, setShowNewGame] = useState(false);
  const [period,      setPeriod]      = useState("1Q");
  const [showRosterEditor, setShowRosterEditor] = useState(false);
  const [creating,         setCreating]         = useState(false);
  const [gridCols,         setGridCols]         = useState(() => parseInt(localStorage.getItem("wp_grid_cols") || "4"));

  function cycleGrid() {
    setGridCols(c => {
      const next = c === 4 ? 3 : c === 3 ? 2 : 4;
      localStorage.setItem("wp_grid_cols", next);
      return next;
    });
  }

  const game      = db.games.find(g => g.id === (viewGameId || db.activeGameId)) || null;
  const lastEvent = game?.events?.[game.events.length - 1];

  useEffect(() => {
    if (db.activeGameId) {
      setViewGameId(db.activeGameId);
      setPeriod("1Q"); // always start fresh at 1Q when a live game is loaded
    }
  }, [db.activeGameId]);

  // Return to game list when Home nav is tapped
  useEffect(() => { if (goHomeSignal > 0) setViewGameId(null); }, [goHomeSignal]);

  // Called by NewGameModal with the resolved setup object
  async function handleCreateGame({ waveTeamId, waveTeamName, waveRosterPlayers, opponentName, ageGroup, tournament, gameDate, _serverKey }) {
    setCreating(true);
    const gameId = uid();
    let homeId   = waveTeamId;
    let homeName = waveTeamName;
    let homePlayers = waveRosterPlayers || [];

    // Build player list for server payload (use existing local players if team already exists)
    if (homeId && !homePlayers.length) {
      homePlayers = db.players.filter(p => p.teamId === homeId);
    }

    // If _serverKey provided (joining an existing server game), skip create_game API call
    let serverKey = _serverKey || null;
    if (!serverKey) {
      // Register game on server (fire and continue — don't block on network)
      try {
        const payload = {
          action: "create_game",
          data: {
            game_date:  gameDate,
            wave_team:  homeName || db.teams.find(t => t.id === homeId)?.name || "WAVE",
            opponent:   opponentName,
            age_group:  ageGroup || "",
            tournament: tournament || "",
            season:     db.season || "",
            players:    homePlayers.map(p => ({ id: p.id || uid(), name: p.name, number: p.number, isGoalie: !!p.isGoalie })),
          },
        };
        const res  = await fetch(SERVER_URL, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(payload) });
        const json = await res.json();
        if (json.ok) serverKey = json.game_key;
      } catch { /* offline — still create locally */ }
    }
    // Save everything locally
    update(d => {
      if (!homeId) {
        homeId = uid();
        d.teams.push({ id: homeId, name: homeName || "WAVE", color: "#003087" });
        if (homePlayers.length) {
          for (const p of homePlayers) {
            if (!d.players.find(x => x.id === p.id))
              d.players.push({ id: p.id || uid(), teamId: homeId, name: p.name, number: p.number, isGoalie: !!p.isGoalie });
          }
        } else {
          // Placeholder roster
          for (let i = 1; i <= 15; i++)
            d.players.push({ id: uid(), teamId: homeId, name: `Player ${i}`, number: String(i), isGoalie: i === 1 });
        }
      }
      const awayId = uid();
      d.teams.push({ id: awayId, name: opponentName, color: "#94a3b8", isOpponent: true });
      if (ageGroup) d.ageGroup = ageGroup;
      d.games.unshift({
        id: gameId,
        serverKey: serverKey || null,
        tournament: tournament || "",
        date: new Date(gameDate + "T12:00:00").toISOString(),
        homeTeamId: homeId,
        awayTeamId: awayId,
        ageGroup:   ageGroup || "",
        homeScore: 0, awayScore: 0, events: [],
      });
      d.activeGameId = gameId;
    });

    if (serverKey) localStorage.setItem("wp_active_server_key", serverKey);
    setViewGameId(gameId);
    setPeriod("1Q");
    setShowNewGame(false);
    setCreating(false);
    setShowRosterEditor(true); // Open roster editor immediately so user can verify/edit players
    push("Game started! Edit your roster below.", "🤽");
  }

  const [showEndModal, setShowEndModal] = useState(false);

  function endGame() {
    update(d => { d.activeGameId = null; });
    push("Game ended — stats saved", "🏁");
  }

  function recordStat(stat, playerId, shotLocation, extras = {}) {
    if (!game) return;
    const player = playerId ? db.players.find(p => p.id === playerId) : null;
    const event = { id: uid(), stat, playerId: playerId || null, ts: Date.now(), period, shotLocation: shotLocation || null, ...extras };
    update(d => {
      const g = d.games.find(x => x.id === game.id);
      g.events.push(event);
      if (stat === "goal") {
        if (player?.teamId === g.homeTeamId) g.homeScore++;
      } else if (stat === "goals_against") {
        g.awayScore++;
      } else if (stat === "penalty_5m_goal_for") {
        g.homeScore++;
      } else if (stat === "penalty_5m_goal_against") {
        g.awayScore++;
      }
    });
    const statDef = [...FIELD_STATS, ...GOALIE_STATS].find(s => s.key === stat);
    const situLabel = extras.situation ? ` (${extras.situation})` : "";
    const periodLabel = period !== "OVER" ? ` [${period}]` : "";
    const who = player?.name || (extras.oppNum ? `Opp #${extras.oppNum}` : "?");
    // Friendly label for penalty events
    const labelMap = {
      penalty_5m_goal_for:    "5M Goal — FOR ✅",
      penalty_5m_miss_for:    "5M Miss — FOR",
      penalty_5m_goal_against:"5M Goal — AGAINST ❌",
      penalty_5m_miss_against:"5M Miss — AGAINST",
      penalty_5m_block:       "5M Blocked! 🧤",
    };
    push(`${labelMap[stat] || statDef?.label || stat} — ${who}${situLabel}${periodLabel}`, "🔵");
    setPickerStat(null);
    setShotPicker(null);
    setGoalContext(null);
    setPenaltyShot(null);
    // Track active kickout so next shot/goal defaults to correct situation
    if (stat === "kickout")         setActiveKickout("wave"); // WAVE kicked out → man down
    else if (stat === "kickout_earned") setActiveKickout("opp"); // Opp kicked out → man up
    else if (SHOT_STATS.has(stat) || stat === "goal" || stat === "goals_against" || stat === "shot_against") setActiveKickout(null);
  }

  function undoLast() {
    if (!game || !lastEvent) return;
    const player = db.players.find(p => p.id === lastEvent.playerId);
    update(d => {
      const g = d.games.find(x => x.id === game.id);
      if (!g.events.length) return;
      const ev = g.events.pop();
      if (ev.stat === "goal" && player?.teamId === g.homeTeamId && g.homeScore > 0) g.homeScore--;
      else if (ev.stat === "goals_against" && g.awayScore > 0) g.awayScore--;
      else if (ev.stat === "penalty_5m_goal_for" && g.homeScore > 0) g.homeScore--;
      else if (ev.stat === "penalty_5m_goal_against" && g.awayScore > 0) g.awayScore--;
    });
    push("Last stat undone", "↩️");
  }

  const homeTeam = db.teams.find(t => t.id === game?.homeTeamId);
  const awayTeam  = db.teams.find(t => t.id === game?.awayTeamId);
  const isLive    = db.activeGameId === game?.id;

  // Only WAVE (non-opponent) team gets the stat grid
  const waveTeamId = game?.homeTeamId;

  if (!game) {
    return (
      <GameListScreen
        db={db}
        update={update}
        creating={creating}
        showNewGame={showNewGame}
        setShowNewGame={setShowNewGame}
        handleCreateGame={handleCreateGame}
        setViewGameId={setViewGameId}
        push={push}
        clubName={clubName}
      />
    );
  }

  return (
    <div>
      {/* Scoreboard — always white text on navy */}
      <div className="scoreboard">
        <div className="score-teams">
          <div className="score-team">
            <div className="score-team-name" style={{ color: "var(--gold)" }}>{homeTeam?.name || "WAVE"}</div>
            <div className="score-number">{game.homeScore}</div>
          </div>
          <div className="score-sep">–</div>
          <div className="score-team">
            <div className="score-team-name" style={{ color: "rgba(255,255,255,0.65)" }}>{awayTeam?.name || "OPP"}</div>
            <div className="score-number">{game.awayScore}</div>
          </div>
        </div>
        <div className="score-date">
          {isLive && <span className="live-badge" style={{ background: "rgba(22,163,74,0.8)" }}><span className="live-dot" />ACCEPTING STATS</span>}
          {!isLive && new Date(game.date).toLocaleDateString("en-CA", { month: "short", day: "numeric", year: "numeric" })}
          {game.tournament && ` · ${game.tournament}`}
        </div>
      </div>

      {/* Stat grid — WAVE players only */}
      {isLive && (
        <>
          {/* Period Slider + Edit Roster + Abandon */}
          <div style={{ margin: "0 16px 12px", display: "flex", gap: 8, alignItems: "center" }}>
            <div style={{ flex: 1, display: "flex", gap: 0, borderRadius: 10, overflow: "hidden", border: "1.5px solid var(--border)" }}>
              {PERIODS.map((p, i) => {
                const isOver = p === "OVER";
                const isActive = period === p;
                return (
                  <button key={p} onClick={() => setPeriod(p)} style={{
                    flex: 1, padding: "9px 2px", border: "none", cursor: "pointer",
                    fontFamily: "var(--font-display)", fontSize: isOver ? 9 : 11, fontWeight: 700,
                    borderLeft: i > 0 ? "1.5px solid var(--border)" : "none",
                    background: isActive ? (isOver ? "#16a34a" : "var(--navy)") : "var(--surface)",
                    color: isActive ? "#fff" : isOver ? "#16a34a" : "var(--muted)",
                    transition: "all 0.15s",
                  }}>
                    {isOver ? "OVER" : p}
                  </button>
                );
              })}
            </div>
            <button onClick={() => setShowRosterEditor(true)} style={{
              padding: "9px 11px", borderRadius: 10, border: "1.5px solid var(--border)",
              background: "var(--surface)", cursor: "pointer", fontSize: 14, flexShrink: 0,
              color: "var(--navy)", fontWeight: 700, transition: "all 0.15s",
            }} title="Edit Roster">✏️</button>
            <button onClick={() => setShowAbandonConfirm(true)} style={{
              padding: "9px 10px", borderRadius: 10, border: "1.5px solid rgba(239,68,68,0.3)",
              background: "rgba(239,68,68,0.06)", cursor: "pointer", fontSize: 11, flexShrink: 0,
              color: "var(--danger)", fontWeight: 700, transition: "all 0.15s", whiteSpace: "nowrap",
            }} title="Return to Game List — tracking data is saved">✕ Abandon</button>
          </div>

          <div style={{ background: "var(--surface)", border: "1px solid var(--border)", borderRadius: 14, margin: "0 16px", overflow: "hidden" }}>
            {/* Grid size toggle */}
            <div style={{ display: "flex", alignItems: "center", justifyContent: "flex-end", padding: "6px 10px 4px", borderBottom: "1px solid var(--border)" }}>
              <button onClick={cycleGrid} style={{
                display: "flex", alignItems: "center", gap: 5, padding: "3px 10px", borderRadius: 8,
                border: "1.5px solid var(--border)", background: "var(--surface2)", cursor: "pointer",
                fontSize: 11, fontWeight: 700, color: "var(--muted)", fontFamily: "var(--font-body)",
              }}>
                {gridCols === 4 ? "⊞ 4×" : gridCols === 3 ? "⊟ 3×" : "▣ 2×"}
              </button>
            </div>
            <div style={{
              display: "grid",
              gridTemplateColumns: `repeat(${gridCols}, 1fr)`,
              gap: gridCols === 4 ? 1 : gridCols === 3 ? 6 : 8,
              background: gridCols === 4 ? "var(--border)" : "transparent",
              padding: gridCols === 4 ? 0 : "8px",
            }}>
              {FIELD_STATS.map(s => {
                const isAssist = s.key === "assist";
                const isPulsing = isAssist && assistPulse;
                // Calculate how far into the shimmer cycle we are so re-renders resume mid-animation
                const shimmerDelay = isPulsing
                  ? Math.min(1.2, (Date.now() - assistPulseStart.current) / 1000) - 1.2
                  : 0;
                return (
                <div key={s.key}
                  className={`stat-tile${isPulsing ? " assist-pulse" : ""}`}
                  style={{
                    borderRadius: gridCols === 4 ? 0 : 12,
                    border: gridCols === 4 ? "none" : "1.5px solid var(--border)",
                    padding: gridCols === 2 ? "16px 10px" : gridCols === 3 ? "13px 8px" : "14px 8px",
                    background: "var(--surface)",
                    ...(isPulsing ? { "--shimmer-delay": shimmerDelay + "s" } : {}),
                  }}
                  onClick={() => {
                    if (isAssist) setAssistPulse(false);
                    if (s.key === "penalty_5m") { setPenaltyShot({ step: "direction" }); }
                    else { setPickerStat({ stat: s.key, teamId: waveTeamId }); }
                  }}>
                  <div className="stat-tile-icon" style={{ fontSize: s.key === "penalty_5m" ? 14 : gridCols === 2 ? 28 : gridCols === 3 ? 24 : 22, fontFamily: s.key === "penalty_5m" ? "var(--font-display)" : "inherit", fontWeight: s.key === "penalty_5m" ? 900 : "normal", color: s.key === "penalty_5m" ? "var(--navy)" : "inherit", letterSpacing: s.key === "penalty_5m" ? 1 : 0 }}>{s.key === "penalty_5m" ? "5M" : s.icon}</div>
                  <div className="stat-tile-label" style={{ fontSize: gridCols === 2 ? 12 : gridCols === 3 ? 11 : 10, color: isPulsing ? "#2563eb" : "var(--navy)", fontWeight: 700 }}>
                    {isPulsing ? "👈 Assist?" : s.label}
                  </div>
                </div>
                );
              })}
              {/* Opponent stats — same grid level, orange-red tint */}
              {[
                { key: "goals_against", label: "Goal Against", icon: "🥅" },
                { key: "shot_against",  label: "Shot Against",  icon: "🎯" },
              ].map(s => (
                <div key={s.key} className="stat-tile" style={{
                  borderRadius: gridCols === 4 ? 0 : 12,
                  border: gridCols === 4 ? "none" : "1.5px solid var(--border)",
                  padding: gridCols === 2 ? "16px 10px" : gridCols === 3 ? "13px 8px" : "14px 8px",
                  background: "rgba(239,68,68,0.06)",
                }}
                  onClick={() => {
                    setGoalContext({ stat: s.key, playerId: null, shotLocation: null, needsOpp: true, oppFirst: true });
                  }}>
                  <div className="stat-tile-icon" style={{ fontSize: gridCols === 2 ? 28 : gridCols === 3 ? 24 : 22 }}>{s.icon}</div>
                  <div className="stat-tile-label" style={{ fontSize: gridCols === 2 ? 12 : gridCols === 3 ? 11 : 10, color: "#ef4444", fontWeight: 700 }}>{s.label}</div>
                </div>
              ))}
            </div>
          </div>

          {/* Game Complete button — above Recent so it's not buried */}
          {period === "OVER" && (
            <div style={{ margin: "12px 16px 0" }}>
              <button className="btn btn-primary" style={{ width: "100%", background: "#16a34a", borderColor: "#16a34a" }}
                onClick={() => setShowEndModal(true)}>
                🏁 Game Complete — Submit Stats
              </button>
            </div>
          )}

          {/* Recent events list — last 12, grouped by period */}
          {game.events.length > 0 && (() => {
            const PENALTY_STAT_DEFS = [
              { key: "penalty_5m_goal_for",    label: "5M Goal — FOR",     icon: "🔵" },
              { key: "penalty_5m_miss_for",    label: "5M Miss — FOR",     icon: "🔵" },
              { key: "penalty_5m_goal_against",label: "5M Goal — AGAINST", icon: "🔵" },
              { key: "penalty_5m_miss_against",label: "5M Miss — AGAINST", icon: "🔵" },
              { key: "penalty_5m_block",       label: "5M Blocked",        icon: "🧤" },
            ];
            const allStats = [...FIELD_STATS, ...GOALIE_STATS, ...PENALTY_STAT_DEFS];
            const recent = [...game.events].reverse().slice(0, 12);

            // Compute kickout counts per WAVE player (from kickout events)
            const waveKoCounts = {};
            game.events.forEach(ev => {
              if (ev.stat === "kickout") {
                waveKoCounts[ev.playerId] = (waveKoCounts[ev.playerId] || 0) + 1;
              }
            });
            // Compute kickout counts per OPP number (from kickout_earned events)
            const oppKoCounts = {};
            game.events.forEach(ev => {
              if (ev.stat === "kickout_earned" && ev.oppNum) {
                oppKoCounts[ev.oppNum] = (oppKoCounts[ev.oppNum] || 0) + 1;
              }
            });
            // Compute goal counts per player (hat trick = 3+)
            const goalCounts = {};
            game.events.forEach(ev => {
              if (ev.stat === "goal" || ev.stat === "penalty_5m_goal_for") {
                goalCounts[ev.playerId] = (goalCounts[ev.playerId] || 0) + 1;
              }
            });

            // Group by period preserving order
            const groups = [];
            recent.forEach(ev => {
              const p = ev.period || "—";
              const last = groups[groups.length - 1];
              if (last && last.period === p) last.events.push(ev);
              else groups.push({ period: p, events: [ev] });
            });
            return (
              <div style={{ margin: "10px 16px 0", borderRadius: 10, border: "1px solid var(--border)", overflow: "hidden", background: "var(--surface)" }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "8px 12px", borderBottom: "1px solid var(--border)", background: "var(--surface2)" }}>
                  <span style={{ fontSize: 11, fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.8, color: "var(--muted)" }}>Recent</span>
                  <button className="btn btn-danger btn-sm" style={{ fontSize: 11, padding: "3px 10px" }} onClick={undoLast}>↩ Undo Last</button>
                </div>
                {groups.map((g, gi) => (
                  <div key={gi}>
                    <div style={{ padding: "4px 12px", background: "rgba(0,48,135,0.06)", fontSize: 10, fontWeight: 700, letterSpacing: 0.8, textTransform: "uppercase", color: "var(--navy)", borderBottom: "1px solid var(--border)" }}>
                      {PERIOD_LABELS[g.period] || g.period}
                    </div>
                    {g.events.map((ev, ei) => {
                      const def = allStats.find(s => s.key === ev.stat);
                      const player = db.players.find(p => p.id === ev.playerId);
                      const isLast = gi === 0 && ei === 0;
                      const isOppStat = ev.stat === "goals_against" || ev.stat === "shot_against";
                      // Red card badge for WAVE player with 3+ kickouts
                      const waveRedCard = ev.stat === "kickout" && (waveKoCounts[ev.playerId] || 0) >= 3;
                      // Red card badge for opp player on kickout_earned with 3+ KOs against them
                      const oppRedCard = ev.stat === "kickout_earned" && ev.oppNum && (oppKoCounts[ev.oppNum] || 0) >= 3;
                      // Hat trick badge for WAVE player with 3+ goals on a goal event
                      const isGoalEvent = ev.stat === "goal" || ev.stat === "penalty_5m_goal_for";
                      const hatTrick = isGoalEvent && (goalCounts[ev.playerId] || 0) >= 3;
                      // Right-side label: opp stats show "#N Opponent", WAVE stats show "#N Name"
                      const rightLabel = isOppStat
                        ? (ev.oppNum ? `#${ev.oppNum} Opponent` : "Opponent")
                        : `#${player?.number || "?"} ${player?.name || "?"}`;
                      return (
                        <div key={ev.id} style={{
                          display: "flex", alignItems: "center", gap: 10, padding: "7px 12px",
                          borderBottom: (gi < groups.length - 1 || ei < g.events.length - 1) ? "1px solid var(--border)" : "none",
                          background: isLast ? "rgba(0,48,135,0.04)" : "transparent",
                        }}>
                          <span style={{ fontSize: 16, minWidth: 22, textAlign: "center" }}>{def?.icon || "📌"}</span>
                          <span style={{ flex: 1, fontSize: 13, fontWeight: isLast ? 700 : 500, color: "var(--text)" }}>
                            {def?.label || ev.stat}
                            {/* KO Earned: show opp # inline since it's context not a "player" */}
                            {ev.stat === "kickout_earned" && ev.oppNum
                              ? <span style={{ fontSize: 11, color: "var(--muted)", marginLeft: 6 }}>vs #{ev.oppNum}</span>
                              : null}
                            {oppRedCard ? <span style={{ marginLeft: 6, fontSize: 12 }} title={`Opp #${ev.oppNum} has ${oppKoCounts[ev.oppNum]} KOs`}>🟥</span> : null}
                          </span>
                          <span style={{ display: "flex", alignItems: "center", gap: 4, fontSize: 12, color: isOppStat ? "#ef4444" : "var(--muted)" }}>
                            {waveRedCard && <span style={{ fontSize: 12 }} title={`${player?.name} has ${waveKoCounts[ev.playerId]} kickouts`}>🟥</span>}
                            {hatTrick && (
                              <svg viewBox="0 0 20 16" width="18" height="14" title={`${player?.name} hat trick! ${goalCounts[ev.playerId]} goals`} style={{ display: "inline-block", verticalAlign: "middle" }}>
                                {/* brim */}
                                <ellipse cx="10" cy="13" rx="9" ry="2.5" fill="#1a1a1a"/>
                                {/* crown */}
                                <rect x="5" y="3" width="10" height="10" rx="1.5" fill="#1a1a1a"/>
                                {/* band */}
                                <rect x="5" y="9.5" width="10" height="2" fill="#003087"/>
                                {/* top flat */}
                                <rect x="5" y="3" width="10" height="1.5" rx="0.5" fill="#111"/>
                              </svg>
                            )}
                            {rightLabel}
                          </span>
                        </div>
                      );
                    })}
                  </div>
                ))}
              </div>
            );
          })()}

        </>
      )}

      {!isLive && (
        <div className="section" style={{ marginTop: 12 }}>
          <MiniBoxScore game={game} players={db.players} teams={db.teams} ageGroup={db.ageGroup} isCoach={false} />
          <div style={{ marginTop: 12, display: "flex", gap: 8 }}>
            <button className="btn btn-secondary" style={{ flex: 1 }} onClick={() => setViewGameId(null)}>← Back</button>
            {!db.activeGameId && (
              <button className="btn btn-primary" style={{ flex: 1, background: "#16a34a", borderColor: "#16a34a" }}
                onClick={() => {
                  update(d => { d.activeGameId = game.id; });
                  if (game.serverKey) localStorage.setItem("wp_active_server_key", game.serverKey);
                }}>
                ▶ Resume Tracking
              </button>
            )}
          </div>
        </div>
      )}

      {showEndModal && (
        <EndGameModal
          game={game}
          db={db}
          onEndOnly={() => { endGame(); setShowEndModal(false); }}
          onEndAndSubmit={() => { endGame(); setShowEndModal(false); }}
          onClose={() => setShowEndModal(false)}
          push={push}
        />
      )}

      {pickerStat && pickerStat.stat === "assist" && (
        <AssistPicker
          teamId={pickerStat.teamId}
          players={db.players}
          teams={db.teams}
          onConfirm={pids => {
            pids.forEach(pid => recordStat("assist", pid));
            setPickerStat(null);
          }}
          onClose={() => setPickerStat(null)}
        />
      )}

      {pickerStat && pickerStat.stat !== "assist" && !OPP_FIRST_STATS.has(pickerStat.stat) && (
        <PlayerPicker
          stat={pickerStat.stat}
          teamId={pickerStat.teamId}
          players={db.players}
          teams={db.teams}
          onSelect={pid => {
            const s = pickerStat.stat;
            if (SHOT_STATS.has(s)) {
              setShotPicker({ stat: s, playerId: pid, oppNum: null });
              setPickerStat(null);
            } else if (s === "kickout_earned") {
              setGoalContext({ stat: s, playerId: pid, shotLocation: null, needsOpp: true });
              setPickerStat(null);
            } else {
              recordStat(s, pid);
            }
          }}
          onClose={() => setPickerStat(null)}
        />
      )}

      {/* OPP-first flow: Goal Against / Shot Against — show opp number picker first */}
      {goalContext?.oppFirst && goalContext.playerId === null && (
        <OppNumberPicker
          stat={goalContext.stat}
          onSelect={n => {
            // After opp number → go to shot location
            setShotPicker({ stat: goalContext.stat, playerId: null, oppNum: n });
            setGoalContext(null);
          }}
          onClose={() => setGoalContext(null)}
        />
      )}

      {shotPicker && (
        <ShotLocationPicker
          stat={shotPicker.stat}
          player={shotPicker.playerId ? db.players.find(p => p.id === shotPicker.playerId) : null}
          oppNum={shotPicker.oppNum}
          period={period}
          clubName={clubName}
          onConfirm={loc => {
            if (NEEDS_CONTEXT.has(shotPicker.stat)) {
              setGoalContext({
                stat: shotPicker.stat,
                playerId: shotPicker.playerId,
                shotLocation: loc,
                oppNum: shotPicker.oppNum || null,
                needsOpp: false,
              });
              setShotPicker(null);
            } else {
              recordStat(shotPicker.stat, shotPicker.playerId, loc);
              setShotPicker(null);
            }
          }}
          onSkip={() => {
            if (NEEDS_CONTEXT.has(shotPicker.stat)) {
              setGoalContext({
                stat: shotPicker.stat,
                playerId: shotPicker.playerId,
                shotLocation: null,
                oppNum: shotPicker.oppNum || null,
                needsOpp: false,
              });
              setShotPicker(null);
            } else {
              recordStat(shotPicker.stat, shotPicker.playerId, null);
              setShotPicker(null);
            }
          }}
          onClose={() => setShotPicker(null)}
        />
      )}

      {goalContext && !goalContext.oppFirst && (
        <GoalContextPicker
          stat={goalContext.stat}
          player={goalContext.playerId ? db.players.find(p => p.id === goalContext.playerId) : null}
          oppNum={goalContext.oppNum}
          needsOpp={goalContext.needsOpp}
          defaultSituation={(() => {
            const s = goalContext.stat;
            const isAgainst = s === "goals_against" || s === "shot_against";
            if (!activeKickout) return "even";
            if (activeKickout === "wave") {
              // WAVE is man-down; opp is on power play
              if (s === "goal") return "even";        // possession changed before WAVE scored
              return "man_down";                       // shot/goals_against/shot_against all man-down
            }
            // activeKickout === "opp": WAVE is man-up
            if (isAgainst) return "even";             // possession changed before opp scored/shot
            return "man_up";                           // WAVE goal or shot on power play
          })()}
          onConfirm={extras => {
            recordStat(goalContext.stat, goalContext.playerId, goalContext.shotLocation, { ...extras, oppNum: goalContext.oppNum || extras.oppNum });
            if (goalContext.stat === "goal" || goalContext.stat === "penalty_5m_goal_for") {
              setAssistPulse(true);
              assistPulseStart.current = Date.now();
              clearTimeout(assistPulseTimer.current);
              assistPulseTimer.current = setTimeout(() => setAssistPulse(false), 8000);
            }
          }}
          onClose={() => setGoalContext(null)}
        />
      )}

      {/* 5M Penalty Shot flow */}
      {penaltyShot && (
        <PenaltyPicker
          penaltyShot={penaltyShot}
          setPenaltyShot={setPenaltyShot}
          db={db}
          waveTeamId={waveTeamId}
          recordStat={recordStat}
        />
      )}

      {/* Abandon confirm */}
      {showAbandonConfirm && (
        <div className="player-picker" onClick={() => setShowAbandonConfirm(false)}>
          <div className="picker-sheet" onClick={e => e.stopPropagation()} style={{ maxHeight: "50vh" }}>
            <div className="picker-header">
              <div style={{ fontSize: 24 }}>⚠️</div>
              <div className="picker-title">
                <div className="picker-stat-name">Abandon Tracking?</div>
                <div className="picker-sub">Your stats are saved — you can resume from the Game List.</div>
              </div>
              <button className="btn btn-icon" onClick={() => setShowAbandonConfirm(false)}>✕</button>
            </div>
            <div style={{ padding: "16px" }}>
              <div style={{ fontSize: 13, color: "var(--muted)", marginBottom: 16, lineHeight: 1.6 }}>
                All {game?.events?.length || 0} recorded event{game?.events?.length !== 1 ? "s" : ""} will be kept. The game stays active and you can continue tracking later.
              </div>
              <div style={{ display: "flex", gap: 10 }}>
                <button className="btn btn-secondary" style={{ flex: 1 }} onClick={() => setShowAbandonConfirm(false)}>
                  Keep Tracking
                </button>
                <button className="btn btn-danger" style={{ flex: 1 }} onClick={() => { setShowAbandonConfirm(false); setViewGameId(null); update(d => { d.activeGameId = null; const g = d.games.find(x => x.id === game.id); if (g) g.abandoned = true; }); }}>
                  Abandon
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {showNewGame && <NewGameModal db={db} onStart={handleCreateGame} onClose={() => setShowNewGame(false)} />}
      {showRosterEditor && game && (
        <RosterEditorSheet
          teamId={waveTeamId}
          db={db}
          update={update}
          onClose={() => setShowRosterEditor(false)}
        />
      )}
    </div>
  );
}

// ─── Penalty Shot Picker (5M) ─────────────────────────────────────────────────
// Step 1: FOR or AGAINST
// Step 2: Pick player (WAVE player for FOR, opp number for AGAINST)
// Step 3: GOAL or MISS  →  records event, updates score if goal
function PenaltyPicker({ penaltyShot, setPenaltyShot, db, waveTeamId, recordStat }) {
  const wavePlayers = db.players
    .filter(p => p.teamId === waveTeamId)
    .sort((a, b) => parseInt(a.number) - parseInt(b.number));

  // Opp number entry state (for AGAINST flow)
  const [oppNum, setOppNum] = useState("");

  function close() { setPenaltyShot(null); }

  // ── Step 1: Direction ──
  if (penaltyShot.step === "direction") {
    return (
      <div className="player-picker" onClick={close}>
        <div className="picker-sheet" onClick={e => e.stopPropagation()} style={{ maxHeight: "60vh" }}>
          <div className="picker-header">
            <div style={{ fontFamily: "var(--font-display)", fontSize: 28, color: "var(--navy)", fontWeight: 900 }}>5M</div>
            <div className="picker-title">
              <div className="picker-stat-name">Penalty Shot</div>
              <div className="picker-sub">Was this for WAVE or against?</div>
            </div>
            <button className="btn btn-icon" onClick={close}>✕</button>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12, padding: "20px 16px 24px" }}>
            <button onClick={() => setPenaltyShot({ step: "player", direction: "for" })} style={{
              padding: "24px 16px", borderRadius: 14, border: "2.5px solid #22c55e",
              background: "rgba(34,197,94,0.08)", cursor: "pointer",
              display: "flex", flexDirection: "column", alignItems: "center", gap: 8,
            }}>
              <div style={{ fontSize: 32 }}>⚡</div>
              <div style={{ fontFamily: "var(--font-display)", fontSize: 20, color: "#166534", fontWeight: 900 }}>FOR</div>
              <div style={{ fontSize: 11, color: "#166534", opacity: 0.8 }}>WAVE shoots</div>
            </button>
            <button onClick={() => setPenaltyShot({ step: "player", direction: "against" })} style={{
              padding: "24px 16px", borderRadius: 14, border: "2.5px solid #ef4444",
              background: "rgba(239,68,68,0.08)", cursor: "pointer",
              display: "flex", flexDirection: "column", alignItems: "center", gap: 8,
            }}>
              <div style={{ fontSize: 32 }}>🥅</div>
              <div style={{ fontFamily: "var(--font-display)", fontSize: 20, color: "#991b1b", fontWeight: 900 }}>AGAINST</div>
              <div style={{ fontSize: 11, color: "#991b1b", opacity: 0.8 }}>Opponent shoots</div>
            </button>
          </div>
        </div>
      </div>
    );
  }

  // ── Step 2: Player / Opp Number ──
  if (penaltyShot.step === "player") {
    const isFor = penaltyShot.direction === "for";
    return (
      <div className="player-picker" onClick={close}>
        <div className="picker-sheet" onClick={e => e.stopPropagation()} style={{ maxHeight: "80vh" }}>
          <div className="picker-header">
            <div style={{ fontFamily: "var(--font-display)", fontSize: 28, color: isFor ? "#166534" : "#991b1b", fontWeight: 900 }}>5M</div>
            <div className="picker-title">
              <div className="picker-stat-name" style={{ color: isFor ? "#166534" : "#991b1b" }}>{isFor ? "FOR — WAVE" : "AGAINST — Opponent"}</div>
              <div className="picker-sub">{isFor ? "Who is taking the shot?" : "Opponent shooter number"}</div>
            </div>
            <button className="btn btn-icon" onClick={() => setPenaltyShot({ step: "direction" })}>←</button>
          </div>

          {isFor ? (
            // WAVE player list
            <div style={{ overflowY: "auto", padding: "8px 0 16px" }}>
              {wavePlayers.map(p => (
                <button key={p.id} onClick={() => setPenaltyShot({ ...penaltyShot, step: "outcome", playerId: p.id })}
                  style={{ display: "flex", alignItems: "center", gap: 14, width: "100%", padding: "12px 20px", background: "none", border: "none", borderBottom: "1px solid var(--border)", cursor: "pointer", textAlign: "left" }}>
                  <div style={{ width: 38, height: 38, borderRadius: 10, background: "var(--navy)", display: "flex", alignItems: "center", justifyContent: "center", color: "#fff", fontFamily: "var(--font-display)", fontSize: 16, fontWeight: 700, flexShrink: 0 }}>
                    {p.number}
                  </div>
                  <div>
                    <div style={{ fontWeight: 700, fontSize: 15, color: "var(--text)" }}>{p.name}</div>
                    {p.isGoalie && <div style={{ fontSize: 11, color: "var(--accent)" }}>Goalkeeper</div>}
                  </div>
                </button>
              ))}
              {wavePlayers.length === 0 && (
                <div style={{ padding: "24px", textAlign: "center", color: "var(--muted)", fontSize: 13 }}>No players on roster.</div>
              )}
            </div>
          ) : (
            // Opp number entry
            <div style={{ padding: "20px 16px 24px" }}>
              <div style={{ fontSize: 13, color: "var(--muted)", marginBottom: 12 }}>Enter opponent jersey number (optional)</div>
              <div style={{ display: "flex", gap: 10, alignItems: "center", marginBottom: 20 }}>
                <input
                  type="number" inputMode="numeric" min="1" max="99"
                  value={oppNum} onChange={e => setOppNum(e.target.value)}
                  placeholder="e.g. 7"
                  style={{ width: 100, padding: "10px 14px", borderRadius: 10, border: "2px solid var(--border)", fontSize: 22, fontFamily: "var(--font-display)", fontWeight: 700, textAlign: "center", color: "var(--navy)" }}
                />
                <div style={{ fontSize: 13, color: "var(--muted)" }}>or leave blank</div>
              </div>
              <button onClick={() => setPenaltyShot({ ...penaltyShot, step: "outcome", oppNum: oppNum || null })}
                style={{ width: "100%", padding: "14px", borderRadius: 12, border: "2.5px solid #ef4444", background: "rgba(239,68,68,0.08)", cursor: "pointer", fontFamily: "var(--font-display)", fontSize: 16, fontWeight: 700, color: "#991b1b" }}>
                Next → Choose Outcome
              </button>
            </div>
          )}
        </div>
      </div>
    );
  }

  // ── Step 3: Outcome — Goal, Blocked or Miss ──
  if (penaltyShot.step === "outcome") {
    const isFor = penaltyShot.direction === "for";
    const player = penaltyShot.playerId ? db.players.find(p => p.id === penaltyShot.playerId) : null;
    const shooterLabel = player ? `#${player.number} ${player.name}` : penaltyShot.oppNum ? `Opp #${penaltyShot.oppNum}` : isFor ? "WAVE" : "Opponent";

    function recordPenalty(outcome) {
      // outcome: "goal" | "miss"  (block goes to goalie step first)
      const statKey = outcome === "goal"
        ? (isFor ? "penalty_5m_goal_for" : "penalty_5m_goal_against")
        : (isFor ? "penalty_5m_miss_for" : "penalty_5m_miss_against");
      recordStat(statKey, penaltyShot.playerId || null, null, { oppNum: penaltyShot.oppNum || null, direction: penaltyShot.direction });
    }

    return (
      <div className="player-picker" onClick={close}>
        <div className="picker-sheet" onClick={e => e.stopPropagation()} style={{ maxHeight: "72vh" }}>
          <div className="picker-header">
            <div style={{ fontFamily: "var(--font-display)", fontSize: 28, color: "var(--navy)", fontWeight: 900 }}>5M</div>
            <div className="picker-title">
              <div className="picker-stat-name">{shooterLabel}</div>
              <div className="picker-sub">{isFor ? "WAVE shooting" : "Opponent shooting"} — what happened?</div>
            </div>
            <button className="btn btn-icon" onClick={() => setPenaltyShot({ step: "player", direction: penaltyShot.direction })}>←</button>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 10, padding: "16px 16px 24px" }}>
            {/* GOAL */}
            <button onClick={() => recordPenalty("goal")} style={{
              padding: "22px 8px", borderRadius: 14,
              border: `2.5px solid ${isFor ? "#22c55e" : "#ef4444"}`,
              background: isFor ? "rgba(34,197,94,0.08)" : "rgba(239,68,68,0.08)",
              cursor: "pointer", display: "flex", flexDirection: "column", alignItems: "center", gap: 6,
            }}>
              <div style={{ fontSize: 30 }}>{isFor ? "✅" : "❌"}</div>
              <div style={{ fontFamily: "var(--font-display)", fontSize: 16, color: isFor ? "#166534" : "#991b1b", fontWeight: 900 }}>GOAL</div>
              <div style={{ fontSize: 10, color: "var(--muted)", textAlign: "center" }}>Score {isFor ? "+1 WAVE" : "+1 Opp"}</div>
            </button>
            {/* BLOCKED — only available on AGAINST shots (goalie blocks opp penalty) */}
            {!isFor ? (
              <button onClick={() => setPenaltyShot({ ...penaltyShot, step: "goalie" })} style={{
                padding: "22px 8px", borderRadius: 14,
                border: "2.5px solid #0ea5e9",
                background: "rgba(14,165,233,0.08)",
                cursor: "pointer", display: "flex", flexDirection: "column", alignItems: "center", gap: 6,
              }}>
                <div style={{ fontSize: 30 }}>🧤</div>
                <div style={{ fontFamily: "var(--font-display)", fontSize: 16, color: "#0369a1", fontWeight: 900 }}>BLOCKED</div>
                <div style={{ fontSize: 10, color: "var(--muted)", textAlign: "center" }}>Goalie save</div>
              </button>
            ) : (
              <div /> /* spacer so grid stays 3-col */
            )}
            {/* MISS */}
            <button onClick={() => recordPenalty("miss")} style={{
              padding: "22px 8px", borderRadius: 14, border: "2.5px solid var(--border)",
              background: "var(--surface2)", cursor: "pointer",
              display: "flex", flexDirection: "column", alignItems: "center", gap: 6,
            }}>
              <div style={{ fontSize: 30 }}>💨</div>
              <div style={{ fontFamily: "var(--font-display)", fontSize: 16, color: "var(--muted)", fontWeight: 900 }}>MISS</div>
              <div style={{ fontSize: 10, color: "var(--muted)", textAlign: "center" }}>No score</div>
            </button>
          </div>
        </div>
      </div>
    );
  }

  // ── Step 4: Goalie — who made the block? ──
  if (penaltyShot.step === "goalie") {
    const goalies = db.players.filter(p => p.teamId === waveTeamId && p.isGoalie);
    const allWave  = db.players.filter(p => p.teamId === waveTeamId).sort((a, b) => parseInt(a.number) - parseInt(b.number));
    // Show goalies first, then the rest (in case someone unregistered is in goal)
    const playerList = [
      ...goalies.sort((a, b) => parseInt(a.number) - parseInt(b.number)),
      ...allWave.filter(p => !p.isGoalie),
    ];

    function recordBlock(goalierId) {
      recordStat("penalty_5m_block", goalierId, null, { oppNum: penaltyShot.oppNum || null, direction: "against" });
    }

    return (
      <div className="player-picker" onClick={close}>
        <div className="picker-sheet" onClick={e => e.stopPropagation()} style={{ maxHeight: "80vh" }}>
          <div className="picker-header">
            <div style={{ fontSize: 28 }}>🧤</div>
            <div className="picker-title">
              <div className="picker-stat-name">5M Blocked!</div>
              <div className="picker-sub">Which goalkeeper made the save?</div>
            </div>
            <button className="btn btn-icon" onClick={() => setPenaltyShot({ ...penaltyShot, step: "outcome" })}>←</button>
          </div>
          <div style={{ overflowY: "auto", padding: "8px 0 16px" }}>
            {playerList.map(p => (
              <button key={p.id} onClick={() => recordBlock(p.id)}
                style={{ display: "flex", alignItems: "center", gap: 14, width: "100%", padding: "12px 20px", background: "none", border: "none", borderBottom: "1px solid var(--border)", cursor: "pointer", textAlign: "left" }}>
                <div style={{ width: 38, height: 38, borderRadius: 10, background: p.isGoalie ? "#0ea5e9" : "var(--navy)", display: "flex", alignItems: "center", justifyContent: "center", color: "#fff", fontFamily: "var(--font-display)", fontSize: 16, fontWeight: 700, flexShrink: 0 }}>
                  {p.number}
                </div>
                <div>
                  <div style={{ fontWeight: 700, fontSize: 15, color: "var(--text)" }}>{p.name}</div>
                  <div style={{ fontSize: 11, color: p.isGoalie ? "#0369a1" : "var(--muted)" }}>{p.isGoalie ? "🧤 Goalkeeper" : "Field player"}</div>
                </div>
              </button>
            ))}
            {playerList.length === 0 && (
              <div style={{ padding: "24px", textAlign: "center", color: "var(--muted)", fontSize: 13 }}>No players on roster.</div>
            )}
          </div>
        </div>
      </div>
    );
  }

  return null;
}


function EndGameModal({ game, db, onEndOnly, onEndAndSubmit, onClose, push }) {
  const [initials, setInitials] = useState(() => localStorage.getItem("wp_initials") || "");
  const [isCoach,  setIsCoach]  = useState(() => localStorage.getItem("wp_is_coach") === "1");
  const [status,   setStatus]   = useState("idle"); // idle | sending | done | error
  const [errMsg,   setErrMsg]   = useState("");

  const homeTeam = db.teams.find(t => t.id === game?.homeTeamId);
  const awayTeam  = db.teams.find(t => t.id === game?.awayTeamId);

  // Stat summary per player
  const roster = db.players.filter(p => p.teamId === game?.homeTeamId);
  const activePlayers = roster.filter(p => game.events.some(e => e.playerId === p.id))
    .sort((a, b) => parseInt(a.number) - parseInt(b.number));

  function saveIdentity(init, coach) {
    setInitials(init);
    setIsCoach(coach);
    localStorage.setItem("wp_initials", init);
    localStorage.setItem("wp_is_coach", coach ? "1" : "0");
  }

  async function submit() {
    if (!initials.trim()) { setErrMsg("Please enter your initials first."); return; }
    if (!game.serverKey)  { push("No server game linked — stats saved locally", "💾"); onEndOnly(); return; }
    setStatus("sending");
    setErrMsg("");
    try {
      const res  = await fetch(SERVER_URL, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          action: "submit_stats",
          data: {
            game_key:     game.serverKey,
            tracker_name: initials.trim().toUpperCase(),
            is_coach:     isCoach ? 1 : 0,
            wave_score:   game.homeScore,
            opp_score:    game.awayScore,
            wave_team:    db.teams.find(t => t.id === game.homeTeamId)?.name || "WAVE",
            opponent:     db.teams.find(t => t.id === game.awayTeamId)?.name || "Opponent",
            game_date:    game.date || new Date().toISOString().slice(0,10),
            tournament:   game.tournament || "",
            age_group:    game.ageGroup || "",
            events:       game.events.map(e => ({
              id: e.id, stat: e.stat, playerId: e.playerId,
              ts: e.ts, period: e.period || null,
              shotLocation: e.shotLocation || null,
              situation: e.situation || null, playType: e.playType || null,
              shotExp: e.shotExp || null, wetDry: e.wetDry || null,
              oppNum: e.oppNum || null,
            })),
          },
        }),
      });
      const json = await res.json();
      if (!json.ok) throw new Error(json.error || "Server error");
      setStatus("done");
      push("Stats submitted! ✅", "📤");
    } catch (err) {
      setStatus("error");
      setErrMsg(err.message);
    }
  }

  const totalEvents = game.events.length;
  const goals       = game.events.filter(isGoalFor).length;

  return (
    <div className="player-picker" onClick={onClose}>
      <div className="picker-sheet" style={{ maxHeight: "92vh" }} onClick={e => e.stopPropagation()}>

        {/* Header — green for completion */}
        <div className="picker-header" style={{ background: "#16a34a" }}>
          <div style={{ fontSize: 26 }}>🏁</div>
          <div className="picker-title">
            <div className="picker-stat-name">Game Complete!</div>
            <div className="picker-sub">{game.homeScore} – {game.awayScore} · {totalEvents} stats recorded</div>
          </div>
          <button className="btn btn-icon" onClick={onClose}>✕</button>
        </div>

        <div className="picker-list" style={{ padding: "16px" }}>

          {/* Final score */}
          <div style={{
            display: "flex", justifyContent: "center", alignItems: "center", gap: 20,
            padding: "12px 0 14px", borderBottom: "1px solid var(--border)", marginBottom: 14,
          }}>
            <div style={{ textAlign: "center" }}>
              <div style={{ fontFamily: "var(--font-display)", fontSize: 48, color: "var(--navy)", lineHeight: 1 }}>{game.homeScore}</div>
              <div style={{ fontSize: 11, fontWeight: 700, color: "var(--navy)", textTransform: "uppercase", marginTop: 3 }}>{homeTeam?.name || "WAVE"}</div>
            </div>
            <div style={{ fontFamily: "var(--font-display)", fontSize: 32, color: "var(--border)" }}>–</div>
            <div style={{ textAlign: "center" }}>
              <div style={{ fontFamily: "var(--font-display)", fontSize: 48, color: "var(--muted)", lineHeight: 1 }}>{game.awayScore}</div>
              <div style={{ fontSize: 11, fontWeight: 700, color: "var(--muted)", textTransform: "uppercase", marginTop: 3 }}>{awayTeam?.name || "OPP"}</div>
            </div>
          </div>

          {/* Stat summary */}
          {activePlayers.length > 0 && (
            <div style={{ marginBottom: 16 }}>
              <div style={{ fontSize: 11, fontWeight: 700, color: "var(--muted)", textTransform: "uppercase", letterSpacing: 0.8, marginBottom: 8 }}>Stats recorded</div>
              {activePlayers.map(p => {
                const counts = {};
                game.events.filter(e => e.playerId === p.id).forEach(e => { counts[e.stat] = (counts[e.stat] || 0) + 1; });
                const allStats = [...FIELD_STATS, ...GOALIE_STATS];
                return (
                  <div key={p.id} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "7px 0", borderBottom: "1px solid var(--border)", fontSize: 13 }}>
                    <span style={{ fontWeight: 600, color: "var(--text)" }}>#{p.number} {p.name}</span>
                    <span style={{ color: "var(--muted)", fontSize: 12 }}>
                      {Object.entries(counts).map(([k, v]) => { const def = allStats.find(s => s.key === k); return `${def?.icon || ""} ${v}`; }).join("  ")}
                    </span>
                  </div>
                );
              })}
            </div>
          )}
          {activePlayers.length === 0 && (
            <div style={{ textAlign: "center", padding: "8px 0 16px", color: "var(--muted)", fontSize: 13 }}>No individual stats recorded.</div>
          )}

          {/* Submit section */}
          {status === "done" ? (
            <div style={{ textAlign: "center", padding: "20px", background: "rgba(22,163,74,0.07)", border: "1px solid rgba(22,163,74,0.2)", borderRadius: 12, marginBottom: 4 }}>
              <div style={{ fontSize: 36, marginBottom: 6 }}>📤</div>
              <div style={{ fontWeight: 700, color: "#16a34a", fontSize: 15 }}>Submitted!</div>
              <div style={{ fontSize: 12, color: "var(--muted)", marginTop: 4 }}>The coaching staff has your stats.</div>
            </div>
          ) : (
            <>
              <div style={{ fontSize: 11, fontWeight: 700, color: "var(--muted)", textTransform: "uppercase", letterSpacing: 0.8, marginBottom: 10 }}>Submit to coaching staff</div>
              <div style={{ display: "flex", gap: 10, alignItems: "flex-end", marginBottom: 12 }}>
                <div style={{ flex: "0 0 88px" }}>
                  <div style={{ fontSize: 11, color: "var(--muted)", fontWeight: 600, marginBottom: 4 }}>Your initials</div>
                  <input className="form-input" maxLength={5} placeholder="SB" value={initials}
                    onChange={e => saveIdentity(e.target.value.toUpperCase(), isCoach)}
                    style={{ textTransform: "uppercase", letterSpacing: 2, fontWeight: 700, fontSize: 18, textAlign: "center" }} />
                </div>
                <div onClick={() => saveIdentity(initials, !isCoach)} style={{
                  flex: 1, display: "flex", alignItems: "center", gap: 8, cursor: "pointer",
                  padding: "10px 12px", borderRadius: 10,
                  background: isCoach ? "rgba(255,199,44,0.1)" : "var(--bg)",
                  border: `1.5px solid ${isCoach ? "var(--gold)" : "var(--border)"}`,
                }}>
                  <div style={{ width: 20, height: 20, borderRadius: 5, flexShrink: 0, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: 700,
                    background: isCoach ? "var(--gold)" : "transparent", border: `2px solid ${isCoach ? "var(--gold)" : "var(--border)"}`,
                    color: isCoach ? "#5a3e00" : "transparent" }}>{isCoach ? "✓" : ""}</div>
                  <div style={{ fontSize: 13, fontWeight: 700, color: isCoach ? "#5a3e00" : "var(--muted)" }}>🏅 I'm a coach</div>
                </div>
              </div>
              {errMsg && <div style={{ padding: "8px 12px", background: "rgba(239,68,68,0.07)", border: "1px solid rgba(239,68,68,0.2)", borderRadius: 8, fontSize: 13, color: "var(--danger)", marginBottom: 10 }}>⚠️ {errMsg}</div>}
              {!game.serverKey && <div style={{ padding: "8px 12px", background: "rgba(255,199,44,0.08)", border: "1px solid rgba(255,199,44,0.3)", borderRadius: 8, fontSize: 12, color: "#5a3e00", marginBottom: 10 }}>ℹ️ Ad-hoc game — stats saved locally only.</div>}
            </>
          )}
        </div>

        <div className="picker-cancel" style={{ display: "flex", flexDirection: "column", gap: 8 }}>
          {status !== "done" && (
            <button className="btn btn-primary" style={{ background: "#16a34a", fontSize: 15, padding: "14px" }}
              onClick={submit} disabled={status === "sending"}>
              {status === "sending" ? "⏳ Submitting…" : `📤 Submit as ${initials.trim().toUpperCase() || "?"}${isCoach ? " 🏅" : ""}`}
            </button>
          )}
          <button className="btn btn-secondary" style={{ width: "100%" }} onClick={onEndOnly}>
            {status === "done" ? "✓ Done" : "End without submitting"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── Shot Location Picker ─────────────────────────────────────────────────────
// Renders a bird's-eye SVG water polo pool. User taps to place a marker.
// Coordinates are stored in a canonical frame: WAVE always attacks the RIGHT goal.
// The pool flips automatically in 3Q/4Q/OT/SO (teams switch ends), and the user
// can override the flip at any time with the 🔄 button.
// When the display is flipped, tapped coordinates are mirrored (100 - x) before
// storing, so all saved locations are in the same canonical frame.
function ShotLocationPicker({ stat, player, oppNum, period, clubName, onConfirm, onSkip, onClose }) {
  const isAgainst    = stat === "goals_against" || stat === "shot_against";
  const isShot       = stat === "shot";
  const isShotAgainst = stat === "shot_against";
  const statLabel    = { goal: "Goal", goals_against: "Goal Against", shot: "Shot", shot_against: "Shot Against" }[stat] || stat;
  const statIcon     = (stat === "goal") ? "⭐" : isAgainst ? "🥅" : "🎯";
  const accentColor  = isAgainst ? "#ef4444" : isShot ? "#f59e0b" : "#22c55e";

  // Auto-flip in 2nd half (3Q, 4Q, OT, SO) — teams switch attacking ends
  const autoFlip = ["3Q","4Q","OT","SO"].includes(period);
  const [flipped, setFlipped] = useState(autoFlip);
  // Keep in sync if period changes while picker is open (unlikely but safe)
  const [marker, setMarker] = useState(null);
  const svgRef = useRef(null);

  const VW = 400, VH = 160;

  function handleTap(e) {
    const svg = svgRef.current;
    if (!svg) return;
    const rect = svg.getBoundingClientRect();
    const clientX = e.touches ? e.touches[0].clientX : e.clientX;
    const clientY = e.touches ? e.touches[0].clientY : e.clientY;
    let x = ((clientX - rect.left) / rect.width) * 100;
    const y = ((clientY - rect.top) / rect.height) * 100;
    // Mirror x into canonical frame when display is flipped
    if (flipped) x = 100 - x;
    setMarker({ x: Math.round(x * 10) / 10, y: Math.round(y * 10) / 10 });
  }

  // Visual x of marker: flip back for display when showing flipped view
  const markerDisplayX = marker ? (flipped ? 100 - marker.x : marker.x) : null;

  // Which goal is "active" (the one being attacked / the one to shoot at)?
  // In canonical frame, WAVE attacks RIGHT (i=1). When flipped, WAVE attacks LEFT (i=0).
  // For goals_against / shot_against, the active goal is OUR goal (the one being defended).
  const waveAttacksRight = !flipped;
  // i=0 → left goal, i=1 → right goal
  function goalFill(i) {
    if (isAgainst) {
      // Highlight the goal WAVE is defending
      const ourGoalSide = waveAttacksRight ? 0 : 1; // WAVE defends left when attacking right
      return i === ourGoalSide ? "rgba(239,68,68,0.35)" : "rgba(255,255,255,0.08)";
    }
    if (isShot || isShotAgainst) {
      const shootSide = waveAttacksRight ? 1 : 0;
      return i === shootSide ? "rgba(245,158,11,0.25)" : "rgba(255,255,255,0.08)";
    }
    // goal scored
    const shootSide = waveAttacksRight ? 1 : 0;
    return i === shootSide ? "rgba(34,197,94,0.35)" : "rgba(255,255,255,0.08)";
  }
  function goalLabel(i) {
    const waveShootSide = waveAttacksRight ? 1 : 0;
    const waveDefendSide = waveAttacksRight ? 0 : 1;
    if (isAgainst) return i === waveDefendSide ? "OUR GOAL" : "THEIR GOAL";
    return i === waveShootSide ? "SHOOT HERE" : "";
  }

  const subLabel = oppNum
    ? `Opp #${oppNum} — tap pool to mark location`
    : player
      ? `${player.name} — tap pool to mark location`
      : "Tap pool to mark location";

  // Team name labels for each end
  const leftTeamName  = waveAttacksRight ? (isAgainst ? "Opponents" : clubName) : (isAgainst ? clubName : "Opponents");
  const rightTeamName = waveAttacksRight ? (isAgainst ? clubName : "Opponents") : (isAgainst ? "Opponents" : clubName);
  const leftIsDefending  = waveAttacksRight ? !isAgainst : isAgainst;  // WAVE defends left when attacking right (non-against)
  const rightIsDefending = !leftIsDefending;

  return (
    <div className="player-picker" onClick={onClose}>
      <div className="picker-sheet" onClick={e => e.stopPropagation()}>
        <div className="picker-header">
          <div style={{ fontSize: 26 }}>{statIcon}</div>
          <div className="picker-title">
            <div className="picker-stat-name">{statLabel}</div>
            <div className="picker-sub">{subLabel}</div>
          </div>
          <button className="btn btn-icon" onClick={onClose}>✕</button>
        </div>

        <div className="picker-list" style={{ padding: "14px 16px 6px" }}>

          {/* Team name labels + flip icon */}
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
            <div style={{ textAlign: "left", minWidth: 80 }}>
              <div style={{ fontSize: 11, fontWeight: 800, color: leftIsDefending ? "#ef4444" : "var(--navy)", letterSpacing: 0.3 }}>
                {leftTeamName}
              </div>
              <div style={{ fontSize: 9, color: "var(--muted)", fontWeight: 600, letterSpacing: 0.5, textTransform: "uppercase" }}>
                {leftIsDefending ? "🛡 defending" : "⚔️ attacking"}
              </div>
            </div>
            <button
              onClick={() => { setFlipped(f => !f); setMarker(null); }}
              style={{
                padding: "6px 10px", borderRadius: 20, cursor: "pointer", fontSize: 18,
                border: `1.5px solid ${flipped ? "var(--gold)" : "var(--border)"}`,
                background: flipped ? "rgba(255,199,44,0.12)" : "var(--surface2)",
                transition: "all 0.15s", lineHeight: 1,
              }}
              title={flipped ? "Flipped (2nd half)" : "Normal (1st half)"}>
              🔄
            </button>
            <div style={{ textAlign: "right", minWidth: 80 }}>
              <div style={{ fontSize: 11, fontWeight: 800, color: rightIsDefending ? "#ef4444" : "var(--navy)", letterSpacing: 0.3 }}>
                {rightTeamName}
              </div>
              <div style={{ fontSize: 9, color: "var(--muted)", fontWeight: 600, letterSpacing: 0.5, textTransform: "uppercase" }}>
                {rightIsDefending ? "🛡 defending" : "⚔️ attacking"}
              </div>
            </div>
          </div>

          {/* SVG Pool Diagram */}
          <svg
            ref={svgRef}
            viewBox={`0 0 ${VW} ${VH}`}
            style={{ width: "100%", borderRadius: 12, cursor: "crosshair", touchAction: "none", userSelect: "none", border: `3px solid ${marker ? accentColor : "var(--border)"}`, transition: "border-color 0.2s" }}
            onClick={handleTap}
            onTouchEnd={handleTap}
          >
            {/* Water */}
            <rect x="0" y="0" width={VW} height={VH} fill="#0ea5e9" rx="8" />
            {/* Lane lines removed for clarity */}
            {/* Pool border */}
            <rect x="2" y="2" width={VW - 4} height={VH - 4} fill="none" stroke="white" strokeWidth="2" rx="7" />
            {/* 5m lines — 5/30 * 400 = 66.7px */}
            {[67, VW - 67].map((x, i) => (
              <g key={i}>
                <line x1={x} y1="0" x2={x} y2={VH} stroke="#fde047" strokeWidth="1.5" strokeDasharray="6 4" opacity="0.8" />
                <text x={x + (i === 0 ? 4 : -4)} y="12" fill="#fde047" fontSize="8" fontWeight="bold" textAnchor={i === 0 ? "start" : "end"} opacity="0.9">5m</text>
              </g>
            ))}
            {/* 2m lines — 2/30 * 400 = 26.7px */}
            {[27, VW - 27].map((x, i) => (
              <g key={i}>
                <line x1={x} y1="0" x2={x} y2={VH} stroke="#f97316" strokeWidth="1.5" strokeDasharray="4 3" opacity="0.8" />
                <text x={x + (i === 0 ? 4 : -4)} y="12" fill="#f97316" fontSize="8" fontWeight="bold" textAnchor={i === 0 ? "start" : "end"} opacity="0.9">2m</text>
              </g>
            ))}
            {/* 6m lines — 6/30 * 400 = 80px */}
            {[80, VW - 80].map((x, i) => (
              <g key={i}>
                <line x1={x} y1="0" x2={x} y2={VH} stroke="#a78bfa" strokeWidth="1.5" strokeDasharray="5 3" opacity="0.85" />
                <text x={x + (i === 0 ? 4 : -4)} y="12" fill="#a78bfa" fontSize="8" fontWeight="bold" textAnchor={i === 0 ? "start" : "end"} opacity="0.9">6m</text>
              </g>
            ))}
            {/* 2m triangle markers — 4 red triangles on end walls, 2m above/below each goal */}
            {/* goal top=60, goal bottom=100, 2m=27px vertically */}
            {/* Left wall: right-pointing triangles at y=33 and y=127 */}
            <polygon points="0,28 0,38 8,33" fill="#ef4444" opacity="0.95" />
            <polygon points="0,122 0,132 8,127" fill="#ef4444" opacity="0.95" />
            {/* Right wall: left-pointing triangles at y=33 and y=127 */}
            <polygon points={`${VW},28 ${VW},38 ${VW-8},33`} fill="#ef4444" opacity="0.95" />
            <polygon points={`${VW},122 ${VW},132 ${VW-8},127`} fill="#ef4444" opacity="0.95" />
            {/* Half line */}
            <line x1={VW / 2} y1="0" x2={VW / 2} y2={VH} stroke="white" strokeWidth="2" opacity="0.6" />
            <text x={VW / 2} y="12" fill="white" fontSize="8" textAnchor="middle" opacity="0.7">MID</text>
            {/* Goals */}
            {[0, VW].map((gx, i) => {
              const gw = 12, gh = 40, gy = (VH - gh) / 2;
              return (
                <g key={i}>
                  <rect x={i === 0 ? gx : gx - gw} y={gy} width={gw} height={gh}
                    fill="none" stroke="white" strokeWidth="3" rx="2" />
                  <rect x={i === 0 ? gx : gx - gw} y={gy} width={gw} height={gh}
                    fill={goalFill(i)} rx="2" />
                  <text x={i === 0 ? gx + gw + 3 : gx - gw - 3} y={VH / 2 + 3}
                    fill="white" fontSize="7" fontWeight="bold" textAnchor={i === 0 ? "start" : "end"} opacity="0.7">
                    {goalLabel(i)}
                  </text>
                </g>
              );
            })}
            {/* Shot marker — positioned using display coords */}
            {marker && markerDisplayX !== null && (
              <g>
                <circle cx={markerDisplayX * VW / 100} cy={marker.y * VH / 100} r="10"
                  fill={accentColor} opacity="0.35" />
                <circle cx={markerDisplayX * VW / 100} cy={marker.y * VH / 100} r="5"
                  fill={accentColor} stroke="white" strokeWidth="2" />
              </g>
            )}
          </svg>

          <div style={{ marginTop: 8, fontSize: 12, color: "var(--muted)", textAlign: "center" }}>
            {marker ? "Marker placed — tap to move it, or confirm below" : "Tap anywhere on the pool to mark the location"}
          </div>

          {/* Auto-flip notice */}
          {autoFlip && (
            <div style={{ marginTop: 6, fontSize: 11, textAlign: "center", color: "#92650a", background: "rgba(255,199,44,0.1)", border: "1px solid rgba(255,199,44,0.25)", borderRadius: 8, padding: "5px 10px" }}>
              🔄 Auto-flipped for {period} — tap 🔄 above to override
            </div>
          )}
        </div>

        <div className="picker-cancel" style={{ display: "flex", gap: 10 }}>
          <button className="btn btn-secondary" style={{ flex: 1 }} onClick={onSkip}>Skip location</button>
          <button className="btn btn-primary" style={{ flex: 1 }}
            onClick={() => onConfirm(marker)}
            disabled={!marker}>
            ✓ Confirm
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── Goal Context Picker ──────────────────────────────────────────────────────
// Handles context details for goal, goals_against, shot, shot_against
// After shot location is placed. Asks:
//   situation, play type, shot expectedness, wet/dry
// For goals_against / shot_against the oppNum is already known from OppNumberPicker
function GoalContextPicker({ stat, player, oppNum, needsOpp, defaultSituation, onConfirm, onClose }) {
  const isAgainst   = stat === "goals_against" || stat === "shot_against";
  const isGoal      = stat === "goal" || stat === "goals_against";
  const isKoEarned  = stat === "kickout_earned";

  const [koOppNum,  setKoOppNum]  = useState(null); // only for kickout_earned
  const [situation, setSituation] = useState(defaultSituation || "even");
  const [playType,  setPlayType]  = useState("");
  const [shotExp,   setShotExp]   = useState("");    // expected | unexpected | unsure
  const [wetDry,    setWetDry]    = useState("");    // wet | dry

  const situations = [
    { key: "man_down", label: "Man-Down", icon: "⬇️" },
    { key: "even",     label: "Even",     icon: "⚖️" },
    { key: "man_up",   label: "Man-Up",   icon: "⬆️" },
  ];
  const playTypes = [
    { key: "counter", label: "Counter-attack", icon: "⚡" },
    { key: "setup",   label: "Set-up Play",    icon: "♟️" },
  ];
  const shotExps = [
    { key: "expected",   label: "Expected",   icon: "🎯" },
    { key: "unexpected", label: "Unexpected", icon: "😮" },
    { key: "unsure",     label: "Unsure",     icon: "🤷" },
  ];
  const wetDryOpts = [
    { key: "wet", label: "Wet", icon: "💧" },
    { key: "dry", label: "Dry", icon: "🏐" },
  ];

  const titleIcon = stat === "goals_against" ? "🥅" : stat === "shot_against" ? "🎯" : stat === "goal" ? "⭐" : "🎯";
  const titleLabel = { goal: "Goal Scored", goals_against: "Goal Against", shot: "Shot", shot_against: "Shot Against", kickout_earned: "KO Earned" }[stat] || stat;

  // KO Earned branch — just opp number
  if (isKoEarned) {
    return (
      <div className="player-picker" onClick={onClose}>
        <div className="picker-sheet" onClick={e => e.stopPropagation()}>
          <div className="picker-header">
            <div style={{ fontSize: 26 }}>⚡</div>
            <div className="picker-title">
              <div className="picker-stat-name">KO Earned</div>
              <div className="picker-sub">{player?.name} — which opponent was kicked out?</div>
            </div>
            <button className="btn btn-icon" onClick={onClose}>✕</button>
          </div>
          <div className="picker-list" style={{ padding: "16px" }}>
            <div style={{ fontSize: 11, fontWeight: 700, color: "var(--muted)", marginBottom: 10, textTransform: "uppercase", letterSpacing: 0.8 }}>Opponent kicked out — #</div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(5, 1fr)", gap: 6 }}>
              {Array.from({ length: 15 }, (_, i) => i + 1).map(n => (
                <button key={n} onClick={() => setKoOppNum(koOppNum === n ? null : n)} style={{
                  padding: "10px 4px", borderRadius: 10, cursor: "pointer",
                  fontFamily: "var(--font-display)", fontSize: 18,
                  background: koOppNum === n ? "#ef4444" : "var(--surface2)",
                  color: koOppNum === n ? "#fff" : "var(--text)",
                  border: `2px solid ${koOppNum === n ? "#ef4444" : "var(--border)"}`,
                  transition: "all 0.12s",
                }}>{n}</button>
              ))}
            </div>
            <div style={{ fontSize: 11, color: "var(--muted)", marginTop: 6, textAlign: "center" }}>Optional — tap to select, tap again to clear</div>
          </div>
          <div className="picker-cancel" style={{ display: "flex", gap: 10 }}>
            <button className="btn btn-secondary" style={{ flex: 1 }} onClick={() => onConfirm({})}>Skip</button>
            <button className="btn btn-primary" style={{ flex: 1 }} onClick={() => onConfirm({ oppNum: koOppNum || null })}>✓ Confirm</button>
          </div>
        </div>
      </div>
    );
  }

  function SelectRow({ label, options, value, onChange }) {
    return (
      <div>
        <div style={{ fontSize: 11, fontWeight: 700, color: "var(--muted)", marginBottom: 8, textTransform: "uppercase", letterSpacing: 0.8 }}>{label}</div>
        <div style={{ display: "grid", gridTemplateColumns: `repeat(${options.length}, 1fr)`, gap: 7 }}>
          {options.map(o => (
            <button key={o.key} onClick={() => onChange(v => v === o.key ? "" : o.key)} style={{
              display: "flex", flexDirection: "column", alignItems: "center", gap: 5,
              padding: "11px 4px", borderRadius: 10,
              border: `2px solid ${value === o.key ? "var(--navy)" : "var(--border)"}`,
              background: value === o.key ? "var(--accent-dim)" : "var(--surface)",
              cursor: "pointer", transition: "all 0.15s",
              fontFamily: "var(--font-body)", fontWeight: 700, fontSize: 11,
              color: value === o.key ? "var(--navy)" : "var(--muted)",
            }}>
              <span style={{ fontSize: 18 }}>{o.icon}</span>
              {o.label}
            </button>
          ))}
        </div>
      </div>
    );
  }

  const subLabel = isAgainst
    ? (oppNum ? `Opp #${oppNum} — details` : "Goal Against — details")
    : (player?.name ? `${player.name} — details` : "Details");

  return (
    <div className="player-picker" onClick={onClose}>
      <div className="picker-sheet" onClick={e => e.stopPropagation()}>
        <div className="picker-header">
          <div style={{ fontSize: 26 }}>{titleIcon}</div>
          <div className="picker-title">
            <div className="picker-stat-name">{titleLabel}</div>
            <div className="picker-sub">{subLabel}</div>
          </div>
          <button className="btn btn-icon" onClick={onClose}>✕</button>
        </div>

        <div className="picker-list" style={{ padding: "16px", display: "flex", flexDirection: "column", gap: 16 }}>

          {/* Situation — goals and shots */}
          <SelectRow label="Was WAVE…?" options={situations} value={situation} onChange={setSituation} />

          {/* Play type — goals only */}
          {isGoal && (
            <SelectRow label="Was the goal…?" options={playTypes} value={playType} onChange={v => setPlayType(v)} />
          )}

          {/* Shot expectedness — all four stat types */}
          <SelectRow label="Was the shot…?" options={shotExps} value={shotExp} onChange={setShotExp} />

          {/* Wet or Dry */}
          <SelectRow label="Ball — Wet or Dry?" options={wetDryOpts} value={wetDry} onChange={setWetDry} />

          <div style={{ fontSize: 11, color: "var(--muted)", textAlign: "center" }}>All fields optional — tap again to deselect</div>
        </div>

        <div className="picker-cancel" style={{ display: "flex", gap: 10 }}>
          <button className="btn btn-secondary" style={{ flex: 1 }} onClick={() => onConfirm({ oppNum: oppNum || null })}>Skip</button>
          <button className="btn btn-primary" style={{ flex: 1 }}
            onClick={() => onConfirm({
              situation: situation || null,
              playType:  isGoal ? (playType || null) : undefined,
              shotExp:   shotExp || null,
              wetDry:    wetDry  || null,
              oppNum:    oppNum  || null,
            })}>
            ✓ Confirm
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── Roster Editor Sheet ─────────────────────────────────────────────────────
function RosterEditorSheet({ teamId, db, update, onClose }) {
  const team = db.teams.find(t => t.id === teamId);
  const initPlayers = db.players
    .filter(p => p.teamId === teamId)
    .sort((a, b) => parseInt(a.number) - parseInt(b.number));

  const [players, setPlayers] = useState(initPlayers);
  const [showAdd, setShowAdd] = useState(false);
  const [newNum,  setNewNum]  = useState("");
  const [newName, setNewName] = useState("");
  const [newPos,  setNewPos]  = useState("field");

  const sorted = [...players].sort((a, b) => parseInt(a.number) - parseInt(b.number));
  const dupNums = new Set(players.map(p => p.number).filter((n, i, a) => a.indexOf(n) !== i));

  function save() {
    if (dupNums.size) {
      alert("Duplicate cap number" + (dupNums.size > 1 ? "s" : "") + ": " + [...dupNums].map(n => "#" + n).join(", ") + ". Please fix before saving.");
      return;
    }
    update(d => {
      d.players = d.players.filter(p => p.teamId !== teamId);
      players.forEach(p => d.players.push({ ...p, teamId }));
    });
    onClose();
  }

  function addPlayer() {
    if (!newNum.trim()) return;
    const p = { id: "m_" + Date.now() + "_" + Math.random().toString(36).slice(2, 5),
      teamId, number: newNum.trim(), name: newName.trim(), isGoalie: newPos === "goalie" };
    setPlayers(prev => [...prev, p]);
    setNewNum(""); setNewName(""); setShowAdd(false);
  }

  function removePlayer(id) { setPlayers(prev => prev.filter(p => p.id !== id)); }
  function toggleGoalie(id) { setPlayers(prev => prev.map(p => p.id === id ? { ...p, isGoalie: !p.isGoalie } : p)); }
  function renamePlayer(id, name) { setPlayers(prev => prev.map(p => p.id === id ? { ...p, name } : p)); }
  function adjustCap(id, val) {
    const num = parseInt(val);
    if (isNaN(num) || num < 1 || num > 99) return;
    setPlayers(prev => prev.map(p => p.id === id ? { ...p, number: String(num) } : p));
  }

  return (
    <div className="player-picker" onClick={onClose}>
      <div className="picker-sheet" onClick={e => e.stopPropagation()} style={{ maxHeight: "90vh" }}>
        <div className="picker-header">
          <div style={{ fontSize: 24 }}>✏️</div>
          <div className="picker-title">
            <div className="picker-stat-name">Edit Roster</div>
            <div className="picker-sub">{team?.name} · {players.length} players · sorted by cap number</div>
          </div>
          <button className="btn btn-icon" onClick={onClose}>✕</button>
        </div>

        <div className="picker-list" style={{ padding: "10px 16px 0", overflowY: "auto" }}>
          {sorted.map((p) => (
            <div key={p.id}
              style={{
                display: "flex", alignItems: "center", gap: 10, padding: "9px 0",
                borderBottom: "1px solid var(--border)",
                background: dupNums.has(p.number) ? "rgba(239,68,68,0.07)" : "transparent",
                outline: dupNums.has(p.number) ? "1px solid rgba(239,68,68,0.3)" : "none",
              }}>
              {/* Cap number — direct input */}
              <input
                type="number" min="1" max="99"
                value={p.number}
                onChange={e => adjustCap(p.id, e.target.value)}
                style={{ width: 52, padding: "5px 4px", fontFamily: "var(--font-mono)", fontWeight: 900, fontSize: 14, textAlign: "center", border: `1.5px solid ${dupNums.has(p.number) ? "#ef4444" : "var(--border)"}`, borderRadius: 6, background: "var(--surface)", color: dupNums.has(p.number) ? "#ef4444" : "var(--navy)" }}
              />
              {/* Editable name */}
              <input
                value={p.name || ""}
                onChange={e => renamePlayer(p.id, e.target.value)}
                placeholder="Player name"
                style={{ flex: 1, fontWeight: 600, fontSize: 13, border: "1px solid var(--border)", borderRadius: 7, padding: "5px 8px", background: "var(--surface)", color: "var(--text)", fontFamily: "var(--font-body)", minWidth: 0 }}
              />
              {/* GK toggle */}
              <button onClick={() => toggleGoalie(p.id)} title={p.isGoalie ? "Switch to Field" : "Switch to Goalie"} style={{
                padding: "4px 9px", borderRadius: 20, fontSize: 13, cursor: "pointer",
                border: `1.5px solid ${p.isGoalie ? "var(--navy)" : "var(--border)"}`,
                background: p.isGoalie ? "var(--accent-dim)" : "var(--surface2)",
                color: p.isGoalie ? "var(--navy)" : "var(--muted)",
              }}>{p.isGoalie ? "🧤" : "🤽"}</button>
              <button onClick={() => removePlayer(p.id)} style={{
                padding: "4px 8px", borderRadius: 8, fontSize: 12, cursor: "pointer",
                border: "1px solid rgba(239,68,68,0.3)", background: "rgba(239,68,68,0.06)",
                color: "#ef4444", fontWeight: 700,
              }}>✕</button>
            </div>
          ))}

          {players.length === 0 && (
            <div style={{ textAlign: "center", padding: "24px 0", color: "var(--muted)", fontSize: 13 }}>
              No players yet — add one below
            </div>
          )}

          {showAdd ? (
            <div style={{ padding: "12px 0", display: "flex", flexDirection: "column", gap: 10 }}>
              <div style={{ display: "grid", gridTemplateColumns: "80px 1fr", gap: 8 }}>
                <input className="form-input" placeholder="Cap #" type="number" value={newNum}
                  onChange={e => setNewNum(e.target.value)} style={{ marginBottom: 0 }} autoFocus />
                <input className="form-input" placeholder="Player name (optional)" value={newName}
                  onChange={e => setNewName(e.target.value)} style={{ marginBottom: 0 }}
                  onKeyDown={e => e.key === "Enter" && addPlayer()} />
              </div>
              <div style={{ display: "flex", gap: 8 }}>
                {["field", "goalie"].map(pos => (
                  <button key={pos} onClick={() => setNewPos(pos)} style={{
                    flex: 1, padding: "8px", borderRadius: 8, cursor: "pointer",
                    fontFamily: "var(--font-body)", fontWeight: 700, fontSize: 13,
                    border: `2px solid ${newPos === pos ? "var(--navy)" : "var(--border)"}`,
                    background: newPos === pos ? "var(--accent-dim)" : "var(--surface2)",
                    color: newPos === pos ? "var(--navy)" : "var(--muted)",
                  }}>{pos === "goalie" ? "🧤 Goalie" : "🤽 Field"}</button>
                ))}
              </div>
              <div style={{ display: "flex", gap: 8 }}>
                <button className="btn btn-primary" style={{ flex: 1 }} onClick={addPlayer}
                  disabled={!newNum.trim()}>Add Player</button>
                <button className="btn btn-secondary" style={{ flex: 1 }} onClick={() => setShowAdd(false)}>Cancel</button>
              </div>
            </div>
          ) : (
            <button onClick={() => setShowAdd(true)} style={{
              width: "100%", marginTop: 10, padding: "10px", borderRadius: 10,
              border: "1.5px dashed var(--border)", background: "none", cursor: "pointer",
              fontSize: 13, color: "var(--muted)", fontWeight: 600,
            }}>＋ Add Player</button>
          )}
        </div>

        <div className="picker-cancel" style={{ display: "flex", gap: 10 }}>
          <button className="btn btn-secondary" style={{ flex: 1 }} onClick={onClose}>Cancel</button>
          <button className="btn btn-primary" style={{ flex: 1 }} onClick={save}>💾 Save Roster</button>
        </div>
      </div>
    </div>
  );
}

