// ─── Player Picker ────────────────────────────────────────────────────────────
function PlayerPicker({ stat, teamId, players, teams, onSelect, onClose }) {
  const statDef = [...FIELD_STATS, ...GOALIE_STATS].find(s => s.key === stat) || {};
  const team = teams.find(t => t.id === teamId);
  const isGoalieStat = GOALIE_STATS.map(s => s.key).includes(stat) && !FIELD_STATS.map(s => s.key).includes(stat);

  const teamPlayers = players
    .filter(p => p.teamId === teamId)
    .sort((a, b) => parseInt(a.number) - parseInt(b.number));

  const goalies = teamPlayers.filter(p => p.isGoalie);
  const field   = teamPlayers.filter(p => !p.isGoalie);

  return (
    <div className="player-picker" onClick={onClose}>
      <div className="picker-sheet" onClick={e => e.stopPropagation()}>
        <div className="picker-header">
          <div style={{ fontSize: 28 }}>{statDef.icon}</div>
          <div className="picker-title">
            <div className="picker-stat-name">{statDef.label}</div>
            <div className="picker-sub">{team?.name} — choose a player</div>
          </div>
          <button className="btn btn-icon" onClick={onClose}>✕</button>
        </div>

        <div className="picker-list">
          {goalies.length > 0 && (
            <>
              <div className="picker-sep">Goalies</div>
              {goalies.map(p => (
                <div key={p.id} className="picker-player" onClick={() => onSelect(p.id)}>
                  <span className="picker-number">#{p.number}</span>
                  <span className="picker-name">{p.name}</span>
                  <span className="picker-goalie-tag">GK</span>
                </div>
              ))}
            </>
          )}
          {field.length > 0 && (
            <>
              <div className="picker-sep">Field Players</div>
              {field.map(p => (
                <div key={p.id} className="picker-player" onClick={() => onSelect(p.id)}>
                  <span className="picker-number">#{p.number}</span>
                  <span className="picker-name">{p.name}</span>
                </div>
              ))}
            </>
          )}
          {teamPlayers.length === 0 && (
            <div className="empty"><div className="empty-icon">🤽</div><div className="empty-sub">No players on this team yet.</div></div>
          )}
        </div>

        <div className="picker-cancel">
          <button className="btn btn-secondary" style={{ width: "100%" }} onClick={onClose}>Cancel</button>
        </div>
      </div>
    </div>
  );
}

// ─── Assist Picker (1 or 2 players) ──────────────────────────────────────────
function AssistPicker({ teamId, players, teams, onConfirm, onClose }) {
  const [selected, setSelected] = useState([]);
  const team = teams.find(t => t.id === teamId);
  const teamPlayers = players
    .filter(p => p.teamId === teamId)
    .sort((a, b) => parseInt(a.number) - parseInt(b.number));
  const goalies = teamPlayers.filter(p => p.isGoalie);
  const field   = teamPlayers.filter(p => !p.isGoalie);

  function toggle(pid) {
    setSelected(prev =>
      prev.includes(pid)
        ? prev.filter(x => x !== pid)
        : prev.length < 2 ? [...prev, pid] : prev
    );
  }

  return (
    <div className="player-picker" onClick={onClose}>
      <div className="picker-sheet" onClick={e => e.stopPropagation()}>
        <div className="picker-header">
          <div style={{ fontSize: 28 }}>🤝</div>
          <div className="picker-title">
            <div className="picker-stat-name">Assist</div>
            <div className="picker-sub">{team?.name} — select 1 or 2 players</div>
          </div>
          <button className="btn btn-icon" onClick={onClose}>✕</button>
        </div>

        <div className="picker-list">
          {goalies.length > 0 && (
            <>
              <div className="picker-sep">Goalies</div>
              {goalies.map(p => {
                const on = selected.includes(p.id);
                const disabled = !on && selected.length >= 2;
                return (
                  <div key={p.id} className="picker-player"
                    style={{ background: on ? "rgba(59,130,246,0.1)" : "", opacity: disabled ? 0.4 : 1 }}
                    onClick={() => !disabled && toggle(p.id)}>
                    <span className="picker-number">#{p.number}</span>
                    <span className="picker-name">{p.name}</span>
                    <span className="picker-goalie-tag">GK</span>
                    {on && <span style={{ marginLeft: "auto", color: "#3b82f6", fontWeight: 900, fontSize: 18 }}>✓</span>}
                  </div>
                );
              })}
            </>
          )}
          {field.length > 0 && (
            <>
              <div className="picker-sep">Field Players</div>
              {field.map(p => {
                const on = selected.includes(p.id);
                const disabled = !on && selected.length >= 2;
                return (
                  <div key={p.id} className="picker-player"
                    style={{ background: on ? "rgba(59,130,246,0.1)" : "", opacity: disabled ? 0.4 : 1 }}
                    onClick={() => !disabled && toggle(p.id)}>
                    <span className="picker-number">#{p.number}</span>
                    <span className="picker-name">{p.name}</span>
                    {on && <span style={{ marginLeft: "auto", color: "#3b82f6", fontWeight: 900, fontSize: 18 }}>✓</span>}
                  </div>
                );
              })}
            </>
          )}
        </div>

        <div className="picker-cancel" style={{ display: "flex", gap: 8 }}>
          <button className="btn btn-secondary" style={{ flex: 1 }} onClick={onClose}>Cancel</button>
          <button className="btn btn-primary" style={{ flex: 2 }}
            disabled={selected.length === 0}
            onClick={() => { if (selected.length > 0) onConfirm(selected); }}>
            Record {selected.length === 2 ? "2 Assists" : selected.length === 1 ? "Assist" : "Assist"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── Mini Box Score ───────────────────────────────────────────────────────────
function MiniBoxScore({ game, players, teams, ageGroup, isCoach }) {
  const [tab, setTab] = useState(game.homeTeamId);
  const team = teams.find(t => t.id === tab);
  const teamPlayers = players.filter(p => p.teamId === tab);

  // Suppress individual goal attribution for 10U/12U in public (non-coach) view
  const cols = ["G","A","SH","ST","BL","TO","KO","KOE","SW"];
  const keys = ["goal","assist","shot","steal","block","turnover","kickout","kickout_earned","swimoff"];

  return (
    <div className="card">
      <div className="card-header">
        <span className="card-title">Box Score</span>
      </div>
      <div style={{ display: "flex", borderBottom: "1px solid var(--border)" }}>
        {[game.homeTeamId, game.awayTeamId].map(tid => {
          const t = teams.find(x => x.id === tid);
          return (
            <button key={tid} onClick={() => setTab(tid)} style={{ flex: 1, padding: "10px 8px", background: "none", border: "none", cursor: "pointer", fontSize: 13, fontWeight: 700, color: tab === tid ? (t?.color || "var(--accent)") : "var(--muted)", borderBottom: tab === tid ? `2px solid ${t?.color || "var(--accent)"}` : "2px solid transparent", transition: "all 0.15s" }}>
              {t?.name || "Team"}
            </button>
          );
        })}
      </div>
      <div style={{ overflowX: "auto" }}>
        <table className="stat-table" style={{ padding: "0 4px" }}>
          <thead>
            <tr>
              <th>Player</th>
              {cols.map(c => <th key={c}>{c}</th>)}
            </tr>
          </thead>
          <tbody>
            {teamPlayers.sort((a, b) => parseInt(a.number) - parseInt(b.number)).map(p => {
              const s = playerStats(game.events, p.id);
              const total = Object.values(s).reduce((a, b) => a + b, 0);
              if (total === 0 && teamPlayers.length > 6) return null;
              return (
                <tr key={p.id}>
                  <td>
                    <span style={{ color: "var(--muted)", fontFamily: "var(--font-mono)", fontSize: 11, marginRight: 6 }}>#{p.number}</span>
                    {p.name}
                    {p.isGoalie && <span style={{ marginLeft: 5, fontSize: 10, background: "rgba(0,229,255,0.12)", color: "var(--accent)", padding: "1px 5px", borderRadius: 10 }}>GK</span>}
                  </td>
                  {keys.map(k => <td key={k} className={s[k] ? "highlight" : ""}>{s[k] || "—"}</td>)}
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

