// ─── PDF Roster Parser ────────────────────────────────────────────────────────
// Loads pdf.js from CDN once, then extracts text from a roster PDF.
// Returns { tournament, teams: [{ name, players: [{number, name}] }] }

let pdfJsReady = null;
function ensurePdfJs() {
  if (pdfJsReady) return pdfJsReady;
  pdfJsReady = new Promise((resolve, reject) => {
    if (window.pdfjsLib) { resolve(window.pdfjsLib); return; }
    const s = document.createElement("script");
    s.src = "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js";
    s.onload = () => {
      window.pdfjsLib.GlobalWorkerOptions.workerSrc =
        "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js";
      resolve(window.pdfjsLib);
    };
    s.onerror = reject;
    document.head.appendChild(s);
  });
  return pdfJsReady;
}

async function extractTextFromPdf(file) {
  const pdfjsLib = await ensurePdfJs();
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  let fullText = "";
  for (let i = 1; i <= pdf.numPages; i++) {
    const page = await pdf.getPage(i);
    const content = await page.getTextContent();
    // Sort items by Y then X to reconstruct reading order
    const items = content.items.map(item => ({
      text: item.str,
      x: item.transform[4],
      y: item.transform[5],
    }));
    items.sort((a, b) => Math.abs(b.y - a.y) > 3 ? b.y - a.y : a.x - b.x);
    let lastY = null;
    for (const item of items) {
      if (lastY !== null && Math.abs(item.y - lastY) > 3) fullText += "\n";
      fullText += item.text + " ";
      lastY = item.y;
    }
    fullText += "\n";
  }
  return fullText;
}

function parseRosterText(text) {
  const lines = text.split("\n").map(l => l.trim()).filter(Boolean);

  // Extract tournament name — first meaningful line before "Toronto" or "Pan Am"
  let tournament = "";
  for (const line of lines) {
    if (/shadow|invitational|tournament|championship|open/i.test(line)) {
      tournament = line.trim();
      break;
    }
  }

  // Find team headers — patterns like "14U WAVE Piranhas" or "12U WAVE Dolphins"
  // Team header: starts with age group OR is ALL-CAPS-ish with "WAVE" or team animal name
  const teamHeaderRe = /^(\d+U\s+.{3,40}?)(?:\s+\d+U\s+(.{3,40?}))?$/;
  // More flexible: any line that looks like a team name (contains age or common team words)
  const isTeamHeader = (line) =>
    /\b(10U|12U|14U|16U|18U)\b/.test(line) &&
    !/^(Shadow|Toronto|Feb|Mar|Jan|Apr|May|Scarborough|FINAL|Names|updated)/i.test(line) &&
    line.length < 60;

  // Player row: starts with a number followed by a name
  const isPlayerRow = (line) => /^\d+\s+[A-ZÁÀÂÃÉÊÍÓÔÕÚÇ''\-]/.test(line);

  const teams = [];
  let currentTeam = null;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    if (isTeamHeader(line)) {
      // Sometimes two team names appear on one line (two-column PDF layout)
      // Split on pattern: "14U WAVE Piranhas 14U WAVE Stingrays"
      const multiTeam = line.match(/(\d+U\s+\S+(?:\s+\S+){0,4}?)\s+(\d+U\s+.+)/);
      if (multiTeam) {
        teams.push({ name: multiTeam[1].trim(), players: [] });
        teams.push({ name: multiTeam[2].trim(), players: [] });
        currentTeam = teams[teams.length - 1]; // point to last; players will be split later
      } else {
        const newTeam = { name: line, players: [] };
        teams.push(newTeam);
        currentTeam = newTeam;
      }
    } else if (isPlayerRow(line)) {
      // Parse "7 John Smith" or "11 Shonakarakehte Miller-Morgan"
      const m = line.match(/^(\d+)\s+(.+)$/);
      if (m && currentTeam) {
        currentTeam.players.push({ number: m[1], name: m[2].trim() });
      }
    }
  }

  // Handle two-column PDFs: players from two teams are interleaved on alternating lines.
  // Detect this by checking if we have teams with very few players but lots of player-looking
  // lines between two consecutive team headers.
  // Re-parse with positional awareness: look for lines where two player entries appear side by side
  // e.g. "1 Addison Jacobe 1 Alexis Gapp"
  const twoColPlayerRe = /^(\d+)\s+([A-Z][a-zA-ZÀ-ÖÙ-öù-ÿ'\-]+(?: [A-Z][a-zA-ZÀ-ÖÙ-öù-ÿ'\-]+)*)\s{2,}(\d+)\s+([A-Z][a-zA-ZÀ-ÖÙ-öù-ÿ'\-]+(?: [A-Z][a-zA-ZÀ-ÖÙ-öù-ÿ'\-]+)*)$/;

  // Second pass: fix teams that have no players by re-parsing as two-column
  const emptyTeams = teams.filter(t => t.players.length === 0);
  if (emptyTeams.length > 0 || teams.some(t => t.players.length < 3)) {
    // Redo with two-column player detection
    let col0Team = null, col1Team = null;
    const teamsNew = [];

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];

      // Two team headers on same line
      const multiTeam = line.match(/^(\d+U\s+\S+(?:\s+\S+){0,4}?)\s{3,}(\d+U\s+.+)$/);
      if (multiTeam) {
        col0Team = { name: multiTeam[1].trim(), players: [] };
        col1Team = { name: multiTeam[2].trim(), players: [] };
        teamsNew.push(col0Team, col1Team);
        continue;
      }

      if (isTeamHeader(line) && !multiTeam) {
        if (!col0Team) { col0Team = { name: line, players: [] }; teamsNew.push(col0Team); }
        else if (!col1Team) { col1Team = { name: line, players: [] }; teamsNew.push(col1Team); }
        else { col0Team = { name: line, players: [] }; col1Team = null; teamsNew.push(col0Team); }
        continue;
      }

      // Two players on one line
      const twoCol = line.match(twoColPlayerRe);
      if (twoCol) {
        if (col0Team) col0Team.players.push({ number: twoCol[1], name: twoCol[2].trim() });
        if (col1Team) col1Team.players.push({ number: twoCol[3], name: twoCol[4].trim() });
        continue;
      }

      // Single player line
      if (isPlayerRow(line)) {
        const m = line.match(/^(\d+)\s+(.+)$/);
        if (m) {
          const target = col0Team;
          if (target) target.players.push({ number: m[1], name: m[2].trim() });
        }
      }
    }

    if (teamsNew.length > 0 && teamsNew.some(t => t.players.length > 0)) {
      return { tournament, teams: teamsNew.filter(t => t.name) };
    }
  }

  return { tournament, teams: teams.filter(t => t.name) };
}

// ─── PDF Import Component ─────────────────────────────────────────────────────
function PdfImport({ db, update, push, onDone }) {
  const [status, setStatus]   = useState("idle"); // idle | parsing | preview | importing | done
  const [parsed, setParsed]   = useState(null);   // { tournament, teams }
  const [error, setError]     = useState(null);
  const [selected, setSelected] = useState({});   // teamName -> bool
  const [editNames, setEditNames] = useState({}); // teamName -> edited name

  async function handleFile(e) {
    const file = e.target.files?.[0];
    if (!file) return;
    setError(null);
    setStatus("parsing");
    try {
      const text = await extractTextFromPdf(file);
      const result = parseRosterText(text);
      if (result.teams.length === 0) throw new Error("No teams found. Make sure this is a WAVE roster PDF.");
      // Default: all teams selected
      const sel = {};
      const names = {};
      result.teams.forEach(t => { sel[t.name] = true; names[t.name] = t.name; });
      setSelected(sel);
      setEditNames(names);
      setParsed(result);
      setStatus("preview");
    } catch (err) {
      setError(err.message || "Could not parse the PDF. Please try again.");
      setStatus("idle");
    }
    e.target.value = "";
  }

  function doImport() {
    if (!parsed) return;
    setStatus("importing");
    const toImport = parsed.teams.filter(t => selected[t.name]);
    let colorIdx = db.teams.length % TEAM_COLORS.length;

    update(d => {
      if (parsed.tournament) d.tournament = parsed.tournament;
      toImport.forEach(team => {
        const existingTeam = d.teams.find(t => t.name.toLowerCase() === editNames[team.name].toLowerCase());
        const teamId = existingTeam ? existingTeam.id : uid();
        if (!existingTeam) {
          d.teams.push({ id: teamId, name: editNames[team.name], color: TEAM_COLORS[colorIdx % TEAM_COLORS.length] });
          colorIdx++;
        }
        team.players.forEach(p => {
          const alreadyExists = d.players.find(x => x.teamId === teamId && x.name.toLowerCase() === p.name.toLowerCase());
          if (!alreadyExists) {
            d.players.push({ id: uid(), teamId, name: p.name, number: p.number, isGoalie: false });
          }
        });
      });
    });

    const totalPlayers = toImport.reduce((n, t) => n + t.players.length, 0);
    push(`Imported ${toImport.length} team(s), ${totalPlayers} player(s)`, "✅");
    setStatus("done");
    setTimeout(onDone, 800);
  }

  if (status === "done") return (
    <div className="empty"><div className="empty-icon">✅</div><div className="empty-title">Import complete!</div></div>
  );

  return (
    <div>
      {/* Drop zone */}
      <div className="card" style={{ marginBottom: 16 }}>
        <div className="card-header"><span className="card-title">📄 Import Roster PDF</span></div>
        <div className="card-body">
          <p style={{ fontSize: 13, color: "var(--muted)", marginBottom: 14, lineHeight: 1.6 }}>
            Upload a WAVE roster PDF and the app will automatically extract the tournament name, teams, and player rosters. You can review and edit before importing.
          </p>
          <label style={{ display: "block", border: "2px dashed var(--border)", borderRadius: 12, padding: "24px 16px", textAlign: "center", cursor: "pointer", background: "var(--surface2)", transition: "border-color 0.15s" }}>
            <input type="file" accept="application/pdf" style={{ display: "none" }} onChange={handleFile} disabled={status === "parsing"} />
            <div style={{ fontSize: 32, marginBottom: 8 }}>📄</div>
            <div style={{ fontWeight: 700, fontSize: 14, color: "var(--navy)", marginBottom: 4 }}>
              {status === "parsing" ? "⏳ Parsing PDF..." : "Tap to choose roster PDF"}
            </div>
            <div style={{ fontSize: 12, color: "var(--muted)" }}>Supports WAVE roster PDFs with numbered player lists</div>
          </label>
          {error && (
            <div style={{ marginTop: 12, padding: "10px 14px", background: "rgba(239,68,68,0.08)", border: "1px solid rgba(239,68,68,0.3)", borderRadius: 8, fontSize: 13, color: "var(--danger)" }}>
              ⚠️ {error}
            </div>
          )}
        </div>
      </div>

      {/* Preview */}
      {status === "preview" && parsed && (
        <div>
          {parsed.tournament && (
            <div className="card" style={{ marginBottom: 12 }}>
              <div className="card-header"><span className="card-title">🏆 Tournament Detected</span></div>
              <div className="card-body">
                <div style={{ fontWeight: 700, fontSize: 15, color: "var(--navy)" }}>{parsed.tournament}</div>
                <div style={{ fontSize: 12, color: "var(--muted)", marginTop: 4 }}>Will be set as the current tournament name</div>
              </div>
            </div>
          )}

          <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: 1, textTransform: "uppercase", color: "var(--muted)", marginBottom: 8 }}>
            {parsed.teams.length} teams found — select which to import
          </div>

          {parsed.teams.map(team => (
            <div key={team.name} className="card" style={{ marginBottom: 10, borderColor: selected[team.name] ? "var(--navy)" : "var(--border)", opacity: selected[team.name] ? 1 : 0.5 }}>
              <div className="card-header" style={{ cursor: "pointer" }} onClick={() => setSelected(s => ({ ...s, [team.name]: !s[team.name] }))}>
                <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                  <div style={{ width: 20, height: 20, borderRadius: 6, border: `2px solid ${selected[team.name] ? "var(--navy)" : "var(--border)"}`, background: selected[team.name] ? "var(--navy)" : "transparent", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                    {selected[team.name] && <span style={{ color: "#fff", fontSize: 12, lineHeight: 1 }}>✓</span>}
                  </div>
                  <span className="card-title" style={{ color: selected[team.name] ? "var(--navy)" : "var(--muted)" }}>{team.name}</span>
                </div>
                <span style={{ fontSize: 12, color: "var(--muted)" }}>{team.players.length} players</span>
              </div>
              {selected[team.name] && (
                <div className="card-body" style={{ paddingTop: 8 }}>
                  <div className="form-group" style={{ marginBottom: 10 }}>
                    <label className="form-label">Team name (editable)</label>
                    <input className="form-input" value={editNames[team.name] || team.name}
                      onChange={e => setEditNames(n => ({ ...n, [team.name]: e.target.value }))} />
                  </div>
                  <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: 0.8, textTransform: "uppercase", color: "var(--muted)", marginBottom: 6 }}>Players</div>
                  {team.players.map(p => (
                    <div key={p.number} style={{ display: "flex", alignItems: "center", gap: 10, padding: "5px 0", borderBottom: "1px solid var(--border)", fontSize: 13 }}>
                      <span style={{ fontFamily: "var(--font-mono)", color: "var(--muted)", minWidth: 28 }}>#{p.number}</span>
                      <span style={{ flex: 1 }}>{p.name}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          ))}

          <div style={{ marginTop: 16, display: "flex", gap: 10 }}>
            <button className="btn btn-secondary" style={{ flex: 1 }} onClick={() => { setStatus("idle"); setParsed(null); }}>← Re-upload</button>
            <button className="btn btn-primary" style={{ flex: 1 }} onClick={doImport}
              disabled={!Object.values(selected).some(Boolean)}>
              ✅ Import {Object.values(selected).filter(Boolean).length} Team(s)
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

function SeasonSetup({ db, update, push }) {
  const [season, setSeason]       = useState(db.season);
  const [tournament, setTournament] = useState(db.tournament);
  const [ageGroup, setAgeGroup]   = useState(db.ageGroup || "");

  function save() {
    update(d => { d.season = season; d.tournament = tournament; d.ageGroup = ageGroup; });
    push("Saved!", "💾");
  }

  const ageGroups = ["10U","12U","14U","16U","18U","Other"];

  return (
    <div>
      <div className="form-group">
        <label className="form-label">Season Name</label>
        <input className="form-input" value={season} onChange={e => setSeason(e.target.value)} placeholder="e.g. 2025 Season" />
      </div>
      <div className="form-group">
        <label className="form-label">Tournament (optional)</label>
        <input className="form-input" value={tournament} onChange={e => setTournament(e.target.value)} placeholder="e.g. Ottawa Open 2025" />
      </div>
      <div className="form-group">
        <label className="form-label">Age Group / Division</label>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 8, marginTop: 4 }}>
          {ageGroups.map(ag => (
            <button key={ag} onClick={() => setAgeGroup(ag === ageGroup ? "" : ag)} style={{
              padding: "10px 6px", borderRadius: 10, cursor: "pointer",
              fontFamily: "var(--font-body)", fontWeight: 700, fontSize: 13,
              border: `2px solid ${ageGroup === ag ? "var(--navy)" : "var(--border)"}`,
              background: ageGroup === ag ? "var(--accent-dim)" : "var(--surface)",
              color: ageGroup === ag ? "var(--navy)" : "var(--muted)",
              transition: "all 0.15s",
            }}>{ag}</button>
          ))}
        </div>

      </div>
      <button className="btn btn-primary" onClick={save}>Save Settings</button>
    </div>
  );
}

function TeamsSetup({ db, update, push }) {
  const [name, setName] = useState("");
  const [color, setColor] = useState(TEAM_COLORS[0]);

  function addTeam() {
    if (!name.trim()) return;
    const teamId = uid();
    update(d => {
      d.teams.push({ id: teamId, name: name.trim(), color });
      // Auto-generate 15 placeholder players
      for (let i = 1; i <= 15; i++) {
        d.players.push({
          id: uid(),
          teamId,
          name: `Player ${i}`,
          number: String(i),
          isGoalie: i === 1, // #1 defaults to goalie
        });
      }
    });
    push(`${name.trim()} added with 15 players`, "🤽");
    setName("");
  }

  function removeTeam(id) {
    update(d => {
      d.teams = d.teams.filter(t => t.id !== id);
      d.players = d.players.filter(p => p.teamId !== id);
    });
    push("Team removed", "🗑");
  }

  return (
    <div>
      <div className="card" style={{ marginBottom: 16 }}>
        <div className="card-header"><span className="card-title">Add Team</span></div>
        <div className="card-body">
          <div className="form-group">
            <label className="form-label">Team Name</label>
            <input className="form-input" value={name} onChange={e => setName(e.target.value)} placeholder="e.g. Capital Wave" onKeyDown={e => e.key === "Enter" && addTeam()} />
          </div>
          <div className="form-group">
            <label className="form-label">Team Colour</label>
            <div className="color-picker">
              {TEAM_COLORS.map(c => (
                <div key={c} className={`color-dot ${color === c ? "selected" : ""}`} style={{ background: c }} onClick={() => setColor(c)} />
              ))}
            </div>
          </div>
          <button className="btn btn-primary" onClick={addTeam}>+ Add Team</button>
        </div>
      </div>

      {db.teams.length === 0 && (
        <div className="empty"><div className="empty-icon">🤽</div><div className="empty-title">No teams yet</div></div>
      )}
      {db.teams.map(t => (
        <div key={t.id} className="card" style={{ marginBottom: 8 }}>
          <div className="list-row">
            <div className="team-dot" style={{ background: t.color, width: 14, height: 14 }} />
            <div className="list-row-main">
              <div className="list-row-name">{t.name}</div>
              <div className="list-row-sub">{db.players.filter(p => p.teamId === t.id).length} player(s)</div>
            </div>
            <button className="btn btn-danger btn-sm" onClick={() => removeTeam(t.id)}>Remove</button>
          </div>
        </div>
      ))}
    </div>
  );
}

function PlayersSetup({ db, update, push }) {
  const [teamId, setTeamId] = useState(db.teams[0]?.id || "");
  const [name, setName]   = useState("");
  const [num, setNum]     = useState("");
  const [goalie, setGoalie] = useState(false);

  function addPlayer() {
    if (!name.trim() || !teamId) return;
    update(d => { d.players.push({ id: uid(), teamId, name: name.trim(), number: num.trim() || "0", isGoalie: goalie }); });
    push(`${name} added`, "👤");
    setName(""); setNum(""); setGoalie(false);
  }

  function removePlayer(id) {
    update(d => { d.players = d.players.filter(p => p.id !== id); });
  }

  const teamPlayers = db.players
    .filter(p => p.teamId === teamId)
    .sort((a, b) => parseInt(a.number) - parseInt(b.number));

  if (db.teams.length === 0) return (
    <div className="empty"><div className="empty-icon">⚙️</div><div className="empty-title">Add teams first</div><div className="empty-sub">Go to the Teams tab to add your teams before adding players.</div></div>
  );

  return (
    <div>
      <div className="card" style={{ marginBottom: 16 }}>
        <div className="card-header"><span className="card-title">Add Player</span></div>
        <div className="card-body">
          <div className="form-group">
            <label className="form-label">Team</label>
            <select className="form-input form-select" value={teamId} onChange={e => setTeamId(e.target.value)}>
              {db.teams.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
            </select>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "80px 1fr", gap: 10 }}>
            <div className="form-group">
              <label className="form-label">#</label>
              <input className="form-input" type="number" min="1" max="99" value={num} onChange={e => setNum(e.target.value)} placeholder="7" />
            </div>
            <div className="form-group">
              <label className="form-label">Name</label>
              <input className="form-input" value={name} onChange={e => setName(e.target.value)} placeholder="Player name" onKeyDown={e => e.key === "Enter" && addPlayer()} />
            </div>
          </div>
          <div className="form-group">
            <label className="form-label">Position</label>
            <div className="toggle-row">
              <button className={`toggle-btn ${!goalie ? "on" : ""}`} onClick={() => setGoalie(false)}>🤽 Field</button>
              <button className={`toggle-btn ${goalie ? "on" : ""}`}  onClick={() => setGoalie(true)}>🧤 Goalie</button>
            </div>
          </div>
          <button className="btn btn-primary" onClick={addPlayer}>+ Add Player</button>
        </div>
      </div>

      {/* Team filter pills */}
      <div className="report-tabs" style={{ padding: "0 0 12px" }}>
        {db.teams.map(t => (
          <button key={t.id} className={`report-tab ${teamId === t.id ? "active" : ""}`} style={{ borderColor: teamId === t.id ? t.color : undefined, color: teamId === t.id ? t.color : undefined }}
            onClick={() => setTeamId(t.id)}>{t.name}</button>
        ))}
      </div>

      {teamPlayers.length === 0 && <div className="empty"><div className="empty-icon">👤</div><div className="empty-title">No players on this team</div></div>}
      {teamPlayers.map(p => {
        const team = db.teams.find(t => t.id === p.teamId);
        return (
          <div key={p.id} className="card" style={{ marginBottom: 8 }}>
            <div className="list-row">
              <div className="number-badge" style={{ color: team?.color }}>#{p.number}</div>
              <div className="list-row-main">
                <div className="list-row-name">{p.name}</div>
                <div className="list-row-sub">{team?.name} · {p.isGoalie ? "Goalie" : "Field Player"}</div>
              </div>
              <button className="btn btn-icon" onClick={() => removePlayer(p.id)}>🗑</button>
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// SUBMIT SCREEN  — identity + submit only; game is loaded from Game List tab
// ═══════════════════════════════════════════════════════════════════════════════
function SubmitScreen({ db, push }) {
  const [initials, setInitials] = useState(() => localStorage.getItem("wp_initials") || "");
  const [isCoach,  setIsCoach]  = useState(() => localStorage.getItem("wp_is_coach") === "1");
  const [subStatus, setSubStatus] = useState("idle");
  const [subErr,    setSubErr]    = useState("");

  function saveIdentity(init, coach) {
    setInitials(init);
    setIsCoach(coach);
    localStorage.setItem("wp_initials", init);
    localStorage.setItem("wp_is_coach", coach ? "1" : "0");
  }

  const activeServerKey = localStorage.getItem("wp_active_server_key") || "";
  const localGame = db.games.find(g => g.serverKey === activeServerKey) || null;
  const homeTeam  = db.teams.find(t => t.id === localGame?.homeTeamId);
  const awayTeam  = db.teams.find(t => t.id === localGame?.awayTeamId);

  async function submitStats() {
    if (!initials.trim()) { push("Enter your initials first", "⚠️"); return; }
    if (!localGame)        { push("Load a game from Game List first", "⚠️"); return; }
    setSubStatus("sending"); setSubErr("");
    try {
      const payload = {
        game_key:     localGame.serverKey,
        tracker_name: initials.trim().toUpperCase(),
        is_coach:     isCoach ? 1 : 0,
        wave_score:   localGame.homeScore,
        opp_score:    localGame.awayScore,
        events:       localGame.events.map(e => ({
          id: e.id, stat: e.stat, playerId: e.playerId,
          ts: e.ts, period: e.period || null,
          shotLocation: e.shotLocation || null,
          situation: e.situation || null, playType: e.playType || null,
          oppNum: e.oppNum || null,
          shotExp: e.shotExp || null, wetDry: e.wetDry || null,
        })),
      };
      const res  = await fetch(SERVER_URL, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action: "submit_stats", data: payload }),
      });
      const json = await res.json();
      if (!json.ok) throw new Error(json.error || "Server error");
      setSubStatus("done");
      push("Stats submitted! 📤", "✅");
    } catch (err) {
      setSubErr(err.message);
      setSubStatus("error");
    }
  }

  return (
    <div>
      <div className="page-header">
        <div className="page-title">SUBMIT</div>
        <div className="page-sub">Send your stats to the coaching staff</div>
      </div>

      <div style={{ padding: "0 16px 100px" }}>

        {/* Identity */}
        <div className="card" style={{ marginBottom: 14 }}>
          <div className="card-header"><span className="card-title">Who are you?</span></div>
          <div className="card-body">
            <div className="form-group" style={{ marginBottom: 12 }}>
              <label className="form-label">Your Initials</label>
              <input className="form-input" maxLength={5} placeholder="e.g. SB"
                value={initials} onChange={e => saveIdentity(e.target.value.toUpperCase(), isCoach)}
                style={{ textTransform: "uppercase", letterSpacing: 2, fontWeight: 700, fontSize: 18, width: 110 }} />
            </div>
            <div onClick={() => saveIdentity(initials, !isCoach)} style={{
              display: "flex", alignItems: "center", gap: 10, cursor: "pointer",
              padding: "10px 14px", borderRadius: 10,
              background: isCoach ? "rgba(255,199,44,0.15)" : "var(--bg)",
              border: `2px solid ${isCoach ? "var(--gold)" : "var(--border)"}`,
            }}>
              <div style={{
                width: 22, height: 22, borderRadius: 6, flexShrink: 0,
                background: isCoach ? "var(--gold)" : "transparent",
                border: `2px solid ${isCoach ? "var(--gold)" : "var(--border)"}`,
                display: "flex", alignItems: "center", justifyContent: "center",
                fontSize: 14, color: isCoach ? "#5a3e00" : "transparent",
              }}>{isCoach ? "✓" : ""}</div>
              <div>
                <div style={{ fontWeight: 700, fontSize: 14, color: isCoach ? "#92650a" : "var(--text)" }}>🏅 I'm a coach</div>
                <div style={{ fontSize: 11, color: "var(--muted)" }}>Coach submissions are highlighted in the admin</div>
              </div>
            </div>
          </div>
        </div>

        {/* Active game summary */}
        {localGame ? (
          <div className="card" style={{ marginBottom: 14 }}>
            <div className="card-header">
              <span className="card-title">Game Ready to Submit</span>
              <span style={{ fontSize: 12, color: "var(--muted)" }}>{localGame.events.length} events</span>
            </div>
            <div className="card-body">
              <div style={{ display: "flex", justifyContent: "center", alignItems: "center", gap: 20, padding: "12px 0 16px" }}>
                <div style={{ textAlign: "center" }}>
                  <div style={{ fontFamily: "var(--font-display)", fontSize: 44, color: "var(--navy)", lineHeight: 1 }}>{localGame.homeScore}</div>
                  <div style={{ fontSize: 11, fontWeight: 700, color: "var(--muted)", textTransform: "uppercase", marginTop: 3 }}>{homeTeam?.name}</div>
                </div>
                <div style={{ fontFamily: "var(--font-display)", fontSize: 28, color: "var(--border)" }}>–</div>
                <div style={{ textAlign: "center" }}>
                  <div style={{ fontFamily: "var(--font-display)", fontSize: 44, color: "var(--navy)", lineHeight: 1 }}>{localGame.awayScore}</div>
                  <div style={{ fontSize: 11, fontWeight: 700, color: "var(--muted)", textTransform: "uppercase", marginTop: 3 }}>{awayTeam?.name}</div>
                </div>
              </div>

              {/* Per-player event count */}
              {db.players.filter(p => p.teamId === localGame.homeTeamId).map(p => {
                const count = localGame.events.filter(e => e.playerId === p.id).length;
                if (!count) return null;
                return (
                  <div key={p.id} style={{ display: "flex", justifyContent: "space-between", fontSize: 13, padding: "5px 0", borderBottom: "1px solid var(--border)" }}>
                    <span style={{ fontWeight: 600 }}>#{p.number} {p.name}</span>
                    <span style={{ color: "var(--navy)", fontWeight: 700 }}>{count} stat{count !== 1 ? "s" : ""}</span>
                  </div>
                );
              })}

              {subStatus === "error" && (
                <div style={{ marginTop: 12, padding: "10px 14px", background: "rgba(239,68,68,0.08)", border: "1px solid rgba(239,68,68,0.3)", borderRadius: 10, fontSize: 13, color: "var(--danger)" }}>
                  ⚠️ {subErr}
                </div>
              )}

              {subStatus === "done" ? (
                <div style={{ marginTop: 14, textAlign: "center", padding: 20, background: "rgba(22,163,74,0.07)", border: "2px solid rgba(22,163,74,0.3)", borderRadius: 12 }}>
                  <div style={{ fontSize: 36, marginBottom: 6 }}>📤</div>
                  <div style={{ fontWeight: 700, color: "#166534", fontSize: 15 }}>Submitted!</div>
                  <div style={{ fontSize: 12, color: "var(--muted)", marginTop: 4 }}>The coaching staff will review your stats.</div>
                  <button className="btn btn-secondary" style={{ marginTop: 12 }} onClick={() => setSubStatus("idle")}>Submit again</button>
                </div>
              ) : (
                <button className="btn btn-primary" style={{ marginTop: 14, width: "100%" }}
                  onClick={submitStats} disabled={subStatus === "sending" || !initials.trim()}>
                  {subStatus === "sending" ? "⏳ Sending…" : `📤 Submit as ${initials.trim().toUpperCase() || "?"}${isCoach ? " 🏅" : ""}`}
                </button>
              )}
            </div>
          </div>
        ) : (
          <div className="empty" style={{ paddingTop: 24 }}>
            <div className="empty-icon">📋</div>
            <div className="empty-title">No active game</div>
            <div className="empty-sub">Go to Game List, load a game, then come back here to submit your stats.</div>
          </div>
        )}
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// ADMIN RECONCILE COMPONENT
// Fetches all submissions for a game, lets admin accept one or calculate a merge,
// then close the game.
// ═══════════════════════════════════════════════════════════════════════════════
function AdminReconcile({ serverKey, push }) {
  const [data,       setData]       = useState(null);   // { submissions, game }
  const [loading,    setLoading]    = useState(false);
  const [err,        setErr]        = useState("");
  const [method,     setMethod]     = useState("accept"); // "accept" | "avg" | "median" | "mode"
  const [chosenIdx,  setChosenIdx]  = useState(0);       // which submission to accept
  const [preview,    setPreview]    = useState(null);    // computed result
  const [saving,     setSaving]     = useState(false);
  const [closed,     setClosed]     = useState(false);

  async function fetchSubmissions() {
    setLoading(true); setErr(""); setData(null); setPreview(null);
    try {
      const res  = await fetch(`${SERVER_URL}?action=get_submissions&game_key=${serverKey}&_=${Date.now()}`);
      const json = await res.json();
      if (!json.ok) throw new Error(json.error || "Server error");
      setData(json);
      setLoading(false);
    } catch (e) { setErr(e.message); setLoading(false); }
  }

  // ── Reconciliation math ────────────────────────────────────────────────────
  function computeResult() {
    if (!data) return null;
    const subs = data.submissions;
    if (!subs.length) return null;

    if (method === "accept") {
      return subs[chosenIdx] ? { ...subs[chosenIdx], _method: `Accepted from ${subs[chosenIdx].tracker_name}` } : null;
    }

    // Gather all player IDs across all submissions
    const allPlayerIds = [...new Set(subs.flatMap(s => Object.keys(s.playerStats || {})))];
    const allStatKeys  = ["goal","assist","shot","steal","block","turnover","kickout","kickout_earned","swimoff","save","goals_against"];

    const playerStats = {};
    for (const pid of allPlayerIds) {
      playerStats[pid] = {};
      for (const key of allStatKeys) {
        const vals = subs.map(s => (s.playerStats?.[pid]?.[key] || 0));
        if (method === "avg") {
          playerStats[pid][key] = Math.round((vals.reduce((a,b)=>a+b,0) / vals.length) * 10) / 10;
        } else if (method === "median") {
          const sorted = [...vals].sort((a,b)=>a-b);
          const mid = Math.floor(sorted.length / 2);
          playerStats[pid][key] = sorted.length % 2 === 0
            ? Math.round(((sorted[mid-1] + sorted[mid]) / 2) * 10) / 10
            : sorted[mid];
        } else if (method === "mode") {
          const freq = {};
          vals.forEach(v => { freq[v] = (freq[v]||0)+1; });
          const maxFreq = Math.max(...Object.values(freq));
          const modes   = Object.keys(freq).filter(v => freq[v] === maxFreq).map(Number);
          playerStats[pid][key] = Math.round((modes.reduce((a,b)=>a+b,0)/modes.length) * 10) / 10;
        }
      }
    }

    // Score: average/median/mode of submitted scores
    const homeScores = subs.map(s => s.wave_score || 0);
    const awayScores = subs.map(s => s.opp_score  || 0);
    function applyMethod(arr) {
      if (method === "avg")    return Math.round(arr.reduce((a,b)=>a+b,0) / arr.length);
      if (method === "median") { const s=[...arr].sort((a,b)=>a-b); const m=Math.floor(s.length/2); return s.length%2===0?Math.round((s[m-1]+s[m])/2):s[m]; }
      if (method === "mode")   { const f={}; arr.forEach(v=>{f[v]=(f[v]||0)+1;}); const mx=Math.max(...Object.values(f)); return Number(Object.keys(f).find(v=>f[v]===mx)); }
    }

    const methodLabel = { avg: "Average", median: "Median", mode: "Most Common (Mode)" }[method];
    return {
      wave_score: applyMethod(homeScores),
      opp_score:  applyMethod(awayScores),
      playerStats,
      _method: `Calculated using ${methodLabel} across ${subs.length} submission(s)`,
    };
  }

  async function applyAndClose() {
    const result = computeResult();
    if (!result) return;
    setSaving(true); setErr("");
    try {
      const res  = await fetch(SERVER_URL, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action: "close_game", data: { game_key: serverKey, result } }),
      });
      const json = await res.json();
      if (!json.ok) throw new Error(json.error || "Server error");
      setClosed(true);
      push("Game closed ✅", "🏁");
    } catch (e) { setErr(e.message); }
    setSaving(false);
  }

  if (closed) return (
    <div className="card" style={{ marginBottom: 14 }}>
      <div className="card-header"><span className="card-title">✅ Game Closed</span></div>
      <div className="card-body" style={{ color: "var(--muted)", fontSize: 13 }}>Stats have been accepted and the game is closed.</div>
    </div>
  );

  const subs = data?.submissions || [];
  const result = data ? computeResult() : null;

  return (
    <div className="card" style={{ marginBottom: 14, border: "2px solid var(--gold)" }}>
      <div className="card-header" style={{ background: "rgba(255,199,44,0.08)" }}>
        <span className="card-title">🏅 Admin — Review &amp; Close Game</span>
        <button className="btn btn-primary" style={{ padding: "6px 12px", fontSize: 12 }}
          onClick={fetchSubmissions} disabled={loading}>
          {loading ? "⏳" : "🔄 Load"}
        </button>
      </div>
      <div className="card-body">
        {err && <div style={{ color: "var(--danger)", fontSize: 13, marginBottom: 10 }}>⚠️ {err}</div>}

        {!data && !loading && (
          <div style={{ color: "var(--muted)", fontSize: 13 }}>
            Tap Load to fetch all tracker submissions for this game.
          </div>
        )}

        {data && subs.length === 0 && (
          <div style={{ color: "var(--muted)", fontSize: 13 }}>No submissions yet for this game.</div>
        )}

        {data && subs.length > 0 && (
          <>
            {/* Submissions summary */}
            <div style={{ marginBottom: 16 }}>
              <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: 1, textTransform: "uppercase", color: "var(--muted)", marginBottom: 8 }}>
                {subs.length} Submission{subs.length !== 1 ? "s" : ""} Received
              </div>
              {subs.map((s, i) => (
                <div key={i} style={{
                  padding: "10px 12px", borderRadius: 10, marginBottom: 6,
                  border: `2px solid ${method === "accept" && chosenIdx === i ? "var(--navy)" : "var(--border)"}`,
                  background: method === "accept" && chosenIdx === i ? "rgba(0,48,135,0.05)" : "var(--bg)",
                  cursor: method === "accept" ? "pointer" : "default",
                  transition: "all 0.15s",
                }} onClick={() => { if (method === "accept") setChosenIdx(i); }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                    <div>
                      <span style={{ fontWeight: 700, fontSize: 14 }}>
                        {s.is_coach ? "🏅 " : ""}{s.tracker_name}
                      </span>
                      <span style={{ fontSize: 12, color: "var(--muted)", marginLeft: 8 }}>
                        {s.wave_score}–{s.opp_score} · {s.event_count} events
                      </span>
                    </div>
                    {method === "accept" && (
                      <div style={{ width: 20, height: 20, borderRadius: "50%", border: `2px solid ${chosenIdx === i ? "var(--navy)" : "var(--border)"}`, background: chosenIdx === i ? "var(--navy)" : "transparent", display: "flex", alignItems: "center", justifyContent: "center" }}>
                        {chosenIdx === i && <span style={{ color: "#fff", fontSize: 12, lineHeight: 1 }}>✓</span>}
                      </div>
                    )}
                  </div>
                  {/* Per-player stat breakdown */}
                  {s.playerStats && Object.entries(s.playerStats).length > 0 && (
                    <div style={{ marginTop: 8, fontSize: 11, color: "var(--muted)", lineHeight: 1.8 }}>
                      {Object.entries(s.playerStats).map(([pid, stats]) => {
                        const statStr = Object.entries(stats).filter(([,v])=>v>0).map(([k,v])=>`${k.replace("goals_against","GA").replace("kickout_earned","KOE").replace("kickout","KO").replace("turnover","TO").replace("assist","A").replace("steal","ST").replace("block","BL").replace("goal","G").replace("shot","SH").replace("save","SV").replace("swimoff","SW")} ${v}`).join(" · ");
                        return statStr ? <div key={pid}>#{data.players?.[pid]?.number || "?"} {data.players?.[pid]?.name || pid}: {statStr}</div> : null;
                      })}
                    </div>
                  )}
                </div>
              ))}
            </div>

            {/* Method picker */}
            <div style={{ marginBottom: 16 }}>
              <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: 1, textTransform: "uppercase", color: "var(--muted)", marginBottom: 8 }}>
                How to determine the final stats
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
                {[
                  { key: "accept", label: "Accept One",     icon: "✓",  desc: "Use one tracker's stats as-is" },
                  { key: "avg",    label: "Average",         icon: "➗", desc: "Mean of all submissions" },
                  { key: "median", label: "Median",          icon: "⚖️", desc: "Middle value — ignores outliers" },
                  { key: "mode",   label: "Most Common",     icon: "🗳️", desc: "Most frequently reported value" },
                ].map(m => (
                  <button key={m.key} onClick={() => setMethod(m.key)} style={{
                    padding: "12px 10px", borderRadius: 10, cursor: "pointer", textAlign: "left",
                    border: `2px solid ${method === m.key ? "var(--navy)" : "var(--border)"}`,
                    background: method === m.key ? "rgba(0,48,135,0.06)" : "var(--bg)",
                    transition: "all 0.15s", fontFamily: "var(--font-body)",
                  }}>
                    <div style={{ fontWeight: 700, fontSize: 13, color: method === m.key ? "var(--navy)" : "var(--text)", marginBottom: 3 }}>
                      {m.icon} {m.label}
                    </div>
                    <div style={{ fontSize: 11, color: "var(--muted)", lineHeight: 1.4 }}>{m.desc}</div>
                  </button>
                ))}
              </div>
            </div>

            {/* Computed result preview */}
            {result && (
              <div style={{ padding: "12px 14px", borderRadius: 10, background: "rgba(22,163,74,0.06)", border: "1.5px solid rgba(22,163,74,0.3)", marginBottom: 14 }}>
                <div style={{ fontSize: 11, fontWeight: 700, color: "#16a34a", marginBottom: 6, textTransform: "uppercase", letterSpacing: 0.8 }}>
                  Result Preview — {result._method}
                </div>
                <div style={{ fontFamily: "var(--font-display)", fontSize: 28, color: "var(--navy)", marginBottom: 6 }}>
                  {result.wave_score} – {result.opp_score}
                </div>
                {result.playerStats && Object.entries(result.playerStats).map(([pid, stats]) => {
                  const relevant = Object.entries(stats).filter(([,v])=>v>0);
                  if (!relevant.length) return null;
                  return (
                    <div key={pid} style={{ fontSize: 12, color: "var(--muted)", lineHeight: 1.9 }}>
                      #{data.players?.[pid]?.number || "?"} {data.players?.[pid]?.name || pid}: {relevant.map(([k,v])=>`${k} ×${v}`).join(", ")}
                    </div>
                  );
                })}
              </div>
            )}

            {err && <div style={{ padding: "8px 12px", background: "rgba(239,68,68,0.07)", border: "1px solid rgba(239,68,68,0.2)", borderRadius: 8, fontSize: 13, color: "var(--danger)", marginBottom: 10 }}>⚠️ {err}</div>}

            <button className="btn btn-primary" style={{ width: "100%", background: "#dc2626", borderColor: "#dc2626", fontSize: 15, padding: "14px" }}
              onClick={applyAndClose} disabled={saving || !result}>
              {saving ? "⏳ Closing…" : "🔒 Accept Stats &amp; Close Game"}
            </button>
          </>
        )}
      </div>
    </div>
  );
}
// ═══════════════════════════════════════════════════════════════════════════════
// REPORT VIEWER — renders structured report sections from admin-published data
// ═══════════════════════════════════════════════════════════════════════════════
function ReportViewer({ data }) {
  if (!data || !data.sections) return (
    <div style={{ color: "var(--muted)", fontSize: 13, padding: "20px 0", textAlign: "center" }}>
      No report data available.
    </div>
  );

  const ZONE_LABELS = {1:"Top-L",2:"Left",3:"Ctr-L",4:"Center",5:"Ctr-R",6:"Right",7:"Top-R"};
  const STAT_HDRS   = {goal:"G",assist:"A",shot:"SH",steal:"ST",block:"BL",turnover:"TO",kickout:"KO",kickout_earned:"KOE",save:"SV"};
  const STAT_LABELS = {goal:"Goals",assist:"Assists",shot:"Shots",steal:"Steals",block:"Blocks",kickout_earned:"KO Earned",save:"Saves"};

  const TH = ({ children, left }) => (
    <th style={{ background: "var(--navy)", color: "#fff", padding: "6px 8px", fontSize: 11, fontWeight: 700, textAlign: left ? "left" : "center", whiteSpace: "nowrap" }}>{children}</th>
  );
  const TD = ({ children, mono, bold, color }) => (
    <td style={{ padding: "5px 8px", borderBottom: "1px solid var(--border)", textAlign: "center", fontFamily: mono ? "monospace" : "inherit", fontWeight: bold ? 700 : 400, color: color || "var(--text)" }}>{children}</td>
  );
  const TDL = ({ children, mono, bold }) => (
    <td style={{ padding: "5px 8px", borderBottom: "1px solid var(--border)", textAlign: "left", fontFamily: mono ? "monospace" : "inherit", fontWeight: bold ? 700 : 400 }}>{children}</td>
  );

  return (
    <div>
      {data.subtitle && <div style={{ fontSize: 13, color: "var(--muted)", marginBottom: 10 }}>{data.subtitle}</div>}
      {data.gameCount && <div style={{ fontSize: 12, color: "var(--muted)", marginBottom: 18 }}>{data.gameCount} game{data.gameCount !== 1 ? "s" : ""} · {new Date(data.generatedAt || Date.now()).toLocaleDateString("en-CA")}</div>}

      {data.sections.map((sec, si) => (
        <div key={si} style={{ marginBottom: 24 }}>
          <div style={{ fontSize: 16, fontWeight: 800, color: "var(--navy)", marginBottom: 10, paddingBottom: 6, borderBottom: "2px solid var(--border)" }}>{sec.title}</div>

          {sec.type === "results_table" && (
            <>
              <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 8, color: "var(--navy)" }}>{sec.record} &nbsp;·&nbsp; GF: {sec.waveTotal} &nbsp; GA: {sec.oppTotal}</div>
              <div style={{ overflowX: "auto" }}>
                <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
                  <thead><tr>{["Date","Opponent","Us","Opp","Result"].map(h => <TH key={h} left={h==="Opponent"}>{h}</TH>)}</tr></thead>
                  <tbody>{sec.rows.map((r, i) => (
                    <tr key={i} style={{ background: i%2===0 ? "var(--surface)" : "var(--bg)" }}>
                      <TDL>{new Date(r.date+"T12:00:00").toLocaleDateString("en-CA",{month:"short",day:"numeric"})}</TDL>
                      <TDL bold>{r.opponent}</TDL>
                      <TD mono bold>{r.waveScore}</TD>
                      <TD mono bold>{r.oppScore}</TD>
                      <TD bold color={r.result==="W"?"#16a34a":r.result==="L"?"#ef4444":"#6b7280"}>{r.result}</TD>
                    </tr>
                  ))}</tbody>
                </table>
              </div>
            </>
          )}

          {sec.type === "player_stats" && (() => {
            const allP = [...(sec.fieldPlayers||[]), ...(sec.goaliePlayers||[])].sort((a,b)=>parseInt(a.number)-parseInt(b.number));
            const cols = (sec.statKeys||[]).filter(k => allP.some(p=>p.stats[k]>0));
            return allP.length ? (
              <div style={{ overflowX: "auto" }}>
                <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 11 }}>
                  <thead><tr>
                    <TH left>#</TH><TH left>Name</TH>
                    {cols.map(k => <TH key={k}>{STAT_HDRS[k]||k}</TH>)}
                  </tr></thead>
                  <tbody>{allP.map((p, i) => (
                    <tr key={i} style={{ background: i%2===0 ? "var(--surface)" : "var(--bg)" }}>
                      <TDL mono>{p.number}</TDL>
                      <TDL bold>{p.name}{p.isGoalie ? " 🧤" : ""}</TDL>
                      {cols.map(k => <TD key={k} mono bold={p.stats[k]>0} color={p.stats[k]>0?"var(--navy)":"#ccc"}>{p.stats[k]||"—"}</TD>)}
                    </tr>
                  ))}</tbody>
                </table>
              </div>
            ) : null;
          })()}

          {sec.type === "leaderboards" && (
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(150px,1fr))", gap: 10 }}>
              {Object.entries(sec.leaders).map(([stat, players]) => (
                <div key={stat} style={{ background: "var(--surface)", borderRadius: 8, padding: 10 }}>
                  <div style={{ fontSize: 10, fontWeight: 700, letterSpacing: 1, color: "var(--muted)", textTransform: "uppercase", marginBottom: 6 }}>{STAT_LABELS[stat]||stat}</div>
                  {players.map((p, i) => (
                    <div key={i} style={{ display: "flex", justifyContent: "space-between", fontSize: 12, marginBottom: 3 }}>
                      <span>{["🥇","🥈","🥉"][i]||"  "} {p.name}</span>
                      <span style={{ fontWeight: 700, color: "var(--navy)", fontFamily: "monospace" }}>{p.stats[stat]}</span>
                    </div>
                  ))}
                </div>
              ))}
            </div>
          )}

          {sec.type === "goalies" && (
            <div style={{ overflowX: "auto" }}>
              <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
                <thead><tr>{["#","Goalie","SV","GA","SA","SV%"].map((h,i) => <TH key={h} left={i<2}>{h}</TH>)}</tr></thead>
                <tbody>{sec.goalieData.map((g, i) => (
                  <tr key={i} style={{ background: i%2===0 ? "var(--surface)" : "var(--bg)" }}>
                    <TDL mono>{g.number}</TDL><TDL bold>{g.name}</TDL>
                    <TD mono>{g.saves}</TD><TD mono>{g.goalsAgainst}</TD><TD mono>{g.shotsAgainst}</TD>
                    <TD mono bold color="var(--navy)">{g.svPct !== null ? g.svPct+"%" : "—"}</TD>
                  </tr>
                ))}</tbody>
              </table>
            </div>
          )}

          {sec.type === "situations" && (
            <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 8 }}>
              {sec.situations.map(s => {
                const color = s.key==="man_up"?"#16a34a":s.key==="man_down"?"#ef4444":"#0ea5e9";
                return (
                  <div key={s.key} style={{ background: "var(--surface)", borderRadius: 8, padding: 10, textAlign: "center", borderTop: `3px solid ${color}` }}>
                    <div style={{ fontSize: 9, fontWeight: 700, letterSpacing: 1, color: "var(--muted)", textTransform: "uppercase", marginBottom: 4 }}>{s.label}</div>
                    <div style={{ fontSize: 24, fontWeight: 900, color }}>{s.pct !== null ? s.pct+"%" : "—"}</div>
                    <div style={{ fontSize: 10, color: "var(--muted)", marginTop: 2 }}>{s.goals}G / {s.shots}SH</div>
                  </div>
                );
              })}
            </div>
          )}

          {sec.type === "penalties" && (() => {
            const forPct     = sec.totalFor > 0     ? Math.round(sec.forGoals/sec.totalFor*100)         : null;
            const againstPct = sec.totalAgainst > 0 ? Math.round(sec.againstGoals/sec.totalAgainst*100) : null;
            return (
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
                {[{label:"For",pct:forPct,goals:sec.forGoals,miss:sec.forMiss,total:sec.totalFor,color:"#16a34a",bg:"#f0fff4"},
                  {label:"Against",pct:againstPct,goals:sec.againstGoals,miss:sec.againstMiss,total:sec.totalAgainst,color:"#ef4444",bg:"#fff5f5"}
                ].map(s => (
                  <div key={s.label} style={{ background: s.bg, borderRadius: 8, padding: 12, borderTop: `3px solid ${s.color}` }}>
                    <div style={{ fontSize: 9, fontWeight: 700, letterSpacing: 1, color: s.color, textTransform: "uppercase", marginBottom: 6 }}>5M {s.label}</div>
                    <div style={{ fontSize: 28, fontWeight: 900, color: s.color }}>{s.pct !== null ? s.pct+"%" : "—"}</div>
                    <div style={{ fontSize: 11, color: "var(--muted)", marginTop: 4 }}>{s.goals}G · {s.miss} miss · {s.total} total</div>
                  </div>
                ))}
              </div>
            );
          })()}

          {sec.type === "shot_zones" && (() => {
            const maxAtt = Math.max(...sec.zones.map(z=>z.attempts));
            return (
              <>
                <div style={{ fontSize: 12, color: "var(--muted)", marginBottom: 8 }}>{sec.total} shots with location data</div>
                <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(100px,1fr))", gap: 6 }}>
                  {sec.zones.map(z => {
                    const intensity = Math.round(z.attempts/maxAtt*100);
                    const bg = `rgba(0,48,135,${0.05 + intensity/100*0.3})`;
                    return (
                      <div key={z.zone} style={{ background: bg, borderRadius: 8, padding: 8, textAlign: "center", border: "1px solid var(--border)" }}>
                        <div style={{ fontSize: 9, fontWeight: 700, color: "var(--muted)", textTransform: "uppercase", marginBottom: 2 }}>Z{z.zone} {ZONE_LABELS[z.zone]||""}</div>
                        <div style={{ fontSize: 20, fontWeight: 900, color: "var(--navy)" }}>{z.attempts}</div>
                        <div style={{ fontSize: 10, color: "var(--muted)" }}>{z.goals}G · {z.pct}%</div>
                      </div>
                    );
                  })}
                </div>
              </>
            );
          })()}

          {sec.type === "shot_map" && (() => {
            const W = 100, H = 60;
            return (
              <div style={{ display: "flex", gap: 14, alignItems: "flex-start", flexWrap: "wrap" }}>
                <svg viewBox={`0 0 ${W} ${H}`} style={{ width: 240, maxWidth: "100%", border: "1px solid var(--border)", borderRadius: 8, background: "#dbeafe" }}>
                  <rect x="0" y="0" width={W} height={H} fill="#dbeafe"/>
                  <rect x="1" y="1" width={W-2} height={H-2} fill="none" stroke="#93c5fd" strokeWidth="0.5"/>
                  <line x1={W*0.82} y1="1" x2={W*0.82} y2={H-1} stroke="#93c5fd" strokeWidth="0.5" strokeDasharray="2,2"/>
                  <line x1={W*0.65} y1="1" x2={W*0.65} y2={H-1} stroke="#bfdbfe" strokeWidth="0.5" strokeDasharray="2,2"/>
                  <rect x={W-2} y={H*0.35} width="2" height={H*0.3} fill="#1d4ed8" rx="1"/>
                  {sec.shots.map((s, i) => (
                    <circle key={i} cx={(s.x/100)*W} cy={(s.y/100)*H} r={s.is5m ? 3.5 : 2.8}
                      fill={s.isGoal ? "#22c55e" : "#f59e0b"} fillOpacity="0.85" stroke="#fff" strokeWidth="0.5"/>
                  ))}
                </svg>
                <div>
                  <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 6, fontSize: 12 }}>
                    <span style={{ display: "inline-block", width: 10, height: 10, borderRadius: "50%", background: "#22c55e" }}></span> Goal
                  </div>
                  <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 12, fontSize: 12 }}>
                    <span style={{ display: "inline-block", width: 10, height: 10, borderRadius: "50%", background: "#f59e0b" }}></span> Shot saved
                  </div>
                  <div style={{ fontSize: 12, color: "var(--muted)" }}>
                    {sec.shots.length} shots plotted<br/>{sec.shots.filter(s=>s.isGoal).length} goals
                  </div>
                </div>
              </div>
            );
          })()}

          {sec.type === "game_flow" && (() => {
            const activePeriods = sec.periods.filter(p => sec.games.some(g => g.periods[p].wave || g.periods[p].opp));
            return (
              <div>
                {sec.games.map((g, gi) => {
                  const rc = g.result==="W" ? "#16a34a" : g.result==="L" ? "#ef4444" : "#6b7280";
                  return (
                    <div key={gi} style={{ marginBottom: 14 }}>
                      <div style={{ fontSize: 12, fontWeight: 700, marginBottom: 6 }}>
                        {g.opponent} <span style={{ color: rc, fontFamily: "monospace" }}>{g.waveScore}–{g.oppScore}</span>
                      </div>
                      <div style={{ display: "flex", gap: 6 }}>
                        {activePeriods.map(p => {
                          const w = g.periods[p].wave, o = g.periods[p].opp;
                          const maxG = Math.max(w, o, 1);
                          return (
                            <div key={p} style={{ textAlign: "center", minWidth: 38 }}>
                              <div style={{ fontSize: 10, color: "var(--muted)", marginBottom: 3 }}>{p}</div>
                              <div style={{ display: "flex", gap: 2, justifyContent: "center", alignItems: "flex-end", height: 36 }}>
                                <div style={{ width: 10, background: "var(--navy)", borderRadius: "2px 2px 0 0", height: Math.round(w/maxG*34)+2 }}/>
                                <div style={{ width: 10, background: "#ef4444", borderRadius: "2px 2px 0 0", height: Math.round(o/maxG*34)+2 }}/>
                              </div>
                              <div style={{ fontSize: 10, fontFamily: "monospace", marginTop: 2 }}>{w}–{o}</div>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  );
                })}
              </div>
            );
          })()}

          {sec.type === "top_performers" && (
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(140px,1fr))", gap: 10 }}>
              {sec.performers.map((p, i) => (
                <div key={i} style={{ background: "var(--surface)", borderRadius: 10, padding: 12, border: "1.5px solid var(--border)", textAlign: "center" }}>
                  {p.customIcon
                    ? <div style={{ display: "flex", justifyContent: "center", marginBottom: 6 }} dangerouslySetInnerHTML={{ __html: p.customIcon }} />
                    : null}
                  <div style={{ fontSize: 10, fontWeight: 700, color: "var(--muted)", textTransform: "uppercase", letterSpacing: ".8px", marginBottom: 6 }}>{p.label}</div>
                  <div style={{ fontSize: 24, fontWeight: 900, color: "var(--navy)", marginBottom: 2 }}>{String(p.value)}</div>
                  <div style={{ fontSize: 13, fontWeight: 700 }}>{p.player.name}</div>
                  <div style={{ fontSize: 11, color: "var(--muted)" }}>Cap {p.player.number}</div>
                  {p.sub && <div style={{ fontSize: 11, color: "var(--muted)", marginTop: 2 }}>{p.sub}</div>}
                </div>
              ))}
            </div>
          )}

          {sec.type === "turnovers_steals" && (() => {
            const netColor = sec.possessionNet >= 0 ? "#16a34a" : "#ef4444";
            return (
              <>
                <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 8, marginBottom: 14 }}>
                  {[
                    { label: "Steals",    value: sec.teamSteals,    color: "#16a34a", bg: "#f0fff4" },
                    { label: "Turnovers", value: sec.teamTurnovers, color: "#ef4444", bg: "#fff5f5" },
                    { label: "Net",       value: (sec.possessionNet >= 0 ? "+" : "") + sec.possessionNet, color: netColor, bg: "var(--surface)" },
                  ].map(s => (
                    <div key={s.label} style={{ background: s.bg, borderRadius: 8, padding: 10, textAlign: "center", borderTop: `3px solid ${s.color}` }}>
                      <div style={{ fontSize: 9, fontWeight: 700, color: "var(--muted)", textTransform: "uppercase", marginBottom: 4 }}>{s.label}</div>
                      <div style={{ fontSize: 26, fontWeight: 900, color: s.color }}>{s.value}</div>
                    </div>
                  ))}
                </div>
                {sec.players.length > 0 && (
                  <div style={{ overflowX: "auto" }}>
                    <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
                      <thead><tr>
                        <TH left>#</TH><TH left>Player</TH>
                        <TH>Steals</TH><TH>TO</TH><TH>Net</TH>
                      </tr></thead>
                      <tbody>{sec.players.map((p, i) => {
                        const nc = p.net > 0 ? "#16a34a" : p.net < 0 ? "#ef4444" : "var(--text)";
                        return (
                          <tr key={i} style={{ background: i%2===0 ? "var(--surface)" : "var(--bg)" }}>
                            <TDL mono>{p.number}</TDL>
                            <TDL bold>{p.name}</TDL>
                            <TD mono>{p.steals || "—"}</TD>
                            <TD mono>{p.turnovers || "—"}</TD>
                            <TD mono bold color={nc}>{p.net > 0 ? "+" : ""}{p.net}</TD>
                          </tr>
                        );
                      })}</tbody>
                    </table>
                  </div>
                )}
              </>
            );
          })()}

        </div>
      ))}
    </div>
  );
}

function ReportsScreen({ db }) {
  const [section, setSection] = useState("submitted"); // "submitted" | "official"

  // Submitted: local games that have a serverKey (were submitted to server)
  const submittedGames = db.games.filter(g => g.serverKey);

  return (
    <div>
      <div className="page-header">
        <div className="page-title">REPORTS</div>
        <div className="page-sub">{db.season}</div>
      </div>

      {/* Section toggle */}
      <div style={{ display: "flex", gap: 8, padding: "0 16px 16px" }}>
        {[
          { key: "submitted", icon: "📋", label: "Submitted" },
          { key: "official",  icon: "✅", label: "Official"  },
        ].map(({ key, icon, label }) => (
          <button key={key} type="button" onClick={() => setSection(key)} style={{
            flex: 1, padding: "10px 8px", borderRadius: 10, border: "2px solid",
            borderColor: section === key ? "var(--navy)" : "var(--border)",
            background: section === key ? "rgba(0,48,135,0.07)" : "var(--surface)",
            color: section === key ? "var(--navy)" : "var(--muted)",
            fontWeight: 700, fontSize: 13, cursor: "pointer", transition: "all .15s",
          }}>
            <div style={{ fontSize: 20, marginBottom: 3 }}>{icon}</div>
            {label}
            <div style={{ fontWeight: 400, fontSize: 11, opacity: 0.7, marginTop: 2 }}>
              {key === "submitted" ? "Games you recorded" : "Admin-approved sheets"}
            </div>
          </button>
        ))}
      </div>

      {section === "submitted" && <SubmittedReports db={db} submittedGames={submittedGames} />}
      {section === "official"  && <OfficialReports  db={db} submittedGames={submittedGames} />}
    </div>
  );
}

// ─── Shot Heat Map ────────────────────────────────────────────────────────────
// Renders an SVG pool with shot dots. Clicking a dot selects it for detail view.
// events: array of event objects with shotLocation {x,y} and stat/player info
// players: array of player objects for name lookup
// title: string label
function ShotHeatMap({ events, players, title }) {
  const shotEvents = events.filter(e => e.shotLocation && (
    isShotFor(e) || e.stat === "goals_against" || e.stat === "shot_against"
  ));
  const [selected, setSelected] = useState(null);  // index into shotEvents
  const [filter, setFilter]     = useState("all");  // all | for | against

  const filtered = shotEvents.filter(e => {
    if (filter === "for")     return isShotFor(e);
    if (filter === "against") return e.stat === "goals_against" || e.stat === "shot_against";
    return true;
  });

  const selEvent = selected !== null ? filtered[selected] : null;
  const selPlayer = selEvent?.playerId ? players.find(p => p.id === selEvent.playerId) : null;

  const shotColor = (e) => {
    if (isGoalFor(e))           return "#22c55e";
    if (e.stat === "shot" || e.stat === "penalty_5m_miss_for" || e.stat === "penalty_5m_block") return "#f59e0b";
    if (isGoalAgainst(e))       return "#ef4444";
    return "#f97316";
  };

  const shotLabel = { goal: "Goal ✅", shot: "Shot", goals_against: "Goal Against ❌", shot_against: "Shot Against", penalty_5m_goal_for: "5M Goal ✅", penalty_5m_miss_for: "5M Miss", penalty_5m_block: "5M Blocked", penalty_5m_goal_against: "5M Goal Against ❌", penalty_5m_miss_against: "5M Miss (Against)" };

  if (shotEvents.length === 0) return null;

  return (
    <div className="section">
      <div className="card">
        <div className="card-header">
          <span className="card-title">🎯 {title || "Shot Map"}</span>
          <span style={{ fontSize: 11, color: "var(--muted)" }}>{filtered.length} shots</span>
        </div>
        <div style={{ padding: "0 16px 16px" }}>

          {/* Filter tabs */}
          <div style={{ display: "flex", gap: 6, marginBottom: 10 }}>
            {[["all","All"],["for","Shots For"],["against","Shots Against"]].map(([k,l]) => (
              <button key={k} type="button" onClick={() => { setFilter(k); setSelected(null); }} style={{
                padding: "4px 10px", borderRadius: 20, fontSize: 11, fontWeight: 700,
                border: `1.5px solid ${filter === k ? "var(--navy)" : "var(--border)"}`,
                background: filter === k ? "var(--accent-dim)" : "var(--surface2)",
                color: filter === k ? "var(--navy)" : "var(--muted)", cursor: "pointer",
              }}>{l}</button>
            ))}
          </div>

          {/* Pool SVG */}
          <svg viewBox="0 0 400 168" style={{ width: "100%", borderRadius: 10, border: "1px solid var(--border)", display: "block" }}>
            {/* Water */}
            <defs>
              <linearGradient id="poolGrad" x1="0" y1="0" x2="0" y2="1">
                <stop offset="0%" stopColor="#0369a1"/>
                <stop offset="100%" stopColor="#0ea5e9"/>
              </linearGradient>
            </defs>
            <rect width="400" height="168" fill="url(#poolGrad)" rx="8"/>
            {/* Lane lines */}
            {[1,2,3,4,5,6].map(i => (
              <line key={i} x1="0" y1={i*168/7} x2="400" y2={i*168/7} stroke="rgba(255,255,255,0.12)" strokeWidth="1"/>
            ))}
            {/* Pool border */}
            <rect x="2" y="2" width="396" height="164" fill="none" stroke="white" strokeWidth="2" rx="7"/>
            {/* Centre line */}
            <line x1="200" y1="0" x2="200" y2="168" stroke="white" strokeWidth="2" opacity="0.4"/>
            {/* 7m lines */}
            <line x1="56" y1="0" x2="56" y2="168" stroke="#fde047" strokeWidth="1.5" strokeDasharray="6,4" opacity="0.8"/>
            <line x1="344" y1="0" x2="344" y2="168" stroke="#fde047" strokeWidth="1.5" strokeDasharray="6,4" opacity="0.8"/>
            {/* 2m lines */}
            <line x1="22" y1="0" x2="22" y2="168" stroke="#f97316" strokeWidth="1.2" strokeDasharray="4,3" opacity="0.7"/>
            <line x1="378" y1="0" x2="378" y2="168" stroke="#f97316" strokeWidth="1.2" strokeDasharray="4,3" opacity="0.7"/>
            {/* 6m lines */}
            <line x1="80" y1="0" x2="80" y2="168" stroke="#a78bfa" strokeWidth="1.5" strokeDasharray="5,3" opacity="0.85"/>
            <line x1="320" y1="0" x2="320" y2="168" stroke="#a78bfa" strokeWidth="1.5" strokeDasharray="5,3" opacity="0.85"/>
            <text x="84" y="12" fill="#a78bfa" fontSize="8" fontWeight="bold" opacity="0.9">6m</text>
            <text x="316" y="12" fill="#a78bfa" fontSize="8" fontWeight="bold" textAnchor="end" opacity="0.9">6m</text>
            {/* Goals */}
            <rect x="0" y="64" width="12" height="40" fill="none" stroke="white" strokeWidth="2.5" rx="2"/>
            <rect x="388" y="64" width="12" height="40" fill="none" stroke="white" strokeWidth="2.5" rx="2"/>
            {/* Shot dots */}
            {filtered.map((e, i) => {
              const x = (e.shotLocation.x / 100) * 400;
              const y = (e.shotLocation.y / 100) * 168;
              const col = shotColor(e);
              const isGoal = e.stat === "goal" || e.stat === "goals_against";
              const isSel  = selected === i;
              return (
                <g key={i} style={{ cursor: "pointer" }} onClick={() => setSelected(selected === i ? null : i)}>
                  <circle cx={x} cy={y} r={isSel ? 13 : 9} fill={col} opacity="0.2"/>
                  <circle cx={x} cy={y} r={isSel ? 7 : 5} fill={col} stroke="white" strokeWidth={isSel ? 2 : 1.5} opacity="0.92"/>
                  {isGoal && <text x={x} y={y+4} textAnchor="middle" fontSize="7" fill="white" fontWeight="bold">G</text>}
                </g>
              );
            })}
          </svg>

          {/* Legend */}
          <div style={{ display: "flex", gap: 14, marginTop: 8, fontSize: 11, color: "var(--muted)", flexWrap: "wrap" }}>
            <span><span style={{ color: "#22c55e" }}>●</span> Goal</span>
            <span><span style={{ color: "#f59e0b" }}>●</span> Shot</span>
            <span><span style={{ color: "#ef4444" }}>●</span> Goal Against</span>
            <span><span style={{ color: "#f97316" }}>●</span> Shot Against</span>
            <span style={{ marginLeft: "auto", opacity: 0.6 }}>Tap a dot for details</span>
          </div>

          {/* Cycle arrows */}
          {filtered.length > 0 && (
            <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 12, marginTop: 10 }}>
              <button type="button" onClick={() => setSelected(s => s === null ? filtered.length-1 : (s-1+filtered.length)%filtered.length)} style={{
                padding: "6px 14px", borderRadius: 8, border: "1px solid var(--border)", background: "var(--surface2)",
                fontSize: 16, cursor: "pointer", fontWeight: 700,
              }}>‹</button>
              <span style={{ fontSize: 12, color: "var(--muted)" }}>
                {selected !== null ? `Shot ${selected+1} of ${filtered.length}` : `${filtered.length} shots`}
              </span>
              <button type="button" onClick={() => setSelected(s => s === null ? 0 : (s+1)%filtered.length)} style={{
                padding: "6px 14px", borderRadius: 8, border: "1px solid var(--border)", background: "var(--surface2)",
                fontSize: 16, cursor: "pointer", fontWeight: 700,
              }}>›</button>
            </div>
          )}

          {/* Selected shot detail */}
          {selEvent && (
            <div style={{ marginTop: 12, padding: "12px 14px", background: "var(--surface2)", borderRadius: 10,
              border: `2px solid ${shotColor(selEvent)}`, fontSize: 13 }}>
              <div style={{ fontWeight: 700, fontSize: 14, color: shotColor(selEvent), marginBottom: 6 }}>
                {shotLabel[selEvent.stat] || selEvent.stat}
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "5px 14px", color: "var(--muted)", fontSize: 12 }}>
                {selPlayer && <div><strong>Player:</strong> #{selPlayer.number} {selPlayer.name}</div>}
                {selEvent.oppNum && <div><strong>Opp #:</strong> {selEvent.oppNum}</div>}
                {selEvent.period && <div><strong>Period:</strong> {selEvent.period}</div>}
                {selEvent.situation && <div><strong>Situation:</strong> {{man_up:"Man-Up ⬆️",man_down:"Man-Down ⬇️",even:"Even ⚖️"}[selEvent.situation]||selEvent.situation}</div>}
                {selEvent.shotExp && <div><strong>Shot type:</strong> {{expected:"Expected 🎯",unexpected:"Unexpected 😮",unsure:"Unsure 🤷"}[selEvent.shotExp]||selEvent.shotExp}</div>}
                {selEvent.wetDry && <div><strong>Ball:</strong> {{wet:"Wet 💧",dry:"Dry 🏐"}[selEvent.wetDry]||selEvent.wetDry}</div>}
                {selEvent.playType && <div><strong>Play:</strong> {{counter:"Counter-attack ⚡",setup:"Set-up Play ♟️"}[selEvent.playType]||selEvent.playType}</div>}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ─── PDF Export (Tracker) ─────────────────────────────────────────────────────
async function exportTrackerPDF(game, db, title) {
  // Load jsPDF and autotable
  if (!window.jspdf) {
    await new Promise((res, rej) => {
      const s = document.createElement("script");
      s.src = "https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js";
      s.onload = res; s.onerror = rej; document.head.appendChild(s);
    });
  }
  if (!window.jspdf?.jsPDF?.prototype?.autoTable) {
    await new Promise((res, rej) => {
      const s = document.createElement("script");
      s.src = "https://cdnjs.cloudflare.com/ajax/libs/jspdf-autotable/3.8.2/jspdf.plugin.autotable.min.js";
      s.onload = res; s.onerror = rej; document.head.appendChild(s);
    });
  }
  const { jsPDF } = window.jspdf;
  const doc = new jsPDF({ orientation: "portrait", unit: "mm", format: "a4" });
  const NAVY = [0, 48, 135], GOLD = [255, 199, 44], WHITE = [255, 255, 255], LIGHT = [240, 242, 247];

  const events   = game.events || [];
  const homeTeam = db.teams.find(t => t.id === game.homeTeamId);
  const awayTeam = db.teams.find(t => t.id === game.awayTeamId);
  const homePlayers = db.players.filter(p => p.teamId === game.homeTeamId).sort((a,b)=>parseInt(a.number)-parseInt(b.number));

  // Header
  doc.setFillColor(...NAVY); doc.rect(0, 0, 210, 26, "F");
  doc.setFillColor(...GOLD); doc.rect(0, 26, 210, 2, "F");
  doc.setTextColor(...WHITE); doc.setFont("helvetica", "bold"); doc.setFontSize(18);
  doc.text("WAVE SWIM & POLO", 12, 12);
  doc.setFontSize(9); doc.setFont("helvetica", "normal");
  doc.text(title || "Game Report", 12, 19);
  doc.text("Generated " + new Date().toLocaleDateString("en-CA"), 198, 19, { align: "right" });

  let y = 33;

  // Score block
  const homeScore = game.homeScore || 0;
  const awayScore = game.awayScore || 0;
  const dateStr = game.date ? new Date(game.date).toLocaleDateString("en-CA", { weekday:"short", month:"short", day:"numeric" }) : "";
  doc.setFillColor(...LIGHT); doc.roundedRect(10, y, 190, 18, 2, 2, "F");
  doc.setTextColor(...NAVY); doc.setFont("helvetica", "bold"); doc.setFontSize(13);
  doc.text(`${homeTeam?.name || "WAVE"} ${homeScore} – ${awayScore} ${awayTeam?.name || "Opponent"}`, 105, y+11, { align: "center" });
  doc.setFont("helvetica", "normal"); doc.setFontSize(8); doc.setTextColor(100, 110, 130);
  doc.text([game.tournament, game.ageGroup, dateStr].filter(Boolean).join(" · "), 105, y+16, { align: "center" });
  y += 24;

  // Player stats table
  const statCols = ["goal","assist","shot","steal","block","turnover","kickout","kickout_earned","save"];
  const statHdr  = ["G","A","SH","ST","BL","TO","KO","KOE","SV"];
  const activeCols = statCols.filter(s => events.some(e => e.stat === s));
  const activeHdr  = activeCols.map(s => statHdr[statCols.indexOf(s)]);

  if (homePlayers.length && activeCols.length) {
    doc.setFont("helvetica", "bold"); doc.setFontSize(9); doc.setTextColor(...NAVY);
    doc.text("Player Statistics — " + (homeTeam?.name || "WAVE"), 12, y); y += 4;

    const body = homePlayers.map(p => {
      const vals = activeCols.map(s => events.filter(e => e.playerId === p.id && e.stat === s).length || "");
      return [p.number, p.name || "—", ...vals];
    }).filter(r => r.slice(2).some(v => v !== ""));

    if (body.length) {
      doc.autoTable({
        startY: y, head: [["#", "Player", ...activeHdr]], body,
        margin: { left: 10, right: 10 },
        styles: { fontSize: 8, cellPadding: 2 },
        headStyles: { fillColor: NAVY, textColor: WHITE, fontStyle: "bold", halign: "center" },
        columnStyles: { 0: { halign: "center", cellWidth: 10 }, 1: { cellWidth: 50 } },
        alternateRowStyles: { fillColor: LIGHT },
      });
      y = doc.lastAutoTable.finalY + 8;
    }
  }

  // Shot analysis
  const shotEvents = events.filter(e => e.shotLocation);
  if (shotEvents.length) {
    doc.setFont("helvetica", "bold"); doc.setFontSize(9); doc.setTextColor(...NAVY);
    doc.text("Shot Analysis", 12, y); y += 4;

    const forShots     = shotEvents.filter(isShotFor);
    const againstShots = shotEvents.filter(e => e.stat === "goals_against" || e.stat === "shot_against");
    const forGoals     = forShots.filter(isGoalFor).length;
    const againstGoals = againstShots.filter(isGoalAgainst).length;

    const countBy = (arr, key) => arr.reduce((acc, e) => { acc[e[key]] = (acc[e[key]]||0)+1; return acc; }, {});
    const forExp   = countBy(forShots, "shotExp");
    const againExp = countBy(againstShots, "shotExp");
    const forSit   = countBy(forShots, "situation");
    const aginSit  = countBy(againstShots, "situation");
    const muShots  = (forSit.man_up||0), mdShots = (forSit.man_down||0), evShots = (forSit.even||0);
    const muGoals  = forShots.filter(e=>e.situation==="man_up"&&isGoalFor(e)).length;
    const mdGoals  = forShots.filter(e=>e.situation==="man_down"&&isGoalFor(e)).length;

    const summaryBody = [
      ["Shots For", forShots.length, forGoals, forShots.length ? Math.round(forGoals/forShots.length*100)+"%" : "—"],
      ["Shots Against", againstShots.length, againstGoals, againstShots.length ? Math.round(againstGoals/againstShots.length*100)+"%" : "—"],
    ];
    doc.autoTable({
      startY: y, head: [["", "Shots", "Goals", "Conversion"]], body: summaryBody,
      margin: { left: 10, right: 10 },
      styles: { fontSize: 8, cellPadding: 2 },
      headStyles: { fillColor: NAVY, textColor: WHITE, fontStyle: "bold" },
      columnStyles: { 0: { cellWidth: 45 } },
      alternateRowStyles: { fillColor: LIGHT },
    });
    y = doc.lastAutoTable.finalY + 4;

    // Situation breakdown
    if (muShots || mdShots) {
      const sitBody = [
        ["Man-Up (PP)", muShots, muGoals, muShots ? Math.round(muGoals/muShots*100)+"%" : "—"],
        ["Even Strength", evShots, forShots.filter(e=>e.situation==="even"&&isGoalFor(e)).length, evShots ? Math.round(forShots.filter(e=>e.situation==="even"&&isGoalFor(e)).length/evShots*100)+"%" : "—"],
        ["Man-Down (PK)", mdShots, mdGoals, mdShots ? Math.round(mdGoals/mdShots*100)+"%" : "—"],
      ];
      doc.autoTable({
        startY: y, head: [["Situation", "Shots", "Goals", "Conversion"]], body: sitBody,
        margin: { left: 10, right: 10 },
        styles: { fontSize: 8, cellPadding: 2 },
        headStyles: { fillColor: [60, 80, 120], textColor: WHITE, fontStyle: "bold" },
        alternateRowStyles: { fillColor: LIGHT },
      });
      y = doc.lastAutoTable.finalY + 4;
    }

    // Shot expectedness
    if (Object.keys(forExp).length) {
      const expBody = [
        ["Expected", forExp.expected||0, againExp.expected||0],
        ["Unexpected", forExp.unexpected||0, againExp.unexpected||0],
        ["Unsure", forExp.unsure||0, againExp.unsure||0],
      ].filter(r => r[1] || r[2]);
      if (expBody.length) {
        doc.autoTable({
          startY: y, head: [["Shot Type", "For", "Against"]], body: expBody,
          margin: { left: 10, right: 10 },
          styles: { fontSize: 8, cellPadding: 2 },
          headStyles: { fillColor: [60, 80, 120], textColor: WHITE, fontStyle: "bold" },
          alternateRowStyles: { fillColor: LIGHT },
        });
        y = doc.lastAutoTable.finalY + 4;
      }
    }
  }

  // Footer
  const pages = doc.internal.getNumberOfPages();
  for (let i = 1; i <= pages; i++) {
    doc.setPage(i);
    doc.setFillColor(...NAVY); doc.rect(0, 285, 210, 12, "F");
    doc.setTextColor(...GOLD); doc.setFont("helvetica", "bold"); doc.setFontSize(7);
    doc.text("WAVE SWIM & POLO · Confidential", 12, 292);
    doc.setTextColor(...WHITE); doc.setFont("helvetica", "normal");
    doc.text(`Page ${i} of ${pages}`, 198, 292, { align: "right" });
  }

  const fn = `WAVE_${(homeTeam?.name||"Game").replace(/\s/g,"_")}_${new Date().toISOString().slice(0,10)}.pdf`;
  doc.save(fn);
}

// ═══════════════════════════════════════════════════════════════════════════════
// UNIFIED REPORT ENGINE
// Converts tracker-format game data → crunchReportData-compatible shape,
// then renders via ReportViewer — same output as admin.
// ═══════════════════════════════════════════════════════════════════════════════

// Convert one tracker game + db into the admin crunchReportData input shape
function trackerGameToAdminShape(game, db) {
  const homeTeam = db.teams.find(t => t.id === game.homeTeamId);
  const awayTeam = db.teams.find(t => t.id === game.awayTeamId);
  const wavePlayers = db.players.filter(p => p.teamId === game.homeTeamId);
  return {
    game_key:        game.id,
    game_date:       game.date,
    opponent:        awayTeam?.name || "Opponent",
    tournament:      game.tournament || "",
    wave_team:       homeTeam?.name || "WAVE",
    wave_score:      game.homeScore ?? 0,
    opp_score:       game.awayScore ?? 0,
    players:         wavePlayers,
    official_events: game.events || [],
  };
}

// Build report data from one or more tracker games using the shared engine
// scope: 'game' | 'tournament' | 'season'
function buildTrackerReport(games, db, title, subtitle, scope) {
  const adminGames = games.map(g => trackerGameToAdminShape(g, db));
  return crunchTrackerReport(adminGames, title, subtitle || "", scope);
}

// Shared crunch logic — canonical version used by all report surfaces
// Matches admin's crunchReportData exactly (same sections, same field names)
function crunchTrackerReport(games, title, subtitle, scope) {
  const playerMap = {};
  games.forEach(g => (g.players || []).forEach(p => { playerMap[p.id] = p; }));

  const allEvents  = [];
  const gameResults = [];

  games.forEach(g => {
    const evts = (g.official_events || []).map(e => ({ ...e, _game: g.game_key, _gameDate: g.game_date }));
    allEvents.push(...evts);
    const waveScore = g.wave_score ?? evts.filter(e => ["goal","penalty_5m_goal_for"].includes(e.stat) && playerMap[e.playerId]).length;
    const oppScore  = g.opp_score  ?? evts.filter(e => ["goals_against","penalty_5m_goal_against"].includes(e.stat)).length;
    gameResults.push({
      date: g.game_date, opponent: g.opponent, tournament: g.tournament,
      waveScore, oppScore,
      result: waveScore > oppScore ? "W" : waveScore < oppScore ? "L" : "T",
      events: evts,
    });
  });

  const sections = [];

  // ── 1. Results table (multi-game only) ──────────────────────────────────────
  if (games.length > 1) {
    const wins   = gameResults.filter(r => r.result === "W").length;
    const losses = gameResults.filter(r => r.result === "L").length;
    const ties   = gameResults.filter(r => r.result === "T").length;
    sections.push({
      type: "results_table", title: "Results",
      rows: gameResults,
      record: `${wins}W–${losses}L${ties ? "–"+ties+"T" : ""}`,
      waveTotal: gameResults.reduce((s,r) => s+r.waveScore, 0),
      oppTotal:  gameResults.reduce((s,r) => s+r.oppScore,  0),
    });
  }

  // ── 2. Box score by period ───────────────────────────────────────────────────
  const periods = ["1Q","2Q","3Q","4Q","OT","SO"];
  const boxScore = {};
  periods.forEach(p => {
    const pe = allEvents.filter(e => e.period === p);
    boxScore[p] = {
      waveGoals: pe.filter(e => ["goal","penalty_5m_goal_for"].includes(e.stat) && playerMap[e.playerId]).length,
      oppGoals:  pe.filter(e => ["goals_against","penalty_5m_goal_against"].includes(e.stat)).length,
      waveShots: pe.filter(e => ["goal","shot"].includes(e.stat) && playerMap[e.playerId]).length,
      waveSaves: pe.filter(e => e.stat === "save" && playerMap[e.playerId]).length,
    };
  });
  if (periods.some(p => boxScore[p].waveGoals || boxScore[p].oppGoals || boxScore[p].waveShots))
    sections.push({ type: "box_score", title: "Team Box Score", boxScore, periods });

  // ── 3. Player stats + Leaderboards ──────────────────────────────────────────
  const statKeys = ["goal","assist","shot","steal","block","turnover","kickout","kickout_earned","save"];
  const playerStats = {};
  Object.entries(playerMap).forEach(([pid, p]) => {
    playerStats[pid] = { name: p.name, number: p.number, isGoalie: p.isGoalie,
      stats: Object.fromEntries(statKeys.map(k => [k, 0])),
      goalsAgainst: 0, shotsAgainst: 0, penalties5mFor: 0, penalties5mAgainst: 0, penalties5mBlock: 0 };
  });
  allEvents.forEach(e => {
    const pid = e.playerId;
    if (!pid || !playerStats[pid]) return;
    if (statKeys.includes(e.stat))           playerStats[pid].stats[e.stat]++;
    if (e.stat === "goals_against")           playerStats[pid].goalsAgainst++;
    if (e.stat === "shot_against")            playerStats[pid].shotsAgainst++;
    if (e.stat === "penalty_5m_goal_for")     { playerStats[pid].stats.goal++; playerStats[pid].penalties5mFor++; }
    if (e.stat === "penalty_5m_miss_for")     playerStats[pid].penalties5mFor++;
    if (e.stat === "penalty_5m_goal_against") playerStats[pid].goalsAgainst++;
    if (e.stat === "penalty_5m_block")        playerStats[pid].penalties5mBlock++;
  });

  const allPlayers    = Object.entries(playerStats).map(([pid, p]) => ({ pid, ...p }))
    .filter(p => Object.values(p.stats).some(v => v > 0) || p.goalsAgainst > 0 || p.shotsAgainst > 0);
  const fieldPlayers  = allPlayers.filter(p => !p.isGoalie);
  const goaliePlayers = allPlayers.filter(p => p.isGoalie);

  sections.push({ type: "player_stats", title: "Player Stats", fieldPlayers, goaliePlayers, statKeys });

  const STAT_LABELS = {goal:"Goals",assist:"Assists",shot:"Shots",steal:"Steals",block:"Blocks",kickout_earned:"KO Earned",save:"Saves"};
  const leaders = {};
  ["goal","assist","shot","steal","block","kickout_earned","save"].forEach(stat => {
    const sorted = allPlayers.filter(p => p.stats[stat] > 0).sort((a,b) => b.stats[stat]-a.stats[stat]).slice(0, 5);
    if (sorted.length) leaders[stat] = sorted;
  });
  if (Object.keys(leaders).length) sections.push({ type: "leaderboards", title: "Leaderboards", leaders });

  // ── 4. Goalie stats ─────────────────────────────────────────────────────────
  const goalieData = goaliePlayers.map(p => {
    const saves = p.stats.save || 0;
    const ga    = p.goalsAgainst || 0;
    const sa    = p.shotsAgainst > 0 ? p.shotsAgainst : saves + ga;
    const svPct = sa > 0 ? Math.round(saves / sa * 1000) / 10 : null;
    return { name: p.name, number: p.number, saves, goalsAgainst: ga, shotsAgainst: sa, svPct };
  }).filter(g => g.saves + g.goalsAgainst > 0);
  if (goalieData.length) sections.push({ type: "goalies", title: "Goalie Stats", goalieData });

  // ── 5. Shooting situations ───────────────────────────────────────────────────
  const situations = {
    man_up:   { label: "Man Up",   shots: 0, goals: 0 },
    man_down: { label: "Man Down", shots: 0, goals: 0 },
    even:     { label: "Even",     shots: 0, goals: 0 },
  };
  allEvents.filter(e => ["goal","shot"].includes(e.stat) && playerMap[e.playerId]).forEach(e => {
    const sit = e.situation || "even";
    if (!situations[sit]) return;
    situations[sit].shots++;
    if (e.stat === "goal") situations[sit].goals++;
  });
  const situArr = Object.entries(situations).map(([k,v]) => ({
    key: k, ...v, pct: v.shots > 0 ? Math.round(v.goals/v.shots*100) : null
  })).filter(s => s.shots > 0);
  if (situArr.length) sections.push({ type: "situations", title: "Shooting by Situation", situations: situArr });

  // ── 6. 5M Penalties ─────────────────────────────────────────────────────────
  const penFor      = allEvents.filter(e => e.stat === "penalty_5m_goal_for").length;
  const penForMiss  = allEvents.filter(e => e.stat === "penalty_5m_miss_for").length;
  const penAgainst  = allEvents.filter(e => e.stat === "penalty_5m_goal_against").length;
  const penAgMiss   = allEvents.filter(e => e.stat === "penalty_5m_miss_against").length;
  const penBlock    = allEvents.filter(e => e.stat === "penalty_5m_block").length;
  const totalFor    = penFor + penForMiss;
  const totalAgainst = penAgainst + penAgMiss + penBlock;
  if (totalFor + totalAgainst > 0) sections.push({
    type: "penalties", title: "5M Penalties",
    forGoals: penFor, forMiss: penForMiss, totalFor,
    againstGoals: penAgainst, againstMiss: penAgMiss, againstBlock: penBlock, totalAgainst,
  });

  // ── 7. Shot zone summary ─────────────────────────────────────────────────────
  // Support both shotLocation.zone (admin events) and shotZone (tracker events)
  const shotZoneEvts = allEvents.filter(e =>
    ["goal","shot"].includes(e.stat) && playerMap[e.playerId] &&
    (e.shotLocation?.zone != null || e.shotZone != null)
  );
  if (shotZoneEvts.length) {
    const zones = {};
    shotZoneEvts.forEach(e => {
      const z = e.shotLocation?.zone ?? e.shotZone;
      if (!zones[z]) zones[z] = { attempts: 0, goals: 0 };
      zones[z].attempts++;
      if (e.stat === "goal") zones[z].goals++;
    });
    const zoneArr = Object.entries(zones).map(([z,d]) => ({
      zone: parseInt(z), ...d, pct: Math.round(d.goals/d.attempts*100)
    })).sort((a,b) => b.attempts-a.attempts);
    sections.push({ type: "shot_zones", title: "Shot Zone Summary", zones: zoneArr, total: shotZoneEvts.length });
  }

  // ── 8. Shot map ──────────────────────────────────────────────────────────────
  const shotMapEvts = allEvents.filter(e =>
    ["goal","shot","penalty_5m_goal_for","penalty_5m_miss_for","penalty_5m_block"].includes(e.stat)
    && e.shotLocation?.x != null && e.shotLocation?.y != null
  );
  if (shotMapEvts.length) sections.push({
    type: "shot_map", title: "Shot Map",
    shots: shotMapEvts.map(e => ({
      x: e.shotLocation.x, y: e.shotLocation.y,
      isGoal: ["goal","penalty_5m_goal_for"].includes(e.stat),
      is5m:   ["penalty_5m_goal_for","penalty_5m_miss_for","penalty_5m_block"].includes(e.stat),
    })),
  });

  // ── 9. Game flow by period ───────────────────────────────────────────────────
  const flowPeriods = ["1Q","2Q","3Q","4Q","OT"];
  const gameFlow = gameResults.map(g => {
    const pMap = {};
    flowPeriods.forEach(p => {
      const pe = g.events.filter(e => e.period === p);
      pMap[p] = {
        wave: pe.filter(e => ["goal","penalty_5m_goal_for"].includes(e.stat) && playerMap[e.playerId]).length,
        opp:  pe.filter(e => ["goals_against","penalty_5m_goal_against"].includes(e.stat)).length,
      };
    });
    return { opponent: g.opponent, date: g.date, waveScore: g.waveScore, oppScore: g.oppScore, result: g.result, periods: pMap };
  });
  const hasFlow = gameFlow.some(g => flowPeriods.some(p => g.periods[p].wave || g.periods[p].opp));
  if (hasFlow) sections.push({ type: "game_flow", title: "Game Flow", games: gameFlow, periods: flowPeriods });

  // ── 10. Top performers ───────────────────────────────────────────────────────
  const perfStats = [
    { key: "assist",        label: "🤝 Top Playmaker" },
    { key: "steal",         label: "🦊 Most Steals" },
    { key: "block",         label: "🛡 Most Blocks" },
    { key: "kickout_earned",label: "📣 Most KO Earned" },
  ];
  const goaliePerf = goaliePlayers.map(p => {
    const saves = p.stats.save || 0;
    const ga    = p.goalsAgainst || 0;
    const sa    = saves + ga;
    return { ...p, svPct: sa > 0 ? Math.round(saves/sa*100) : null };
  }).filter(p => (p.stats.save || 0) > 0).sort((a,b) => (b.svPct||0)-(a.svPct||0));

  const topPerformers = perfStats.map(({ key, label }) => {
    const sorted = allPlayers.filter(p => p.stats[key] > 0).sort((a,b) => b.stats[key]-a.stats[key]);
    if (!sorted.length) return null;
    return { key, label, player: sorted[0], value: sorted[0].stats[key] };
  }).filter(Boolean);

  // Shooting % — min 3 shots to qualify
  const shootingPct = allPlayers
    .filter(p => !p.isGoalie && p.stats.shot >= 3)
    .map(p => ({ ...p, pct: Math.round(p.stats.goal / p.stats.shot * 100) }))
    .sort((a,b) => b.pct-a.pct);
  if (shootingPct.length) {
    const best = shootingPct[0];
    topPerformers.unshift({ key: "shoot_pct", label: "🎯 Best Shooting %", player: best, value: best.pct + "%", sub: `${best.stats.goal}G / ${best.stats.shot} shots` });
  }
  if (goaliePerf.length) topPerformers.push({ key: "save_pct", label: "🧤 Best Save %", player: goaliePerf[0], value: goaliePerf[0].svPct + "%" });
  if (topPerformers.length) sections.push({ type: "top_performers", title: "Top Performers", performers: topPerformers });

  // ── 11. Turnovers vs Steals ──────────────────────────────────────────────────
  const teamSteals    = allEvents.filter(e => e.stat === "steal"    && playerMap[e.playerId]).length;
  const teamTurnovers = allEvents.filter(e => e.stat === "turnover" && playerMap[e.playerId]).length;
  const tvsPlayers = allPlayers
    .map(p => ({ name: p.name, number: p.number, steals: p.stats.steal||0, turnovers: p.stats.turnover||0, net: (p.stats.steal||0)-(p.stats.turnover||0) }))
    .filter(p => p.steals > 0 || p.turnovers > 0)
    .sort((a,b) => b.net-a.net);
  if (teamSteals + teamTurnovers > 0) sections.push({
    type: "turnovers_steals", title: "Turnovers vs Steals",
    teamSteals, teamTurnovers, possessionNet: teamSteals-teamTurnovers, players: tvsPlayers,
  });

  return { title, subtitle, sections, gameCount: games.length, generatedAt: Date.now(), scope };
}


// ─── Shared PDF export using unified report data ───────────────────────────────
async function exportReportPDF(reportData, filenameBase) {
  // Uses the same jsPDF path as exportTrackerPDF but fed from unified report
  if (!window.jspdf) {
    await new Promise((res, rej) => {
      const s = document.createElement("script");
      s.src = "https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js";
      s.onload = res; s.onerror = rej; document.head.appendChild(s);
    });
  }
  if (!window.jspdf?.jsPDF?.prototype?.autoTable) {
    await new Promise((res, rej) => {
      const s = document.createElement("script");
      s.src = "https://cdnjs.cloudflare.com/ajax/libs/jspdf-autotable/3.8.2/jspdf.plugin.autotable.min.js";
      s.onload = res; s.onerror = rej; document.head.appendChild(s);
    });
  }
  const { jsPDF } = window.jspdf;
  const doc = new jsPDF({ orientation: "portrait", unit: "mm", format: "a4" });
  const NAVY=[0,48,135], GOLD=[255,199,44], WHITE=[255,255,255], LIGHT=[240,242,247], MUTED=[120,130,150];

  // Header banner
  doc.setFillColor(...NAVY); doc.rect(0,0,210,26,"F");
  doc.setFillColor(...GOLD); doc.rect(0,26,210,2,"F");
  doc.setTextColor(...WHITE); doc.setFont("helvetica","bold"); doc.setFontSize(16);
  doc.text(reportData.title || "Game Report", 12, 12);
  doc.setFontSize(8); doc.setFont("helvetica","normal");
  if (reportData.subtitle) doc.text(reportData.subtitle, 12, 19);
  doc.text("Generated "+new Date().toLocaleDateString("en-CA"), 198, 19, { align:"right" });
  let y = 33;

  for (const sec of (reportData.sections || [])) {
    if (y > 260) { doc.addPage(); y = 14; }
    // Section heading
    doc.setFillColor(...LIGHT); doc.rect(10, y, 190, 7, "F");
    doc.setTextColor(...NAVY); doc.setFont("helvetica","bold"); doc.setFontSize(10);
    doc.text(sec.title, 12, y+5);
    y += 10;

    if (sec.type === "results_table") {
      doc.autoTable({
        startY: y,
        head: [["Date","Opponent","Us","Opp","Result"]],
        body: sec.rows.map(r => [
          new Date(r.date+"T12:00:00").toLocaleDateString("en-CA",{month:"short",day:"numeric"}),
          r.opponent, r.waveScore, r.oppScore, r.result,
        ]),
        margin:{left:10,right:10}, styles:{fontSize:9,cellPadding:2},
        headStyles:{fillColor:NAVY,textColor:WHITE,fontStyle:"bold"},
        alternateRowStyles:{fillColor:LIGHT},
        columnStyles:{2:{halign:"center"},3:{halign:"center"},4:{halign:"center",fontStyle:"bold"}},
      });
      y = doc.lastAutoTable.finalY + 6;
    }

    else if (sec.type === "box_score") {
      const ap = sec.periods.filter(p => sec.boxScore[p].waveGoals||sec.boxScore[p].oppGoals||sec.boxScore[p].waveShots);
      if (ap.length) {
        const wt=ap.reduce((s,p)=>s+sec.boxScore[p].waveGoals,0);
        const ot=ap.reduce((s,p)=>s+sec.boxScore[p].oppGoals,0);
        const ws=ap.reduce((s,p)=>s+sec.boxScore[p].waveShots,0);
        const sv=ap.reduce((s,p)=>s+sec.boxScore[p].waveSaves,0);
        doc.autoTable({
          startY: y,
          head:[["Team",...ap,"TOT","SH","SV"]],
          body:[
            ["WAVE",...ap.map(p=>sec.boxScore[p].waveGoals||"—"),wt,ws,sv],
            ["Opponent",...ap.map(p=>sec.boxScore[p].oppGoals||"—"),ot,"—","—"],
          ],
          margin:{left:10,right:10}, styles:{fontSize:9,cellPadding:2,halign:"center"},
          headStyles:{fillColor:NAVY,textColor:WHITE,fontStyle:"bold"},
          columnStyles:{0:{halign:"left",fontStyle:"bold"}},
        });
        y = doc.lastAutoTable.finalY + 6;
      }
    }

    else if (sec.type === "player_stats") {
      const all = [...(sec.fieldPlayers||[]),...(sec.goaliePlayers||[])].sort((a,b)=>parseInt(a.number)-parseInt(b.number));
      const cols = sec.statKeys.filter(k=>all.some(p=>p.stats[k]>0));
      const hdrs = {goal:"G",assist:"A",shot:"SH",steal:"ST",block:"BL",turnover:"TO",kickout:"KO",kickout_earned:"KOE",save:"SV"};
      doc.autoTable({
        startY: y,
        head:[["#","Name",...cols.map(k=>hdrs[k]||k)]],
        body: all.map(p=>[p.number, p.name+(p.isGoalie?" 🧤":""), ...cols.map(k=>p.stats[k]||"—")]),
        margin:{left:10,right:10}, styles:{fontSize:8,cellPadding:2},
        headStyles:{fillColor:NAVY,textColor:WHITE,fontStyle:"bold"},
        alternateRowStyles:{fillColor:LIGHT},
        columnStyles:{0:{halign:"center",cellWidth:10},2:{halign:"center"}},
      });
      y = doc.lastAutoTable.finalY + 6;
    }

    else if (sec.type === "top_performers") {
      const cols = sec.performers.length;
      const cw = Math.min(35, 180/cols);
      sec.performers.forEach((p, i) => {
        const cx = 12 + i*(cw+2);
        doc.setFillColor(...LIGHT); doc.roundedRect(cx, y, cw, 24, 2, 2, "F");
        doc.setTextColor(...MUTED); doc.setFontSize(7); doc.setFont("helvetica","bold");
        doc.text(p.label.toUpperCase(), cx+cw/2, y+5, {align:"center"});
        doc.setTextColor(...NAVY); doc.setFontSize(14); doc.setFont("helvetica","bold");
        doc.text(String(p.value), cx+cw/2, y+13, {align:"center"});
        doc.setFontSize(7); doc.setFont("helvetica","normal"); doc.setTextColor(40,40,40);
        doc.text(p.player.name, cx+cw/2, y+19, {align:"center"});
        doc.setTextColor(...MUTED);
        doc.text("Cap "+p.player.number, cx+cw/2, y+23, {align:"center"});
      });
      y += 30;
    }

    else if (sec.type === "situations") {
      doc.autoTable({
        startY: y,
        head:[["Situation","Goals","Shots","Conversion"]],
        body: sec.situations.map(s=>[s.label, s.goals, s.shots, s.pct!=null?s.pct+"%":"—"]),
        margin:{left:10,right:10}, styles:{fontSize:9,cellPadding:2},
        headStyles:{fillColor:NAVY,textColor:WHITE,fontStyle:"bold"},
        alternateRowStyles:{fillColor:LIGHT},
        columnStyles:{1:{halign:"center"},2:{halign:"center"},3:{halign:"center",fontStyle:"bold"}},
      });
      y = doc.lastAutoTable.finalY + 6;
    }

    else if (sec.type === "turnovers_steals") {
      doc.autoTable({
        startY: y,
        head:[["#","Player","Steals","TO","Net"]],
        body:[["—","TEAM TOTAL",sec.teamSteals,sec.teamTurnovers,(sec.possessionNet>=0?"+":"")+sec.possessionNet],
              ...sec.players.map(p=>[p.number,p.name,p.steals||"—",p.turnovers||"—",(p.net>=0?"+":"")+p.net])],
        margin:{left:10,right:10}, styles:{fontSize:8,cellPadding:2},
        headStyles:{fillColor:NAVY,textColor:WHITE,fontStyle:"bold"},
        alternateRowStyles:{fillColor:LIGHT},
        columnStyles:{0:{halign:"center"},2:{halign:"center"},3:{halign:"center"},4:{halign:"center",fontStyle:"bold"}},
      });
      y = doc.lastAutoTable.finalY + 6;
    }

    else if (sec.type === "goalies") {
      doc.autoTable({
        startY: y,
        head:[["#","Goalie","SV","GA","SA","SV%"]],
        body: sec.goalieData.map(g=>[g.number,g.name,g.saves,g.goalsAgainst,g.shotsAgainst,g.svPct!=null?g.svPct+"%":"—"]),
        margin:{left:10,right:10}, styles:{fontSize:9,cellPadding:2},
        headStyles:{fillColor:NAVY,textColor:WHITE,fontStyle:"bold"},
        alternateRowStyles:{fillColor:LIGHT},
        columnStyles:{0:{halign:"center"},2:{halign:"center"},3:{halign:"center"},4:{halign:"center"},5:{halign:"center",fontStyle:"bold"}},
      });
      y = doc.lastAutoTable.finalY + 6;
    }

    else if (sec.type === "penalties") {
      doc.autoTable({
        startY: y,
        head:[["","Goals","Miss","Total","Conv%"]],
        body:[
          ["For",   sec.forGoals,     sec.forMiss,     sec.totalFor,     sec.totalFor?Math.round(sec.forGoals/sec.totalFor*100)+"%":"—"],
          ["Against",sec.againstGoals,sec.againstMiss,sec.totalAgainst,sec.totalAgainst?Math.round(sec.againstGoals/sec.totalAgainst*100)+"%":"—"],
        ],
        margin:{left:10,right:10}, styles:{fontSize:9,cellPadding:2},
        headStyles:{fillColor:NAVY,textColor:WHITE,fontStyle:"bold"},
        columnStyles:{0:{fontStyle:"bold"},1:{halign:"center"},2:{halign:"center"},3:{halign:"center"},4:{halign:"center",fontStyle:"bold"}},
      });
      y = doc.lastAutoTable.finalY + 6;
    }

    else if (sec.type === "shot_zones") {
      doc.autoTable({
        startY: y,
        head:[["Zone","Attempts","Goals","Conv%"]],
        body: sec.zones.map(z=>[`Zone ${z.zone}`,z.attempts,z.goals,z.pct+"%"]),
        margin:{left:10,right:10}, styles:{fontSize:9,cellPadding:2},
        headStyles:{fillColor:NAVY,textColor:WHITE,fontStyle:"bold"},
        alternateRowStyles:{fillColor:LIGHT},
        columnStyles:{1:{halign:"center"},2:{halign:"center"},3:{halign:"center",fontStyle:"bold"}},
      });
      y = doc.lastAutoTable.finalY + 6;
    }
  }

  // Footer
  const pages = doc.internal.getNumberOfPages();
  for (let i=1; i<=pages; i++) {
    doc.setPage(i);
    doc.setFillColor(...NAVY); doc.rect(0,285,210,12,"F");
    doc.setTextColor(...GOLD); doc.setFont("helvetica","bold"); doc.setFontSize(7);
    doc.text("WAVE SWIM & POLO · Confidential", 12, 292);
    doc.setTextColor(...WHITE); doc.setFont("helvetica","normal");
    doc.text(`Page ${i} of ${pages}`, 198, 292, { align:"right" });
  }
  doc.save(`WAVE_${(filenameBase||"Report").replace(/\s/g,"_")}_${new Date().toISOString().slice(0,10)}.pdf`);
}

// ─── Game Report Card — used in both Submitted and Official views ─────────────
function GameReportCard({ reportData, badge, exporting, onPDF }) {
  return (
    <div style={{ padding: "0 0 80px" }}>
      {badge && (
        <div style={{ margin: "0 16px 16px", background: badge.bg, borderRadius: 14,
          padding: "14px 16px", display: "flex", alignItems: "center", gap: 12, color: "#fff" }}>
          <div style={{ fontSize: 28 }}>{badge.icon}</div>
          <div style={{ flex: 1 }}>
            <div style={{ fontWeight: 800, fontSize: 15 }}>{badge.title}</div>
            {badge.sub && <div style={{ fontSize: 12, opacity: 0.75, marginTop: 2 }}>{badge.sub}</div>}
          </div>
          {onPDF && (
            <button type="button" onClick={onPDF} disabled={exporting} style={{
              padding: "8px 14px", borderRadius: 9, border: "1.5px solid rgba(255,255,255,0.4)",
              background: "rgba(255,255,255,0.15)", color: "#fff", fontWeight: 700, fontSize: 13, cursor: "pointer",
            }}>{exporting ? "⏳" : "📄 PDF"}</button>
          )}
        </div>
      )}
      {!badge && onPDF && (
        <div style={{ padding: "0 16px 12px", display: "flex", justifyContent: "flex-end" }}>
          <button type="button" onClick={onPDF} disabled={exporting} style={{
            padding: "8px 14px", borderRadius: 9, border: "1.5px solid var(--border)",
            background: "var(--surface2)", color: "var(--navy)", fontWeight: 700, fontSize: 13, cursor: "pointer",
          }}>{exporting ? "⏳" : "📄 PDF"}</button>
        </div>
      )}
      <div style={{ padding: "0 16px" }}>
        <ReportViewer data={reportData} />
      </div>
    </div>
  );
}

// ─── Submitted Reports ────────────────────────────────────────────────────────
function SubmittedReports({ db, submittedGames }) {
  const [selectedId, setSelectedId] = useState(submittedGames[0]?.id || null);
  const [exporting,  setExporting]  = useState(false);
  const game = submittedGames.find(g => g.id === selectedId) || submittedGames[0] || null;

  if (submittedGames.length === 0) return (
    <div className="empty" style={{ padding: "40px 24px" }}>
      <div className="empty-icon">📋</div>
      <div className="empty-title">No submitted games</div>
      <div className="empty-sub">Games you track and submit will appear here.</div>
    </div>
  );

  const homeTeam = db.teams.find(t => t.id === game?.homeTeamId);
  const awayTeam = db.teams.find(t => t.id === game?.awayTeamId);
  const reportData = game ? buildTrackerReport([game], db,
    `${homeTeam?.name || "WAVE"} vs ${awayTeam?.name || "Opponent"}`,
    game.tournament ? `${game.tournament} · ${game.date ? new Date(game.date).toLocaleDateString("en-CA",{month:"short",day:"numeric",year:"numeric"}) : ""}` : "",
    "game") : null;

  async function handlePDF() {
    if (!reportData) return;
    setExporting(true);
    try { await exportReportPDF(reportData, `${homeTeam?.name||"WAVE"}_vs_${awayTeam?.name||"Opp"}`); }
    catch(e) { alert("PDF error: "+e.message); }
    setExporting(false);
  }

  return (
    <div style={{ padding: "0 0 80px" }}>
      {submittedGames.length > 1 && (
        <div style={{ padding: "0 16px 14px" }}>
          <label className="form-label">Select Game</label>
          <select className="form-input form-select" value={selectedId||""} onChange={e => setSelectedId(e.target.value)}>
            {submittedGames.map(g => {
              const ht = db.teams.find(t=>t.id===g.homeTeamId);
              const at = db.teams.find(t=>t.id===g.awayTeamId);
              return <option key={g.id} value={g.id}>{ht?.name} {g.homeScore}–{g.awayScore} {at?.name} · {new Date(g.date).toLocaleDateString("en-CA",{month:"short",day:"numeric"})}</option>;
            })}
          </select>
        </div>
      )}
      {game && reportData && (
        <GameReportCard
          reportData={reportData}
          badge={{ icon:"📋", title:`${homeTeam?.name||"WAVE"} ${game.homeScore}–${game.awayScore} ${awayTeam?.name||"Opponent"}`,
                   sub: [game.tournament, game.date ? new Date(game.date).toLocaleDateString("en-CA",{month:"short",day:"numeric",year:"numeric"}) : "", `${game.events?.length||0} events tracked`].filter(Boolean).join(" · "),
                   bg: "linear-gradient(135deg,#1e3a6e,#003087)" }}
          exporting={exporting}
          onPDF={handlePDF}
        />
      )}
    </div>
  );
}

// ─── Official Reports ─────────────────────────────────────────────────────────
function OfficialReports({ db, submittedGames }) {
  const [selectedServerKey, setSelectedServerKey] = useState(submittedGames[0]?.serverKey || null);
  const [loading,   setLoading]   = useState(false);
  const [serverData, setServerData] = useState(null);
  const [error,     setError]     = useState(null);
  const [exporting, setExporting] = useState(false);

  useEffect(() => {
    if (!selectedServerKey) return;
    setLoading(true); setError(null); setServerData(null);
    fetch(`${SERVER_URL}?action=get_official_game&game_key=${encodeURIComponent(selectedServerKey)}&_=${Date.now()}`)
      .then(r => r.json())
      .then(j => { setLoading(false); if (j.ok) setServerData(j); else setError(j.error || "No official record for this game yet."); })
      .catch(() => { setLoading(false); setError("Could not reach server."); });
  }, [selectedServerKey]);

  if (submittedGames.length === 0) return (
    <div className="empty" style={{ padding: "40px 24px" }}>
      <div className="empty-icon">✅</div>
      <div className="empty-title">No submitted games</div>
      <div className="empty-sub">Submit a game first, then check back once admin has approved it.</div>
    </div>
  );

  // Build unified report from official server data
  const reportData = serverData ? (() => {
    const { game: g, official } = serverData;
    const adminGame = {
      game_key: selectedServerKey, game_date: g.game_date, opponent: g.opponent,
      tournament: g.tournament, wave_team: g.wave_team,
      wave_score: official.wave_score, opp_score: official.opp_score,
      players: g.players || [], official_events: official.events || [],
    };
    return crunchTrackerReport([adminGame], `${g.wave_team} vs ${g.opponent}`,
      [g.tournament, new Date(g.game_date+"T12:00:00").toLocaleDateString("en-CA",{month:"short",day:"numeric",year:"numeric"})].filter(Boolean).join(" · "),
      "game");
  })() : null;

  async function handlePDF() {
    if (!reportData || !serverData) return;
    setExporting(true);
    try { await exportReportPDF(reportData, `${serverData.game.wave_team}_vs_${serverData.game.opponent}`); }
    catch(e) { alert("PDF error: "+e.message); }
    setExporting(false);
  }

  return (
    <div style={{ padding: "0 0 80px" }}>
      {submittedGames.length > 1 && (
        <div style={{ padding: "0 16px 14px" }}>
          <label className="form-label">Select Game</label>
          <select className="form-input form-select" value={selectedServerKey||""} onChange={e => setSelectedServerKey(e.target.value)}>
            {submittedGames.map(g => {
              const ht = db.teams.find(t=>t.id===g.homeTeamId);
              const at = db.teams.find(t=>t.id===g.awayTeamId);
              return <option key={g.id} value={g.serverKey}>{ht?.name} vs {at?.name} · {new Date(g.date).toLocaleDateString("en-CA",{month:"short",day:"numeric"})}</option>;
            })}
          </select>
        </div>
      )}

      {loading && <div style={{ textAlign:"center", padding:"40px 16px", color:"var(--muted)", fontSize:14 }}>⏳ Loading official record…</div>}

      {error && !loading && (
        <div style={{ margin:"0 16px", padding:"20px", background:"rgba(245,158,11,0.08)", border:"1px solid rgba(245,158,11,0.3)", borderRadius:12, textAlign:"center" }}>
          <div style={{ fontSize:24, marginBottom:8 }}>⏳</div>
          <div style={{ fontWeight:700, fontSize:15, marginBottom:4 }}>Not approved yet</div>
          <div style={{ fontSize:13, color:"var(--muted)" }}>{error}</div>
        </div>
      )}

      {serverData && !loading && reportData && (
        <GameReportCard
          reportData={reportData}
          badge={{ icon:"✅", title:`${serverData.game.wave_team} ${serverData.official.wave_score}–${serverData.official.opp_score} ${serverData.game.opponent}`,
                   sub: `✅ Official · Approved ${new Date(serverData.official.finalized_at).toLocaleDateString("en-CA",{month:"short",day:"numeric",year:"numeric"})}`,
                   bg: "linear-gradient(135deg,#166534,#15803d)" }}
          exporting={exporting}
          onPDF={handlePDF}
        />
      )}
    </div>
  );
}

// ─── Tournament Report ────────────────────────────────────────────────────────
function TournamentReport({ db }) {
  const tournaments = [...new Set(db.games.map(g => g.tournament || "Unnamed"))];
  const [selected,  setSelected]  = useState(tournaments[0] || "");
  const [exporting, setExporting] = useState(false);

  const games = db.games.filter(g => (g.tournament||"Unnamed") === selected);
  const reportData = games.length ? buildTrackerReport(games, db, `🏆 ${selected}`, `${games.length} game${games.length!==1?"s":""}`, "tournament") : null;

  async function handlePDF() {
    if (!reportData) return;
    setExporting(true);
    try { await exportReportPDF(reportData, selected); }
    catch(e) { alert("PDF error: "+e.message); }
    setExporting(false);
  }

  return (
    <div>
      {tournaments.length > 1 && (
        <div style={{ padding:"0 16px 12px" }}>
          <label className="form-label">Tournament</label>
          <select className="form-input form-select" value={selected} onChange={e => setSelected(e.target.value)}>
            {tournaments.map(t => <option key={t}>{t}</option>)}
          </select>
        </div>
      )}
      {!reportData && <div style={{ padding:"24px 16px", color:"var(--muted)", fontSize:13, textAlign:"center" }}>No games tracked for this tournament yet.</div>}
      {reportData && (
        <GameReportCard
          reportData={reportData}
          badge={{ icon:"🏆", title:selected, sub:`${games.length} game${games.length!==1?"s":""}`, bg:"linear-gradient(135deg,#92400e,#b45309)" }}
          exporting={exporting}
          onPDF={handlePDF}
        />
      )}
    </div>
  );
}

// ─── Season Report ────────────────────────────────────────────────────────────
function SeasonReport({ db }) {
  const [exporting, setExporting] = useState(false);
  const reportData = db.games.length ? buildTrackerReport(db.games, db, `${db.season||"Season"} Report`, `${db.games.length} game${db.games.length!==1?"s":""}`, "season") : null;

  async function handlePDF() {
    if (!reportData) return;
    setExporting(true);
    try { await exportReportPDF(reportData, db.season||"Season"); }
    catch(e) { alert("PDF error: "+e.message); }
    setExporting(false);
  }

  if (!reportData) return (
    <div className="empty" style={{ padding:"40px 24px" }}>
      <div className="empty-icon">📊</div>
      <div className="empty-title">No games yet</div>
      <div className="empty-sub">Track some games to see your season report.</div>
    </div>
  );

  return (
    <GameReportCard
      reportData={reportData}
      badge={{ icon:"📊", title:db.season||"Season Report", sub:`${db.games.length} game${db.games.length!==1?"s":""}`, bg:"linear-gradient(135deg,#1e3a6e,#003087)" }}
      exporting={exporting}
      onPDF={handlePDF}
    />
  );
}


ReactDOM.createRoot(document.getElementById("root")).render(React.createElement(App));
  </script>
<script>
if ('serviceWorker' in navigator) {
  window.addEventListener('load', () => {
    navigator.serviceWorker.register('service-worker.js?v=4')
      .then(reg => {
        console.log('[WAVE] Service worker registered:', reg.scope);
        reg.update(); // force check for new SW on every load
      })
      .catch(err => console.warn('[WAVE] Service worker registration failed:', err));
  });
}
</script>
